def sync_proxy_kernel_provider_base_url(db: Session, provider_id: str, base_url: str) -> models.Provider:
    provider = db.get(models.Provider, provider_id) or ensure_provider_from_template(db, provider_id, status="disabled")
    if not provider:
        raise HTTPException(status_code=404, detail={"error": "PROVIDER_TEMPLATE_NOT_FOUND"})
    config = provider_runtime_config(provider_id, loads(provider.base_config_json, {}))
    config["base_url"] = validate_provider_base_url_input(provider_id, base_url)
    if provider_id == "gemini_cli_oauth" and str(config.get("health_endpoint") or "/health") == "/health":
        config["health_endpoint"] = "/v1/models"
    provider.base_config_json = dumps(config)
    db.commit()
    return provider


def run_proxy_kernel_runtime_health_check(
    db: Session,
    provider_id: str,
    *,
    sync_provider_base_url_value: bool = True,
    require_running_process: bool = False,
    fail_on_health_check: bool = False,
) -> dict[str, Any]:
    proxy_kernel_service.require_spec(provider_id)
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    runtime_base_url = str(kernel.get("runtime_base_url") or "").strip().rstrip("/")
    if not runtime_base_url:
        raise ValueError("LOOPBACK_RUNTIME_NOT_REGISTERED")
    if not proxy_kernel_service.is_loopback_url(runtime_base_url):
        raise ValueError("LOOPBACK_RUNTIME_REQUIRED")
    process = proxy_kernel_service.process_status(provider_id)
    if require_running_process and not process.get("running"):
        raise ValueError("KERNEL_PROCESS_NOT_RUNNING")
    provider = db.get(models.Provider, provider_id)
    if sync_provider_base_url_value:
        provider = sync_proxy_kernel_provider_base_url(db, provider_id, runtime_base_url)
    elif not provider:
        raise ValueError("PROVIDER_NOT_INITIALIZED")
    health = run_provider_health_check_preserve_active(db, provider)
    ok = health.get("status") == "ok"
    if fail_on_health_check and not ok:
        raise ValueError("RUNTIME_HEALTH_CHECK_FAILED")
    return {
        "object": "media2api.proxy_kernel.runtime_health_check",
        "provider_id": provider_id,
        "ok": bool(ok),
        "runtime": {
            "base_url": runtime_base_url,
            "loopback_only": True,
            "registered": True,
        },
        "process": process,
        "provider": serialize_provider(provider),
        "health_check": health,
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "uses_provider_health_record": True,
        },
    }


def proxy_kernel_mapping_template_payload(provider_id: str, item: Any, priority_offset: int = 0) -> dict[str, Any]:
    return {
        "id": f"{item.logical_model}:{provider_id}:{item.provider_model}",
        "logical_model": item.logical_model,
        "provider_id": provider_id,
        "provider_model": item.provider_model,
        "operations": item.operations,
        "priority": item.priority + priority_offset,
        "weight": 1,
        "cost_score": item.cost_score,
        "speed_score": item.speed_score,
        "quality_score": item.quality_score,
        "reliability_score": item.reliability_score,
    }


def proxy_kernel_routing_plan(db: Session, provider_id: str) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    summary = proxy_kernel_service.kernel_summary(db, provider_id)
    provider = db.get(models.Provider, provider_id)
    accounts = db.query(models.AccountResource).filter(models.AccountResource.provider_id == provider_id).all()
    active_accounts = [account for account in accounts if account.status == "active"]
    existing_mappings = (
        db.query(models.ProviderModelMapping)
        .filter(models.ProviderModelMapping.provider_id == provider_id)
        .order_by(models.ProviderModelMapping.logical_model, models.ProviderModelMapping.priority, models.ProviderModelMapping.provider_model)
        .all()
    )
    existing_by_id = {mapping.id: mapping for mapping in existing_mappings}
    template_mappings = [proxy_kernel_mapping_template_payload(provider_id, item) for item in template.mappings]
    missing_mappings = [item for item in template_mappings if item["id"] not in existing_by_id]
    disabled_mappings = [serialize_mapping(mapping) for mapping in existing_mappings if not mapping.enabled]
    enabled_mapping_count = sum(1 for mapping in existing_mappings if mapping.enabled)
    route_config_ready = bool(provider and provider.status == "active" and enabled_mapping_count > 0)
    blockers = list(summary.get("blockers") or [])
    if provider and provider.status != "active":
        blockers.append({"code": "PROVIDER_DISABLED", "message": "Provider exists but is not active; apply routing with status=active when ready to route traffic."})
    if enabled_mapping_count == 0:
        blockers.append({"code": "NO_ENABLED_MAPPINGS", "message": "Apply the finalized provider template mappings before routing requests to this kernel."})
    elif missing_mappings:
        blockers.append({"code": "TEMPLATE_MAPPINGS_INCOMPLETE", "message": "Some finalized template mappings are missing for this provider."})
    next_actions: list[str] = []
    if provider and provider.status != "active":
        next_actions.append("Apply routing with provider status active, or keep it disabled until account/runtime checks are complete.")
    if not provider or missing_mappings or disabled_mappings:
        next_actions.append("Apply routing mappings; this creates provider/model routes only and does not create any fake account.")
    if not summary.get("runtime_registered"):
        next_actions.append("Install/register or start a verified loopback runtime.")
    if not active_accounts:
        next_actions.append("Import a real Web session or Agent Provider account for this provider.")
    if route_config_ready and summary.get("usable"):
        next_actions.append("Run live image/video acceptance samples before marking the provider production-ready.")
    return {
        "object": "media2api.proxy_kernel.routing_plan",
        "provider_id": provider_id,
        "selection_id": summary.get("selection_id"),
        "template": provider_template_payload(template),
        "provider": serialize_provider(provider) if provider else None,
        "provider_initialized": bool(provider),
        "provider_status": provider.status if provider else "missing",
        "runtime_registered": summary.get("runtime_registered", False),
        "runtime_base_url": summary.get("runtime_base_url", ""),
        "account_count": len(accounts),
        "active_account_count": len(active_accounts),
        "template_mapping_count": len(template_mappings),
        "existing_mapping_count": len(existing_mappings),
        "enabled_mapping_count": enabled_mapping_count,
        "template_mappings": template_mappings,
        "missing_mappings": missing_mappings,
        "disabled_mappings": disabled_mappings,
        "route_config_ready": route_config_ready,
        "production_ready": bool(route_config_ready and summary.get("usable")),
        "blockers": blockers,
        "next_actions": next_actions,
        "no_fake_account_created": True,
    }


def apply_proxy_kernel_routing(
    db: Session,
    provider_id: str,
    *,
    status: str = "active",
    enable_mappings: bool = True,
    priority_offset: int = 0,
    update_provider_base_url: bool = True,
) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    if status not in {"active", "disabled"}:
        raise ValueError("ROUTING_STATUS_UNSUPPORTED")
    summary_before = proxy_kernel_service.kernel_summary(db, provider_id)
    provider = db.get(models.Provider, provider_id)
    created_provider = False
    if not provider:
        provider = ensure_provider_from_template(db, provider_id, status=status)
        created_provider = True
    if not provider:
        raise KeyError(provider_id)

    provider.name = template.name
    provider.adapter_type = template.adapter_type
    provider.status = status
    if not provider.notes:
        provider.notes = template.notes
    template_config = provider_template_default_config(template.id, template.default_config)
    existing_config = provider_runtime_config(template.id, loads(provider.base_config_json, {}))
    next_config = {**template_config, **existing_config}
    runtime_base_url = str(summary_before.get("runtime_base_url") or "").strip()
    if update_provider_base_url and runtime_base_url:
        validated_base_url = validate_provider_base_url_input(template.id, runtime_base_url, field_name="runtime_base_url")
        if validated_base_url:
            next_config["base_url"] = validated_base_url
    provider.base_config_json = dumps(provider_runtime_config(template.id, next_config))
    db.flush()

    created: list[dict[str, Any]] = []
    updated: list[dict[str, Any]] = []
    skipped: list[dict[str, Any]] = []
    for item in template.mappings:
        logical_model = ensure_logical_model_seed(db, item.logical_model)
        if not logical_model:
            skipped.append({"logical_model": item.logical_model, "provider_model": item.provider_model, "reason": "logical_model_missing"})
            continue
        mapping_id = f"{item.logical_model}:{template.id}:{item.provider_model}"
        mapping = db.get(models.ProviderModelMapping, mapping_id)
        values = {
            "logical_model": item.logical_model,
            "provider_id": template.id,
            "provider_model": item.provider_model,
            "operations_json": dumps(item.operations),
            "priority": item.priority + priority_offset,
            "weight": 1,
            "cost_score": item.cost_score,
            "speed_score": item.speed_score,
            "quality_score": item.quality_score,
            "reliability_score": item.reliability_score,
            "enabled": enable_mappings,
        }
        if mapping:
            for key, value in values.items():
                setattr(mapping, key, value)
            updated.append(serialize_mapping(mapping))
        else:
            mapping = models.ProviderModelMapping(id=mapping_id, **values)
            db.add(mapping)
            db.flush()
            created.append(serialize_mapping(mapping))

    db.commit()
    return {
        "object": "media2api.proxy_kernel.routing_apply",
        "provider_id": provider_id,
        "selection_id": summary_before.get("selection_id"),
        "created_provider": created_provider,
        "provider": serialize_provider(provider),
        "mappings": {
            "created": created,
            "updated": updated,
            "skipped": skipped,
            "summary": {"created": len(created), "updated": len(updated), "skipped": len(skipped)},
        },
        "routing_plan": proxy_kernel_routing_plan(db, provider_id),
        "no_fake_account_created": True,
    }


def proxy_kernel_routing_provider_ids(db: Session, provider_ids: list[str] | None = None) -> list[str]:
    requested = [provider_id.strip() for provider_id in (provider_ids or []) if provider_id and provider_id.strip()]
    if not requested:
        requested = [item["provider_id"] for item in proxy_kernel_service.list_kernels(db).get("data", [])]
    selected: list[str] = []
    for provider_id in requested:
        if provider_id in selected:
            continue
        if provider_id not in PROVIDER_TEMPLATES:
            raise ValueError(f"PROVIDER_TEMPLATE_NOT_FOUND:{provider_id}")
        proxy_kernel_service.require_spec(provider_id)
        selected.append(provider_id)
    return selected


def summarize_proxy_kernel_routing_plans(plans: list[dict[str, Any]]) -> dict[str, Any]:
    blocker_counts: dict[str, int] = {}
    for plan in plans:
        for blocker in plan.get("blockers", []):
            code = str(blocker.get("code") or "UNKNOWN")
            blocker_counts[code] = blocker_counts.get(code, 0) + 1
    return {
        "total": len(plans),
        "provider_initialized": sum(1 for plan in plans if plan.get("provider_initialized")),
        "route_config_ready": sum(1 for plan in plans if plan.get("route_config_ready")),
        "production_ready": sum(1 for plan in plans if plan.get("production_ready")),
        "needs_account": sum(1 for plan in plans if any(blocker.get("code") == "NO_ACTIVE_ACCOUNT" for blocker in plan.get("blockers", []))),
        "needs_runtime": sum(1 for plan in plans if any(blocker.get("code") == "NO_LOOPBACK_RUNTIME" for blocker in plan.get("blockers", []))),
        "needs_mapping": sum(1 for plan in plans if any(blocker.get("code") in {"NO_ENABLED_MAPPINGS", "TEMPLATE_MAPPINGS_INCOMPLETE"} for blocker in plan.get("blockers", []))),
        "blocker_counts": blocker_counts,
    }


def proxy_kernel_bulk_routing_plan(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    plans = [proxy_kernel_routing_plan(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.routing_plan.list",
        "data": plans,
        "summary": summarize_proxy_kernel_routing_plans(plans),
        "no_fake_account_created": True,
    }


def apply_proxy_kernel_bulk_routing(
    db: Session,
    provider_ids: list[str] | None = None,
    *,
    status: str = "active",
    enable_mappings: bool = True,
    priority_offset: int = 0,
    update_provider_base_url: bool = True,
) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    results = [
        apply_proxy_kernel_routing(
            db,
            provider_id,
            status=status,
            enable_mappings=enable_mappings,
            priority_offset=priority_offset,
            update_provider_base_url=update_provider_base_url,
        )
        for provider_id in selected
    ]
    plans = [result["routing_plan"] for result in results]
    mapping_summary = {
        "created": sum(result["mappings"]["summary"]["created"] for result in results),
        "updated": sum(result["mappings"]["summary"]["updated"] for result in results),
        "skipped": sum(result["mappings"]["summary"]["skipped"] for result in results),
    }
    return {
        "object": "media2api.proxy_kernel.routing_apply.list",
        "data": results,
        "summary": {
            **summarize_proxy_kernel_routing_plans(plans),
            "created_providers": sum(1 for result in results if result.get("created_provider")),
            "mappings": mapping_summary,
        },
        "no_fake_account_created": True,
    }


def proxy_kernel_checklist_step(step_id: str, label: str, ok: bool, *, action: str, detail: dict[str, Any] | None = None) -> dict[str, Any]:
    return {
        "id": step_id,
        "label": label,
        "status": "done" if ok else "action_required",
        "ok": ok,
        "action": action,
        "detail": detail or {},
    }


def proxy_kernel_sample_models(plan: dict[str, Any]) -> dict[str, str]:
    result: dict[str, str] = {}
    mappings = plan.get("template_mappings") or []
    for operation, key in [
        ("text_to_image", "image_generation_model"),
        ("image_edit", "image_edit_model"),
        ("text_to_video", "video_generation_model"),
        ("image_to_video", "image_to_video_model"),
    ]:
        for mapping in mappings:
            if operation in (mapping.get("operations") or []) and mapping.get("logical_model"):
                result[key] = str(mapping["logical_model"])
                break
    return result


def build_proxy_kernel_go_live_checklist(db: Session, provider_id: str) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    summary = proxy_kernel_service.kernel_summary(db, provider_id)
    routing = proxy_kernel_routing_plan(db, provider_id)
    workflow = build_account_setup_workflow(db, provider_id, AccountSetupWorkflowRunRequest(include_preflight=False))
    guide = connector_registry_service.provider_guide(db, provider_id)
    input_requirements = PLATFORM_INPUT_REQUIREMENTS.get(provider_id, {}).get("user_inputs", [])
    sample_models = proxy_kernel_sample_models(routing)
    runtime_ok = bool(summary.get("runtime_registered") and summary.get("runtime_loopback_only"))
    route_ok = bool(routing.get("route_config_ready"))
    account_ok = bool(routing.get("active_account_count", 0) > 0)
    release_ok = bool((summary.get("installed") and summary.get("installed_verified")) or summary.get("runtime_registered"))
    ready_for_acceptance = route_ok and runtime_ok and account_ok
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    user_key = "$MEDIA2API_USER_API_KEY"
    commands = {
        "routing_plan": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/routing-plan",
        "apply_routing": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/apply-routing -d '{{\"status\":\"active\",\"enable_mappings\":true,\"priority_offset\":0,\"update_provider_base_url\":true}}'",
        "release_probe": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-probe",
        "install_release": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/install-release -d '{{\"tag_name\":\"vX.Y.Z\",\"asset_name\":\"example-linux-amd64.tar.gz\",\"expected_sha256\":\"64位十六进制sha256\"}}'",
        "register_runtime": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/register-runtime -d '{{\"base_url\":\"http://127.0.0.1:19081\",\"version\":\"vX.Y.Z\",\"sha256\":\"64位十六进制sha256\"}}'",
        "loopback_contract_test": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/loopback-contract-test -d '{{\"operations\":[\"text_to_image\",\"image_edit\",\"text_to_video\"]}}'",
        "account_guide": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/account-guides/{provider_id}",
        "account_setup_workflow": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/account-setup-workflows/{provider_id}",
        "account_acceptance_suite": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/account-acceptance-suite -d '{json.dumps({'dry_run': True, 'external_only': True, 'provider_ids': [provider_id], 'operations': template.operations, 'run_samples': True, 'max_samples': 1}, ensure_ascii=False, separators=(',', ':'))}'",
        "live_acceptance": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{json.dumps({'dry_run': True, 'operations': template.operations, 'run_samples': True, 'max_samples': 1}, ensure_ascii=False, separators=(',', ':'))}'",
    }
    if sample_models.get("image_generation_model"):
        commands["sample_image_generation"] = f"curl -X POST -H \"Authorization: Bearer {user_key}\" -H \"Content-Type: application/json\" {base}/v1/images/generations -d '{json.dumps({'model': sample_models['image_generation_model'], 'prompt': 'one small product render on a dark desk', 'size': '1024x1024', 'wait': True}, ensure_ascii=False, separators=(',', ':'))}'"
    if sample_models.get("video_generation_model"):
        commands["sample_video_generation"] = f"curl -X POST -H \"Authorization: Bearer {user_key}\" -H \"Content-Type: application/json\" {base}/v1/videos/generations -d '{json.dumps({'model': sample_models['video_generation_model'], 'prompt': 'a short cinematic product turntable', 'duration': 3, 'wait': True}, ensure_ascii=False, separators=(',', ':'))}'"
    steps = [
        proxy_kernel_checklist_step(
            "routing",
            "Provider 与模型路由",
            route_ok,
            action="点击“补齐路由映射”或调用 apply-routing。",
            detail={
                "enabled_mapping_count": routing.get("enabled_mapping_count", 0),
                "template_mapping_count": routing.get("template_mapping_count", 0),
                "blockers": [item for item in routing.get("blockers", []) if item.get("code") in {"PROVIDER_NOT_INITIALIZED", "PROVIDER_DISABLED", "NO_ENABLED_MAPPINGS", "TEMPLATE_MAPPINGS_INCOMPLETE"}],
            },
        ),
        proxy_kernel_checklist_step(
            "runtime",
            "Loopback 执行器",
            runtime_ok,
            action="安装已校验 release 资产并启动/登记 127.0.0.1 runtime。",
            detail={
                "runtime_registered": summary.get("runtime_registered", False),
                "runtime_base_url": summary.get("runtime_base_url", ""),
                "runtime_loopback_only": summary.get("runtime_loopback_only", False),
                "process": summary.get("process", {}),
            },
        ),
        proxy_kernel_checklist_step(
            "release_asset",
            "Release 资产与 SHA256",
            release_ok,
            action="优先安装 release 二进制并提供 expected_sha256；源码只进 source-repo 参考。",
            detail={
                "installed": summary.get("installed", {}),
                "installed_verified": summary.get("installed_verified", False),
                "source_policy": (summary.get("spec") or {}).get("install_policy", {}),
            },
        ),
        proxy_kernel_checklist_step(
            "account",
            "真实授权账号",
            account_ok,
            action="到“授权资源”按字段指南导入真实 Web Cookie/session 或 Agent Provider profile。",
            detail={
                "account_count": routing.get("account_count", 0),
                "active_account_count": routing.get("active_account_count", 0),
                "resource_type": guide.get("resource_type"),
                "auth_methods": guide.get("auth_methods", []),
                "input_requirements": input_requirements,
            },
        ),
        proxy_kernel_checklist_step(
            "live_acceptance",
            "真实样本验收",
            ready_for_acceptance,
            action="账号、runtime 和路由都就绪后，先用 dry_run 再运行 1 条真实样本验收。",
            detail={
                "ready_for_acceptance": ready_for_acceptance,
                "sample_models": sample_models,
                "operations": template.operations,
            },
        ),
    ]
    next_step = next((step for step in steps if not step["ok"]), None)
    return {
        "object": "media2api.proxy_kernel.go_live_checklist",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": summary.get("selection_id"),
        "status": "ready_for_live_acceptance" if ready_for_acceptance else "action_required",
        "usable": bool(summary.get("usable")),
        "ready_for_live_acceptance": ready_for_acceptance,
        "production_ready": False,
        "next_step": next_step or {"id": "live_acceptance", "label": "真实样本验收", "action": "运行账号验收并确认真实图片/视频资产入库。"},
        "steps": steps,
        "kernel": summary,
        "routing": routing,
        "account_workflow": {
            "status": workflow.get("status"),
            "summary": workflow.get("summary"),
            "next_action": workflow.get("next_action"),
            "commands": workflow.get("commands"),
        },
        "guide": {
            "resource_type": guide.get("resource_type"),
            "auth_methods": guide.get("auth_methods", []),
            "credential_ref_example": guide.get("credential_ref_example"),
            "input_requirements": input_requirements,
        },
        "commands": commands,
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "no_fake_account_created": True,
        },
    }


def proxy_kernel_go_live_checklist_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "total": len(rows),
        "ready_for_live_acceptance": sum(1 for row in rows if row.get("ready_for_live_acceptance")),
        "needs_routing": sum(1 for row in rows if any(step["id"] == "routing" and not step["ok"] for step in row.get("steps", []))),
        "needs_runtime": sum(1 for row in rows if any(step["id"] == "runtime" and not step["ok"] for step in row.get("steps", []))),
        "needs_account": sum(1 for row in rows if any(step["id"] == "account" and not step["ok"] for step in row.get("steps", []))),
        "needs_acceptance": sum(1 for row in rows if any(step["id"] == "live_acceptance" and not step["ok"] for step in row.get("steps", []))),
    }


def build_proxy_kernel_go_live_checklists(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_go_live_checklist(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.go_live_checklist.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": proxy_kernel_go_live_checklist_summary(rows),
        "data": rows,
    }


def proxy_kernel_material_field(item: dict[str, Any]) -> dict[str, Any]:
    name = str(item.get("name") or "").strip()
    store_as = str(item.get("store_as") or "")
    auth_method = str(item.get("auth_method") or "")
    if name in RUNTIME_BASE_URL_FIELD_NAMES:
        where_to_put = "runtime_or_provider_base_url"
    elif auth_method or "secret" in store_as or "credential" in store_as:
        where_to_put = "encrypted_credential_or_agent_ref"
    else:
        where_to_put = "account_resource_profile"
    payload = {
        "name": name,
        "label": item.get("label") or name,
        "required": bool(item.get("required")),
        "any_of_group": item.get("any_of_group") or "",
        "auth_method": auth_method,
        "store_as": store_as,
        "where_to_put": where_to_put,
        "when": item.get("when") or "",
        "evidence": item.get("evidence") or "",
        "aliases": item.get("aliases") or [],
        "require_named_field": bool(item.get("require_named_field")),
    }
    return payload


def proxy_kernel_material_groups(fields: list[dict[str, Any]]) -> list[dict[str, Any]]:
    groups: dict[str, list[dict[str, Any]]] = {}
    for field in fields:
        group = str(field.get("any_of_group") or "").strip()
        if group:
            groups.setdefault(group, []).append(field)
    return [
        {
            "group": group,
            "required": any(field.get("required") for field in group_fields),
            "choose": "one_of",
            "fields": group_fields,
        }
        for group, group_fields in sorted(groups.items())
    ]


def proxy_kernel_required_account_materials(fields: list[dict[str, Any]]) -> list[dict[str, Any]]:
    grouped = {field.get("any_of_group") for field in fields if field.get("any_of_group")}
    materials = [
        {
            "type": "account_field",
            "name": field.get("name"),
            "label": field.get("label"),
            "where_to_put": field.get("where_to_put"),
            "required_from_user": True,
        }
        for field in fields
        if field.get("required") and not field.get("any_of_group")
    ]
    for group in sorted(grouped):
        group_fields = [field for field in fields if field.get("any_of_group") == group]
        if any(field.get("required") for field in group_fields):
            materials.append(
                {
                    "type": "account_any_of_group",
                    "name": group,
                    "label": " / ".join(str(field.get("label") or field.get("name")) for field in group_fields),
                    "where_to_put": "encrypted_credential_or_agent_ref",
                    "required_from_user": True,
                    "choose": "one_of",
                    "fields": group_fields,
                }
            )
    return materials


def proxy_kernel_materials_request_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "total": len(rows),
        "ready_for_live_acceptance": sum(1 for row in rows if row.get("ready_for_live_acceptance")),
        "materials_required": sum(1 for row in rows if row.get("status") == "materials_required"),
        "needs_account_materials": sum(1 for row in rows if row.get("account_materials", {}).get("status") != "ready"),
        "needs_runtime_materials": sum(1 for row in rows if row.get("runtime_materials", {}).get("status") != "ready"),
        "needs_routing_materials": sum(1 for row in rows if row.get("routing_materials", {}).get("status") != "ready"),
        "needs_live_acceptance": sum(1 for row in rows if row.get("validation_materials", {}).get("status") != "ready_to_run"),
        "required_material_count": sum(len(row.get("required_materials", [])) for row in rows),
    }


def build_proxy_kernel_materials_request(db: Session, provider_id: str) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    go_live = build_proxy_kernel_go_live_checklist(db, provider_id)
    kernel = go_live.get("kernel") or proxy_kernel_service.kernel_summary(db, provider_id)
    routing = go_live.get("routing") or proxy_kernel_routing_plan(db, provider_id)
    guide = connector_registry_service.provider_guide(db, provider_id)
    input_requirements = PLATFORM_INPUT_REQUIREMENTS.get(provider_id, {}).get("user_inputs", [])
    fields = [proxy_kernel_material_field(item) for item in input_requirements if item.get("name")]
    runtime_input_fields = [field for field in fields if field.get("name") in RUNTIME_BASE_URL_FIELD_NAMES or field.get("where_to_put") == "runtime_or_provider_base_url"]
    account_input_fields = [field for field in fields if field not in runtime_input_fields]
    fields_by_destination = proxy_kernel_account_fields_by_destination(account_input_fields)
    account_required = proxy_kernel_required_account_materials(account_input_fields)
    runtime_ok = bool(kernel.get("runtime_registered") and kernel.get("runtime_loopback_only"))
    route_ok = bool(routing.get("route_config_ready"))
    account_ok = bool(routing.get("active_account_count", 0) > 0)
    ready_for_acceptance = bool(go_live.get("ready_for_live_acceptance"))
    release_ok = any(step.get("id") == "release_asset" and step.get("ok") for step in go_live.get("steps", []))
    required_materials: list[dict[str, Any]] = []
    if not account_ok:
        required_materials.extend(account_required)
        if not account_required:
            required_materials.append(
                {
                    "type": "authorized_account",
                    "name": "account_credential",
                    "label": "Authorized Web session / OAuth profile / agent credential",
                    "where_to_put": "encrypted_credential_or_agent_ref",
                    "required_from_user": True,
                }
            )
    if not runtime_ok:
        required_materials.append(
            {
                "type": "runtime_release_or_loopback",
                "name": "runtime_material",
                "label": "Release asset + SHA256, or an already started loopback runtime",
                "fields": [
                    {"name": "tag_name", "required": False, "where_to_put": "install_release"},
                    {"name": "asset_name", "required": True, "where_to_put": "install_release"},
                    {"name": "expected_sha256", "required": True, "where_to_put": "install_release_or_start_runtime"},
                    {"name": "base_url", "required": True, "where_to_put": "register_runtime", "example": "http://127.0.0.1:19081"},
                    {"name": "command", "required": True, "where_to_put": "start_runtime", "format": "one argument per line or JSON string array"},
                ],
                "required_from_user": True,
            }
        )
    if not route_ok:
        required_materials.append(
            {
                "type": "routing_apply",
                "name": "provider_model_mappings",
                "label": "Provider/model route mappings",
                "platform_can_generate": True,
                "required_from_user": False,
            }
        )
    if route_ok and runtime_ok and account_ok and not ready_for_acceptance:
        required_materials.append(
            {
                "type": "live_acceptance",
                "name": "one_real_sample",
                "label": "One real image/video acceptance sample",
                "requires_user_api_key": True,
                "required_from_user": False,
            }
        )

    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    commands = {
        "materials_request": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/materials-request",
        "go_live_checklist": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/go-live-checklist",
        "routing_plan": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/routing-plan",
        "apply_routing": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/apply-routing -d '{{\"status\":\"active\",\"enable_mappings\":true,\"priority_offset\":0,\"update_provider_base_url\":true}}'",
        "release_probe": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-probe",
        "install_release": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/install-release -d '{{\"tag_name\":\"vX.Y.Z\",\"asset_name\":\"example-linux-amd64.tar.gz\",\"expected_sha256\":\"64-hex-sha256\"}}'",
        "register_runtime": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/register-runtime -d '{{\"base_url\":\"http://127.0.0.1:19081\",\"version\":\"vX.Y.Z\",\"sha256\":\"64-hex-sha256\"}}'",
        "loopback_contract_test": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/loopback-contract-test -d '{{\"operations\":[\"text_to_image\",\"image_edit\",\"text_to_video\"]}}'",
        "account_guide": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/account-guides/{provider_id}",
        "account_setup_workflow": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/account-setup-workflows/{provider_id}",
        "account_onboarding": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/account-onboarding",
    }
    for key in ["account_acceptance_suite", "live_acceptance", "sample_image_generation", "sample_video_generation"]:
        if key in (go_live.get("commands") or {}):
            commands[key] = go_live["commands"][key]

    account_labels = [str(item.get("label") or item.get("name")) for item in account_required]
    runtime_labels = ["release tag/asset/SHA256", "loopback base_url", "start command"] if not runtime_ok else []
    message_to_user = [
        f"{kernel.get('selection_id') or provider_id} / {provider_id}",
        "Need real account material: " + (", ".join(account_labels) if account_labels else "already satisfied") if not account_ok else "Account material is already satisfied.",
        "Need runtime material: " + ", ".join(runtime_labels) if not runtime_ok else "Runtime material is already satisfied.",
        "Route mappings can be generated by the platform without fake accounts." if not route_ok else "Route mappings are ready.",
        "Run one live acceptance sample only after account, runtime, and routing are ready.",
    ]
    return {
        "object": "media2api.proxy_kernel.materials_request",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "status": "ready_for_live_acceptance" if ready_for_acceptance else "materials_required",
        "usable": bool(kernel.get("usable")),
        "ready_for_live_acceptance": ready_for_acceptance,
        "production_ready": False,
        "next_step": go_live.get("next_step"),
        "required_materials": required_materials,
        "message_to_user": message_to_user,
        "account_materials": {
            "status": "ready" if account_ok else "needed",
            "resource_type": guide.get("resource_type"),
            "accepted_resource_types": guide.get("accepted_resource_types", []),
            "auth_methods": guide.get("recommended_auth_methods", []),
            "credential_ref_example": guide.get("credential_ref_example"),
            "required_fields": [field for field in account_input_fields if field.get("required") and not field.get("any_of_group")],
            "optional_fields": [field for field in account_input_fields if not field.get("required")],
            "any_of_groups": proxy_kernel_material_groups(account_input_fields),
            "fields_by_destination": fields_by_destination,
            "credential_fields": fields_by_destination["credential_value"],
            "resource_profile_fields": fields_by_destination["resource_profile"],
            "resource_profile_template": platform_resource_profile_template(provider_id),
            "user_actions": guide.get("user_actions", []),
            "existing_account_count": routing.get("account_count", 0),
            "active_account_count": routing.get("active_account_count", 0),
        },
        "runtime_materials": {
            "status": "ready" if runtime_ok else "needed",
            "release_asset_status": "ready" if release_ok else "needed",
            "runtime_registered": bool(kernel.get("runtime_registered")),
            "runtime_base_url": kernel.get("runtime_base_url") or "",
            "runtime_loopback_only": bool(kernel.get("runtime_loopback_only")),
            "runtime_input_fields": runtime_input_fields,
            "installed": kernel.get("installed", {}),
            "installed_verified": bool(kernel.get("installed_verified")),
            "release_required_fields": [
                {"name": "tag_name", "required": False},
                {"name": "asset_name", "required": True},
                {"name": "expected_sha256", "required": True},
            ],
            "register_runtime_required_fields": [
                {"name": "base_url", "required": True, "example": "http://127.0.0.1:19081"},
                {"name": "version", "required": False},
                {"name": "binary_path", "required": False},
                {"name": "sha256", "required": False},
            ],
            "start_runtime_required_fields": [
                {"name": "command", "required": True},
                {"name": "base_url", "required": True},
                {"name": "artifact_path", "required": True},
                {"name": "expected_sha256", "required": True},
                {"name": "run_health_check", "required": False, "default": True},
                {"name": "fail_on_health_check", "required": False, "default": False},
            ],
            "source_repo_fallback": (kernel.get("spec") or {}).get("source_repo_policy", {}),
            "install_policy": (kernel.get("spec") or {}).get("install_policy", {}),
        },
        "routing_materials": {
            "status": "ready" if route_ok else "needed",
            "platform_can_generate": True,
            "route_config_ready": route_ok,
            "template_mapping_count": routing.get("template_mapping_count", 0),
            "enabled_mapping_count": routing.get("enabled_mapping_count", 0),
            "missing_mapping_count": len(routing.get("missing_mappings", [])),
            "apply_payload": {"status": "active", "enable_mappings": True, "priority_offset": 0, "update_provider_base_url": True},
        },
        "validation_materials": {
            "status": "ready_to_run" if ready_for_acceptance else "waiting_for_account_runtime_routing",
            "admin_api_key_env": "$MEDIA2API_API_KEY",
            "user_api_key_env": "$MEDIA2API_USER_API_KEY",
            "sample_models": proxy_kernel_sample_models(routing),
            "operations": template.operations,
        },
        "platform_can_generate": [
            "provider/model route mappings from finalized templates",
            "encrypted credential refs after the operator submits account material",
            "user API keys from the platform key management workflow",
            "controlled runtime registration once a loopback base_url or verified artifact is provided",
        ],
        "must_be_provided_by_operator": [item for item in required_materials if item.get("required_from_user")],
        "commands": commands,
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "release_binary_preferred": True,
            "source_repo_only_when_needed": True,
            "no_fake_account_created": True,
            "read_only": True,
            "upstream_calls": False,
        },
    }


def build_proxy_kernel_materials_requests(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_materials_request(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.materials_request.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": proxy_kernel_materials_request_summary(rows),
        "data": rows,
    }


def proxy_kernel_operator_account_payload_template(provider_id: str, template: Any, materials: dict[str, Any], guide: dict[str, Any]) -> dict[str, Any]:
    account_materials = materials.get("account_materials") or {}
    auth_methods = list(account_materials.get("auth_methods") or guide.get("recommended_auth_methods") or guide.get("auth_methods") or [])
    auth_method = str(auth_methods[0] if auth_methods else "agent_provider_credential")
    resource_type = str(account_materials.get("resource_type") or guide.get("resource_type") or ("web_cookie_provider" if auth_method == "cookie_secret" else "agent_provider"))
    credential_kind = "cookie" if auth_method == "cookie_secret" else "agent_provider"
    provider_models = sorted({str(item.provider_model) for item in template.mappings if getattr(item, "provider_model", "")})
    return {
        "provider_id": provider_id,
        "account_id": f"acct_{provider_id}_01",
        "label": f"{template.name} primary account",
        "resource_type": resource_type,
        "auth_method": auth_method,
        "credential_kind": credential_kind,
        "credential_value": "<paste provider-specific JSON/env/profile material here>",
        "credential_ref": "",
        "resource_profile": account_materials.get("resource_profile_template") or platform_resource_profile_template(provider_id),
        "supported_operations": list(template.operations),
        "supported_provider_models": provider_models,
        "quota_buckets": [],
        "concurrency_limit": 1,
        "status": "active",
        "sync_capabilities": False,
        "run_health_check": False,
    }


def proxy_kernel_account_material_value_template(account_materials: dict[str, Any]) -> dict[str, Any]:
    fields: dict[str, Any] = {}
    credential_fields = account_materials.get("credential_fields") or account_materials.get("required_fields") or []
    for field in credential_fields:
        if field.get("where_to_put") and field.get("where_to_put") != "encrypted_credential_or_agent_ref":
            continue
        if not field.get("required"):
            continue
        if field.get("any_of_group"):
            continue
        name = str(field.get("name") or "").strip()
        if name:
            fields[name] = f"<{name}>"
    for group in account_materials.get("any_of_groups") or []:
        group_name = str(group.get("group") or "one_of").strip()
        options = [
            str(field.get("name") or "").strip()
            for field in group.get("fields") or []
            if str(field.get("name") or "").strip() and field.get("where_to_put") == "encrypted_credential_or_agent_ref"
        ]
        if options:
            fields[f"choose_one_of_{group_name}"] = options
            fields[options[0]] = f"<{options[0]}>"
    return fields


def proxy_kernel_account_fields_by_destination(fields: list[dict[str, Any]]) -> dict[str, list[dict[str, Any]]]:
    buckets = {
        "credential_value": [],
        "resource_profile": [],
        "runtime_or_provider_base_url": [],
        "other": [],
    }
    for field in fields:
        destination = str(field.get("where_to_put") or "")
        if destination == "encrypted_credential_or_agent_ref":
            buckets["credential_value"].append(field)
        elif destination == "account_resource_profile":
            buckets["resource_profile"].append(field)
        elif destination == "runtime_or_provider_base_url":
            buckets["runtime_or_provider_base_url"].append(field)
        else:
            buckets["other"].append(field)
    return buckets


def proxy_kernel_account_field_instructions(account_materials: dict[str, Any]) -> list[dict[str, Any]]:
    credential_fields = account_materials.get("credential_fields") or []
    profile_fields = account_materials.get("resource_profile_fields") or []
    instructions: list[dict[str, Any]] = []
    if credential_fields or account_materials.get("any_of_groups"):
        instructions.append(
            {
                "section": "credential_value",
                "title": "Credential Value JSON",
                "message": "Paste secret material here: cookie/session/OAuth/profile/token. This value is encrypted or converted to a managed credential ref and is never echoed back.",
                "field_names": [field.get("name") for field in credential_fields if field.get("name")],
            }
        )
    if profile_fields:
        instructions.append(
            {
                "section": "resource_profile",
                "title": "Resource Profile JSON",
                "message": "Put non-secret routing/profile fields here, such as guild_id, channel_id, project_id, region, plan, account email, or cookie domain.",
                "field_names": [field.get("name") for field in profile_fields if field.get("name")],
            }
        )
    return instructions


def proxy_kernel_redact_account_material_payload(payload: dict[str, Any]) -> dict[str, Any]:
    safe = deepcopy(payload)
    if credential_material_to_text(safe.get("credential_value")):
        safe["credential_value"] = "[provided]"
    if safe.get("credential_ref"):
        safe["credential_ref"] = redact_credential_ref(str(safe.get("credential_ref") or ""))
    if isinstance(safe.get("resource_profile"), dict):
        safe["resource_profile"] = redact_resource_profile(safe["resource_profile"])
    if isinstance(safe.get("provider_config"), dict):
        safe["provider_config"] = redact_config(safe["provider_config"])
    return safe


def credential_material_contains_template_placeholder(value: Any) -> bool:
    if value in (None, ""):
        return False
    if isinstance(value, str):
        text = value.strip()
        lowered = text.lower()
        return bool(re.fullmatch(r"<[^<>]+>", text)) or "<paste" in lowered or "paste-real" in lowered
    if isinstance(value, dict):
        return any(credential_material_contains_template_placeholder(child) for child in value.values())
    if isinstance(value, list):
        return any(credential_material_contains_template_placeholder(child) for child in value)
    return False


GEMINI_CLI_OAUTH_CLIENT_ID_ENV = "MEDIA2API_GEMINI_CLI_OAUTH_CLIENT_ID"
GEMINI_CLI_OAUTH_CLIENT_SECRET_ENV = "MEDIA2API_GEMINI_CLI_OAUTH_CLIENT_SECRET"
GEMINI_CLI_OAUTH_SCOPES = [
    "https://www.googleapis.com/auth/cloud-platform",
    "https://www.googleapis.com/auth/userinfo.email",
    "https://www.googleapis.com/auth/userinfo.profile",
]
GEMINI_CLI_TOKEN_KEYS = {
    "access_token",
    "refresh_token",
    "token_type",
    "expiry",
    "expiry_date",
    "expires_at",
    "scope",
    "scopes",
    "token_uri",
    "client_id",
    "client_secret",
    "universe_domain",
}


def parse_json_object_material(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return deepcopy(value)
    text = credential_material_to_text(value)
    if not text:
        return {}
    try:
        parsed = json.loads(text)
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


def decode_base64_json_object(value: Any) -> dict[str, Any]:
    text = credential_material_to_text(value)
    if not text:
        return {}
    if "," in text and text.lower().startswith("data:"):
        text = text.split(",", 1)[1]
    padding = "=" * ((4 - len(text) % 4) % 4)
    try:
        raw = base64.b64decode((text + padding).encode("utf-8"), validate=False)
    except Exception:
        return {}
    try:
        parsed = json.loads(raw.decode("utf-8"))
    except Exception:
        return {}
    return parsed if isinstance(parsed, dict) else {}


def gemini_cli_oauth_candidate_from_material(value: Any) -> tuple[dict[str, Any], str]:
    root = parse_json_object_material(value)
    if not root:
        return {}, ""
    for key in ["gemini_oauth_creds_base64", "oauth_creds_base64", "credentials_base64"]:
        if profile_value_present(root.get(key)):
            return decode_base64_json_object(root.get(key)), key
    for key in ["gemini_oauth_creds_file", "gemini_oauth_credentials", "oauth_creds", "credentials", "credential"]:
        if not profile_value_present(root.get(key)):
            continue
        child = root.get(key)
        if isinstance(child, dict):
            return deepcopy(child), key
        parsed = parse_json_object_material(child)
        if parsed:
            return parsed, key
        return {}, key
    if root.get("token") or any(profile_value_present(root.get(key)) for key in GEMINI_CLI_TOKEN_KEYS):
        return root, "credential_value"
    return {}, ""


def normalize_gemini_cli_oauth_auth_json(
    credential_value: Any,
    *,
    account_id: str,
    label: str,
    resource_profile: dict[str, Any] | None = None,
) -> tuple[dict[str, Any], dict[str, Any]]:
    candidate, source_field = gemini_cli_oauth_candidate_from_material(credential_value)
    if not candidate:
        raise HTTPException(
            status_code=400,
            detail={
                "error": "GEMINI_CLI_OAUTH_JSON_REQUIRED",
                "message": "Submit gemini_oauth_creds_file as JSON content/object or gemini_oauth_creds_base64 as base64-encoded JSON.",
            },
        )

    resource_profile = resource_profile or {}
    token = candidate.get("token")
    if isinstance(token, str):
        token = parse_json_object_material(token)
    if not isinstance(token, dict):
        token = {key: candidate.get(key) for key in GEMINI_CLI_TOKEN_KEYS if profile_value_present(candidate.get(key))}
    token = {str(key): value for key, value in dict(token or {}).items() if profile_value_present(value)}
    if not token or not any(token.get(key) for key in ("refresh_token", "access_token")):
        raise HTTPException(
            status_code=400,
            detail={
                "error": "GEMINI_CLI_OAUTH_TOKEN_REQUIRED",
                "message": "Gemini CLI OAuth material must include token.refresh_token or token.access_token.",
            },
        )

    token.setdefault("token_uri", "https://oauth2.googleapis.com/token")
    env_client_id = os.environ.get(GEMINI_CLI_OAUTH_CLIENT_ID_ENV, "").strip()
    env_client_secret = os.environ.get(GEMINI_CLI_OAUTH_CLIENT_SECRET_ENV, "").strip()
    if env_client_id:
        token.setdefault("client_id", env_client_id)
    if env_client_secret:
        token.setdefault("client_secret", env_client_secret)
    token.setdefault("scopes", GEMINI_CLI_OAUTH_SCOPES)
    token.setdefault("universe_domain", "googleapis.com")

    clean: dict[str, Any] = {
        key: value
        for key, value in candidate.items()
        if key not in GEMINI_CLI_TOKEN_KEYS and key not in {"token", "gemini_oauth_creds_file", "gemini_oauth_creds_base64"}
    }
    clean["type"] = "gemini"
    clean["token"] = token
    email = (
        str(candidate.get("email") or resource_profile.get("email") or resource_profile.get("account_email") or "").strip()
        or str(label or account_id).strip()
    )
    project_id = str(
        candidate.get("project_id")
        or candidate.get("gemini_project_id")
        or resource_profile.get("project_id")
        or resource_profile.get("gemini_project_id")
        or ""
    ).strip()
    if email:
        clean["email"] = email
    if project_id:
        clean["project_id"] = project_id
    clean["auto"] = bool(clean.get("auto", not bool(project_id)))
    clean["checked"] = bool(clean.get("checked", False))
    metadata = {
        "source_field": source_field,
        "email_present": bool(email),
        "project_id_present": bool(project_id),
        "token_fields": sorted(token.keys()),
    }
    return clean, metadata


def runtime_account_auth_file_name(provider_id: str, account_id: str, auth_payload: dict[str, Any]) -> str:
    if provider_id == "gemini_cli_oauth":
        email = str(auth_payload.get("email") or account_id).strip()
        project_id = str(auth_payload.get("project_id") or "auto").strip()
        return f"gemini-{email}-{project_id}.json"
    return f"{provider_id}-{account_id}.json"


def build_proxy_kernel_runtime_credential_sync(
    db: Session,
    provider_id: str,
    req: ProxyKernelRuntimeCredentialSyncRequest,
) -> dict[str, Any]:
    account: models.AccountResource | None = None
    if req.account_id:
        account = db.get(models.AccountResource, req.account_id)
        if not account or account.provider_id != provider_id:
            if credential_material_to_text(req.credential_value) or (req.credential_ref or "").strip() or req.credential_secret_id:
                account = None
            else:
                return {
                    "object": "media2api.proxy_kernel.runtime_credential_sync",
                    "provider_id": provider_id,
                    "account_id": req.account_id,
                    "dry_run": req.dry_run,
                    "status": "needs_credential_material",
                    "ok": False,
                    "message": "Account is not imported yet; submit credential_value or import account materials first.",
                }

    credential_ref = (req.credential_ref or "").strip()
    if not credential_ref and req.credential_secret_id:
        credential_ref = f"secret://{req.credential_secret_id}"
    if not credential_ref and account:
        credential_ref = account.credential_ref

    credential_value = req.credential_value if req.credential_value not in (None, "") else ""
    if not credential_material_to_text(credential_value) and credential_ref:
        if credential_ref.startswith("secret://"):
            credential_value = credential_secret_ref_value_for_validation(db, credential_ref)
        else:
            return {
                "object": "media2api.proxy_kernel.runtime_credential_sync",
                "provider_id": provider_id,
                "account_id": account.id if account else (req.account_id or ""),
                "dry_run": req.dry_run,
                "status": "reference_only",
                "ok": False,
                "credential_ref": redact_credential_ref(credential_ref),
                "message": "Runtime credential sync requires decryptable local secret:// material; external agent:// references remain platform-side references.",
            }
    if not credential_material_to_text(credential_value):
        return {
            "object": "media2api.proxy_kernel.runtime_credential_sync",
            "provider_id": provider_id,
            "account_id": account.id if account else (req.account_id or ""),
            "dry_run": req.dry_run,
            "status": "needs_credential_material",
            "ok": False,
            "message": "Provide credential_value, credential_secret_id, credential_ref, or account_id with a secret:// credential.",
        }

    account_id = account.id if account else (req.account_id or f"acct_{provider_id}_runtime")
    label = account.label if account else account_id
    resource_profile = req.resource_profile or (loads(account.resource_profile_json, {}) if account else {})
    if provider_id == "gemini_cli_oauth":
        auth_payload, metadata = normalize_gemini_cli_oauth_auth_json(
            credential_value,
            account_id=account_id,
            label=label,
            resource_profile=resource_profile,
        )
    else:
        return {
            "object": "media2api.proxy_kernel.runtime_credential_sync",
            "provider_id": provider_id,
            "account_id": account_id,
            "dry_run": req.dry_run,
            "status": "unsupported",
            "ok": False,
            "message": "Runtime credential file sync is currently implemented for gemini_cli_oauth.",
        }
    return proxy_kernel_service.write_runtime_account_auth_json(
        provider_id,
        account_id=account_id,
        file_name=runtime_account_auth_file_name(provider_id, account_id, auth_payload),
        payload=auth_payload,
        dry_run=req.dry_run,
        metadata=metadata,
    )


def proxy_kernel_account_material_payload_from_request(
    provider_id: str,
    template: Any,
    materials: dict[str, Any],
    guide: dict[str, Any],
    req: ProxyKernelAccountMaterialsRequest | None,
) -> dict[str, Any]:
    payload = proxy_kernel_operator_account_payload_template(provider_id, template, materials, guide)
    payload["credential_value"] = ""
    payload["credential_ref"] = ""
    if not req:
        return payload
    simple_fields = [
        "account_id",
        "label",
        "resource_type",
        "provider_base_url",
        "auth_method",
        "credential_ref",
        "credential_secret_id",
        "credential_kind",
        "concurrency_limit",
        "region",
        "plan",
        "status",
        "upsert",
        "auto_create_mappings",
        "sync_capabilities",
        "run_health_check",
    ]
    for field in simple_fields:
        value = getattr(req, field)
        if value is not None and value != "":
            payload[field] = value
    if req.credential_value not in (None, ""):
        payload["credential_value"] = req.credential_value
    if req.resource_profile:
        payload["resource_profile"] = {**(payload.get("resource_profile") or {}), **req.resource_profile}
    if req.provider_config:
        payload["provider_config"] = {**(payload.get("provider_config") or {}), **req.provider_config}
    if req.supported_operations:
        payload["supported_operations"] = req.supported_operations
    if req.supported_provider_models:
        payload["supported_provider_models"] = req.supported_provider_models
    if req.quota_buckets:
        payload["quota_buckets"] = req.quota_buckets
    return payload


def proxy_kernel_account_material_preflight(db: Session, provider_id: str, payload: dict[str, Any]) -> dict[str, Any]:
    try:
        auth_method = validate_provider_auth_method(provider_id, str(payload.get("auth_method") or "agent_provider_credential"))
        requested_credential_kind = str(payload.get("credential_kind") or credential_kind_for_auth_method(auth_method))
        if auth_method == "cookie_secret":
            requested_credential_kind = "cookie"
        if auth_method == "agent_provider_credential":
            requested_credential_kind = "agent_provider"
        resource_type = validate_provider_resource_type(
            provider_id,
            infer_account_resource_type(provider_id, auth_method, payload.get("resource_type")),
            auth_method=auth_method,
            credential_kind=requested_credential_kind,
        )
        provider_config = dict(payload.get("provider_config") or {})
        provider_base_url = validate_provider_base_url_input(provider_id, payload.get("provider_base_url"))
        if provider_base_url:
            provider_config["base_url"] = provider_base_url
        if not provider_runtime_base_url_allowed(provider_id):
            provider_config = strip_runtime_base_url_fields(provider_config)
        resource_profile = dict(payload.get("resource_profile") or {})
        validate_runtime_base_url_fields(provider_id, provider_config, field_name="provider_config")
        validate_runtime_base_url_fields(provider_id, resource_profile, field_name="resource_profile")
        validate_platform_provider_config_fields(provider_id, provider_config, field_name="provider_config")
        validate_platform_resource_profile_fields(provider_id, resource_profile, field_name="resource_profile")
        validate_required_platform_inputs(
            provider_id,
            auth_method=auth_method,
            resource_type=resource_type,
            provider_config=provider_config,
            resource_profile=resource_profile,
            credential_ref=payload.get("credential_ref"),
            credential_value=payload.get("credential_value"),
            credential_secret_id=payload.get("credential_secret_id"),
            db=db,
        )
        if not payload.get("credential_ref") and not credential_material_to_text(payload.get("credential_value")) and not payload.get("credential_secret_id"):
            raise HTTPException(status_code=400, detail={"error": "CREDENTIAL_VALUE_REQUIRED", "message": "Paste credential_value or submit a secret:// / agent:// credential_ref."})
        if credential_material_contains_template_placeholder(payload.get("credential_value")):
            raise HTTPException(
                status_code=400,
                detail={
                    "error": "CREDENTIAL_PLACEHOLDER_VALUE",
                    "message": "Credential material still contains template placeholders. Replace every <...> value with the real cookie/session/profile before importing.",
                    "missing_input_fields": [{"name": "credential_value", "label": "Real cookie/session/profile material"}],
                },
            )
        if provider_id == "gemini_cli_oauth" and credential_material_to_text(payload.get("credential_value")):
            normalize_gemini_cli_oauth_auth_json(
                payload.get("credential_value"),
                account_id=str(payload.get("account_id") or "acct_gemini_cli_oauth_01"),
                label=str(payload.get("label") or "Gemini CLI OAuth account"),
                resource_profile=payload.get("resource_profile") or {},
            )
        if not payload.get("supported_operations") or not payload.get("supported_provider_models"):
            raise HTTPException(status_code=400, detail={"error": "ACCOUNT_CAPABILITIES_REQUIRED"})
        return {
            "ok": True,
            "status": "ready_to_import",
            "auth_method": auth_method,
            "resource_type": resource_type,
            "missing_input_fields": [],
            "message": "Account material passes provider-specific input validation.",
        }
    except HTTPException as exc:
        detail = exc.detail if isinstance(exc.detail, dict) else {"error": str(exc.detail)}
        return {
            "ok": False,
            "status": "needs_input",
            "error": detail.get("error") or "ACCOUNT_MATERIAL_INVALID",
            "missing_input_fields": detail.get("missing_input_fields") or [],
            "detail": detail,
            "message": detail.get("message") or "Account material is incomplete or does not match this provider.",
        }
    except ValueError as exc:
        return {
            "ok": False,
            "status": "needs_input",
            "error": str(exc),
            "missing_input_fields": [],
            "detail": {"error": str(exc)},
            "message": "Account material is incomplete or does not match this provider.",
        }


def build_proxy_kernel_account_materials(
    db: Session,
    provider_id: str,
    req: ProxyKernelAccountMaterialsRequest | None = None,
) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    materials = build_proxy_kernel_materials_request(db, provider_id)
    guide = connector_registry_service.provider_guide(db, provider_id)
    payload = proxy_kernel_account_material_payload_from_request(provider_id, template, materials, guide, req)
    account_materials = materials.get("account_materials") or {}
    value_template = proxy_kernel_account_material_value_template(account_materials)
    resource_profile_template = account_materials.get("resource_profile_template") or platform_resource_profile_template(provider_id)
    preflight = proxy_kernel_account_material_preflight(db, provider_id, payload)
    applied: dict[str, Any] = {}
    runtime_credential_sync = {"status": "unsupported", "ok": False}
    if provider_id == "gemini_cli_oauth":
        try:
            runtime_credential_sync = build_proxy_kernel_runtime_credential_sync(
                db,
                provider_id,
                ProxyKernelRuntimeCredentialSyncRequest(
                    dry_run=True,
                    account_id=payload.get("account_id"),
                    credential_value=payload.get("credential_value"),
                    credential_ref=payload.get("credential_ref"),
                    credential_secret_id=payload.get("credential_secret_id"),
                    resource_profile=payload.get("resource_profile") or {},
                ),
            )
        except HTTPException as exc:
            detail = exc.detail if isinstance(exc.detail, dict) else {"error": str(exc.detail)}
            runtime_credential_sync = {
                "object": "media2api.proxy_kernel.runtime_credential_sync",
                "provider_id": provider_id,
                "dry_run": True,
                "status": "needs_input",
                "ok": False,
                "detail": detail,
                "message": detail.get("message") or "Runtime credential sync needs valid Gemini CLI OAuth material.",
            }
        except ValueError as exc:
            runtime_credential_sync = {
                "object": "media2api.proxy_kernel.runtime_credential_sync",
                "provider_id": provider_id,
                "dry_run": True,
                "status": "needs_input",
                "ok": False,
                "error": str(exc),
                "message": "Runtime credential sync needs valid Gemini CLI OAuth material.",
            }
    dry_run = True if req is None else bool(req.dry_run)
    if req is not None and not dry_run and preflight.get("ok"):
        account_req = AccountOnboardingRequest(**{**payload, "provider_id": provider_id})
        applied = apply_account_onboarding(db, account_req)
        try:
            runtime_credential_sync = build_proxy_kernel_runtime_credential_sync(
                db,
                provider_id,
                ProxyKernelRuntimeCredentialSyncRequest(
                    dry_run=False,
                    account_id=((applied.get("account") or {}).get("id") if isinstance(applied.get("account"), dict) else None) or payload.get("account_id"),
                    credential_value=payload.get("credential_value"),
                    credential_ref=payload.get("credential_ref"),
                    credential_secret_id=payload.get("credential_secret_id"),
                    resource_profile=payload.get("resource_profile") or {},
                ),
            )
        except HTTPException as exc:
            runtime_credential_sync = {
                "object": "media2api.proxy_kernel.runtime_credential_sync",
                "provider_id": provider_id,
                "dry_run": False,
                "status": "failed",
                "ok": False,
                "detail": exc.detail,
            }
        except ValueError as exc:
            runtime_credential_sync = {
                "object": "media2api.proxy_kernel.runtime_credential_sync",
                "provider_id": provider_id,
                "dry_run": False,
                "status": "failed",
                "ok": False,
                "error": str(exc),
            }
        preflight = {**preflight, "status": "imported", "message": "Account material was imported and stored as a managed credential reference."}
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    post_payload = {
        "dry_run": True,
        "credential_value": value_template or "<paste credential material>",
        "resource_profile": resource_profile_template,
        "auth_method": payload.get("auth_method"),
        "resource_type": payload.get("resource_type"),
    }
    submission_template = {
        **post_payload,
        "account_id": payload.get("account_id") or f"acct_{provider_id}_01",
        "label": payload.get("label") or f"{template.name} primary account",
        "supported_operations": payload.get("supported_operations") or list(template.operations),
        "supported_provider_models": payload.get("supported_provider_models") or sorted({str(item.provider_model) for item in template.mappings if getattr(item, "provider_model", "")}),
        "concurrency_limit": payload.get("concurrency_limit") or 1,
        "upsert": True,
        "auto_create_mappings": True,
        "sync_capabilities": False,
        "run_health_check": False,
    }
    return {
        "object": "media2api.proxy_kernel.account_materials",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": materials.get("selection_id"),
        "dry_run": dry_run,
        "status": preflight.get("status") or ("ready_to_import" if preflight.get("ok") else "needs_input"),
        "ok": bool(preflight.get("ok")),
        "preflight": preflight,
        "applied": applied,
        "runtime_credential_sync": runtime_credential_sync,
        "account_materials": account_materials,
        "payload_template": proxy_kernel_operator_account_payload_template(provider_id, template, materials, guide),
        "payload_preview": proxy_kernel_redact_account_material_payload(payload),
        "credential_value_json_template": value_template,
        "credential_value_env_template": "\n".join(f"{key}=<{key}>" for key in value_template if not key.startswith("choose_one_of_")),
        "resource_profile_json_template": resource_profile_template,
        "submission_json_template": submission_template,
        "field_instructions": proxy_kernel_account_field_instructions(account_materials),
        "fields_by_destination": account_materials.get("fields_by_destination") or {},
        "required_fields": account_materials.get("required_fields") or [],
        "any_of_groups": account_materials.get("any_of_groups") or [],
        "guide": {
            "title": guide.get("title"),
            "resource_type": guide.get("resource_type"),
            "accepted_resource_types": guide.get("accepted_resource_types") or [],
            "recommended_auth_methods": guide.get("recommended_auth_methods") or [],
            "user_actions": guide.get("user_actions") or [],
            "opensource_basis": guide.get("opensource_basis") or [],
        },
        "commands": {
            "inspect": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/account-materials",
            "preflight": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/account-materials -d '{json.dumps(post_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "import": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/account-materials -d '{json.dumps({**post_payload, 'dry_run': False}, ensure_ascii=False, separators=(',', ':'))}'",
            "sync_runtime_credentials": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/runtime-credentials/sync -d '{{\"dry_run\":true,\"account_id\":\"{payload.get('account_id') or 'acct_' + provider_id + '_01'}\"}}'",
            "activation_run": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/activation-run -d '{{\"dry_run\":true,\"steps\":[\"submit_account_material\"]}}'",
        },
        "policy": {
            "official_sdk_api": "forbidden",
            "credential_value_echo": "redacted",
            "dry_run_mutates_state": False,
            "dry_run_default": True,
            "real_import_requires_dry_run_false": True,
        },
    }


def proxy_kernel_account_material_matrix_field(field: dict[str, Any]) -> dict[str, Any]:
    return {
        "name": field.get("name"),
        "label": field.get("label") or field.get("name"),
        "required": bool(field.get("required")),
        "where_to_put": field.get("where_to_put") or "",
        "any_of_group": field.get("any_of_group") or "",
        "aliases": field.get("aliases") or [],
        "when": field.get("when") or "",
        "evidence": field.get("evidence") or "",
        "require_named_field": bool(field.get("require_named_field")),
    }


def proxy_kernel_account_material_matrix_section(
    section_id: str,
    title: str,
    message: str,
    fields: list[dict[str, Any]],
    template: Any,
) -> dict[str, Any]:
    return {
        "id": section_id,
        "title": title,
        "message": message,
        "field_count": len(fields),
        "required_field_count": sum(1 for field in fields if field.get("required")),
        "fields": [proxy_kernel_account_material_matrix_field(field) for field in fields],
        "template": template,
    }


def proxy_kernel_account_material_matrix_next_action(
    provider_id: str,
    available_account_count: int,
    active_account_count: int,
    runtime_sync: dict[str, Any],
) -> dict[str, Any]:
    if available_account_count <= 0:
        return {
            "id": "import_account_material",
            "label": "Import real account material",
            "button_action": "open-account",
            "ui_target": "kernel-account-material-panel",
            "primary_api": f"/v1/admin/proxy-kernels/{provider_id}/account-materials",
        }
    if active_account_count > available_account_count:
        return {
            "id": "fix_credential_ref",
            "label": "Fix credential ref for imported accounts",
            "button_action": "open-account",
            "ui_target": "kernel-account-material-panel",
            "primary_api": f"/v1/admin/proxy-kernels/{provider_id}/account-materials",
        }
    if runtime_sync.get("status") not in {"unsupported", "reference_only"} and not runtime_sync.get("ok"):
        return {
            "id": "sync_runtime_credentials",
            "label": "Sync runtime credential files",
            "button_action": "open-account",
            "ui_target": "kernel-account-runtime-sync",
            "primary_api": f"/v1/admin/proxy-kernels/{provider_id}/runtime-credentials/sync",
        }
    return {
        "id": "account_ready",
        "label": "Account ready; continue runtime and live acceptance",
        "button_action": "open-runtime",
        "ui_target": "kernel-start-runtime",
        "primary_api": f"/v1/admin/proxy-kernels/{provider_id}/runtime-delivery-plan",
    }


def proxy_kernel_account_material_matrix_row(db: Session, provider_id: str) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    materials = build_proxy_kernel_materials_request(db, provider_id)
    package = build_proxy_kernel_account_materials(db, provider_id)
    account_materials = package.get("account_materials") or {}
    fields_by_destination = package.get("fields_by_destination") or {}
    credential_fields = fields_by_destination.get("credential_value") or []
    profile_fields = fields_by_destination.get("resource_profile") or []
    runtime_fields = fields_by_destination.get("runtime_or_provider_base_url") or []
    other_fields = fields_by_destination.get("other") or []
    routing = proxy_kernel_routing_plan(db, provider_id)
    accounts = db.query(models.AccountResource).filter(models.AccountResource.provider_id == provider_id).order_by(models.AccountResource.id).all()
    active_accounts = [account for account in accounts if account.status == "active"]
    available_accounts = [account for account in active_accounts if account_credential_available(db, account)]
    runtime_sync = package.get("runtime_credential_sync") or {}
    required_field_names = [
        str(field.get("name") or "")
        for field in list(credential_fields) + list(profile_fields)
        if field.get("required") and not field.get("any_of_group") and field.get("name")
    ]
    required_group_names = [
        str(group.get("group") or "")
        for group in package.get("any_of_groups") or []
        if group.get("required") and group.get("group")
    ]
    next_action = proxy_kernel_account_material_matrix_next_action(
        provider_id,
        len(available_accounts),
        len(active_accounts),
        runtime_sync,
    )
    return {
        "provider_id": provider_id,
        "selection_id": materials.get("selection_id"),
        "name": template.name,
        "status": "account_ready" if available_accounts else "needs_account_material",
        "account_ready": bool(available_accounts),
        "existing_account_count": len(accounts),
        "active_account_count": len(active_accounts),
        "available_account_count": len(available_accounts),
        "route_config_ready": bool(routing.get("route_config_ready")),
        "runtime_registered": bool(routing.get("runtime_registered")),
        "next_action": next_action,
        "auth": {
            "auth_method": (package.get("payload_template") or {}).get("auth_method"),
            "resource_type": (package.get("payload_template") or {}).get("resource_type"),
            "credential_kind": (package.get("payload_template") or {}).get("credential_kind"),
            "credential_ref_example": (account_materials.get("credential_ref_example") or ""),
            "accepted_resource_types": account_materials.get("accepted_resource_types") or [],
        },
        "what_to_prepare": [
            proxy_kernel_account_material_matrix_section(
                "credential_value",
                "Credential Value",
                "Sensitive upstream material goes here: cookie, session, OAuth JSON, profile export, or user token. It is stored as a managed secret and never echoed back.",
                credential_fields,
                package.get("credential_value_json_template") or {},
            ),
            proxy_kernel_account_material_matrix_section(
                "resource_profile",
                "Resource Profile",
                "Non-secret routing/profile fields go here: guild_id, channel_id, project_id, region, plan, account email, or domain scope.",
                profile_fields,
                package.get("resource_profile_json_template") or {},
            ),
            proxy_kernel_account_material_matrix_section(
                "runtime_or_provider_base_url",
                "Runtime Or Provider Base URL",
                "Only use this section when the selected reverse-proxy kernel requires a loopback runtime URL or a local provider endpoint field.",
                runtime_fields,
                {},
            ),
            proxy_kernel_account_material_matrix_section(
                "other",
                "Other",
                "Additional provider-specific fields that do not belong to the secret or resource profile sections.",
                other_fields,
                {},
            ),
        ],
        "required_field_names": required_field_names,
        "required_group_names": required_group_names,
        "any_of_groups": package.get("any_of_groups") or [],
        "field_instructions": package.get("field_instructions") or [],
        "credential_value_json_template": package.get("credential_value_json_template") or {},
        "credential_value_env_template": package.get("credential_value_env_template") or "",
        "resource_profile_json_template": package.get("resource_profile_json_template") or {},
        "submission_json_template": package.get("submission_json_template") or {},
        "payload_preview": package.get("payload_preview") or {},
        "preflight": package.get("preflight") or {},
        "runtime_credential_sync": runtime_sync,
        "accounts": [
            {
                **serialize_account(account),
                "credential_available": account_credential_available(db, account),
            }
            for account in accounts
        ],
        "commands": {
            "inspect_account_materials": (package.get("commands") or {}).get("inspect"),
            "preflight_account_materials": (package.get("commands") or {}).get("preflight"),
            "import_account_materials": (package.get("commands") or {}).get("import"),
            "sync_runtime_credentials": (package.get("commands") or {}).get("sync_runtime_credentials"),
        },
    }


def proxy_kernel_account_material_matrix_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    return {
        "total": len(rows),
        "account_ready": sum(1 for row in rows if row.get("account_ready")),
        "needs_account_material": sum(1 for row in rows if not row.get("account_ready")),
        "active_accounts": sum(int(row.get("active_account_count") or 0) for row in rows),
        "available_accounts": sum(int(row.get("available_account_count") or 0) for row in rows),
        "credential_field_count": sum((row.get("what_to_prepare") or [{}])[0].get("field_count", 0) for row in rows),
        "resource_profile_field_count": sum((row.get("what_to_prepare") or [{}, {}])[1].get("field_count", 0) for row in rows),
        "runtime_sync_supported": sum(1 for row in rows if (row.get("runtime_credential_sync") or {}).get("status") != "unsupported"),
    }


def build_proxy_kernel_account_materials_matrix(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [proxy_kernel_account_material_matrix_row(db, provider_id) for provider_id in selected]
    base = settings.public_base_url
    return {
        "object": "media2api.proxy_kernel.account_materials_matrix",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_ids": selected,
        "summary": proxy_kernel_account_material_matrix_summary(rows),
        "data": rows,
        "commands": {
            "inspect": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {base}/v1/admin/proxy-kernels/account-materials-matrix",
            "inspect_openai_web": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {base}/v1/admin/proxy-kernels/account-materials-matrix?provider_ids=openai_web_session",
            "inspect_gemini_cli": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {base}/v1/admin/proxy-kernels/account-materials-matrix?provider_ids=gemini_cli_oauth",
        },
        "policy": {
            "read_only": True,
            "upstream_calls": False,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "credential_value_echo": "redacted",
            "no_fake_account_created": True,
        },
    }


def proxy_kernel_account_connection_required_items(row: dict[str, Any]) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    for section in row.get("what_to_prepare") or []:
        section_id = str(section.get("id") or "")
        if section_id not in {"credential_value", "resource_profile", "runtime_or_provider_base_url"}:
            continue
        for field in section.get("fields") or []:
            if not field.get("required") and not field.get("any_of_group"):
                continue
            items.append(
                {
                    "section": section_id,
                    "name": field.get("name"),
                    "label": field.get("label") or field.get("name"),
                    "required": bool(field.get("required")),
                    "choose_one_of": field.get("any_of_group") or "",
                    "where_to_paste": section_id,
                }
            )
    for group in row.get("any_of_groups") or []:
        if not group.get("required"):
            continue
        options = [
            str(field.get("name") or "")
            for field in group.get("fields") or []
            if str(field.get("name") or "")
        ]
        if options:
            items.append(
                {
                    "section": "credential_value",
                    "name": group.get("group"),
                    "label": "Choose one of: " + ", ".join(options),
                    "required": True,
                    "choose": "one_of",
                    "options": options,
                    "where_to_paste": "credential_value",
                }
            )
    return items


def proxy_kernel_account_connection_submission_item(row: dict[str, Any]) -> dict[str, Any]:
    template = dict(row.get("submission_json_template") or {})
    template["provider_id"] = row.get("provider_id")
    template["dry_run"] = True
    return template


def proxy_kernel_account_connection_package_row(row: dict[str, Any]) -> dict[str, Any]:
    provider_id = str(row.get("provider_id") or "")
    credential_template = row.get("credential_value_json_template") or {}
    profile_template = row.get("resource_profile_json_template") or {}
    required_items = proxy_kernel_account_connection_required_items(row)
    return {
        "provider_id": provider_id,
        "selection_id": row.get("selection_id"),
        "name": row.get("name"),
        "status": row.get("status"),
        "account_ready": bool(row.get("account_ready")),
        "next_action": row.get("next_action") or {},
        "plain_request": (
            f"请提供 {row.get('name') or provider_id} 的真实账号材料。"
            "敏感 cookie/session/OAuth/profile/token 放入 credential_value；"
            "guild/channel/project/region/plan 等非敏感资料放入 resource_profile。"
        ),
        "required_items": required_items,
        "credential_value_json_template": credential_template,
        "resource_profile_json_template": profile_template,
        "submission_item_template": proxy_kernel_account_connection_submission_item(row),
        "copyable_request": {
            "title": f"{provider_id} account material request",
            "message": (
                "Do not send official API keys. Send only the reverse-proxy/session material required by this provider. "
                "Replace every <...> placeholder with real material before import."
            ),
            "credential_value": credential_template,
            "resource_profile": profile_template,
        },
    }


def build_proxy_kernel_account_connection_package(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    matrix = build_proxy_kernel_account_materials_matrix(db, provider_ids)
    rows = [proxy_kernel_account_connection_package_row(row) for row in matrix.get("data") or []]
    bulk_items = [row.get("submission_item_template") or {} for row in rows]
    base = settings.public_base_url
    bulk_payload = {"dry_run": True, "continue_on_error": True, "items": bulk_items}
    return {
        "object": "media2api.proxy_kernel.account_connection_package",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_ids": matrix.get("provider_ids") or [],
        "summary": {
            "total": len(rows),
            "account_ready": sum(1 for row in rows if row.get("account_ready")),
            "needs_account_material": sum(1 for row in rows if not row.get("account_ready")),
            "required_item_count": sum(len(row.get("required_items") or []) for row in rows),
        },
        "data": rows,
        "bulk_submission_json_template": bulk_payload,
        "commands": {
            "inspect": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {base}/v1/admin/proxy-kernels/account-connection-package",
            "inspect_openai_gemini": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {base}/v1/admin/proxy-kernels/account-connection-package?provider_ids=openai_web_session,gemini_cli_oauth",
            "bulk_preflight": f"curl -X POST -H \"Authorization: Bearer $MEDIA2API_API_KEY\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/account-materials-bulk -d '{json.dumps(bulk_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "bulk_import": f"curl -X POST -H \"Authorization: Bearer $MEDIA2API_API_KEY\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/account-materials-bulk -d '{json.dumps({**bulk_payload, 'dry_run': False}, ensure_ascii=False, separators=(',', ':'))}'",
        },
        "policy": {
            "read_only": True,
            "upstream_calls": False,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "credential_value_echo": "redacted",
            "no_fake_account_created": True,
        },
    }


def proxy_kernel_account_materials_request_from_bulk_item(
    item: ProxyKernelAccountMaterialsBulkItem,
    *,
    dry_run: bool,
) -> ProxyKernelAccountMaterialsRequest:
    payload = item.model_dump()
    payload.pop("provider_id", None)
    return ProxyKernelAccountMaterialsRequest(dry_run=dry_run, **payload)


def build_proxy_kernel_account_materials_bulk(
    db: Session,
    req: ProxyKernelAccountMaterialsBulkRequest,
) -> dict[str, Any]:
    if not req.items:
        raise ValueError("ACCOUNT_MATERIAL_ITEMS_REQUIRED")
    rows: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []
    for index, item in enumerate(req.items):
        provider_id = item.provider_id.strip()
        try:
            proxy_kernel_routing_provider_ids(db, [provider_id])
            package = build_proxy_kernel_account_materials(
                db,
                provider_id,
                proxy_kernel_account_materials_request_from_bulk_item(item, dry_run=bool(req.dry_run)),
            )
            rows.append({"index": index, "provider_id": provider_id, "status": package.get("status"), "ok": bool(package.get("ok")), "package": package})
        except Exception as exc:
            error = {"index": index, "provider_id": provider_id, "error": type(exc).__name__, "message": str(exc)}
            if isinstance(exc, HTTPException):
                error["detail"] = exc.detail
            errors.append(error)
            if not req.continue_on_error:
                break
    ok_count = sum(1 for row in rows if row.get("ok"))
    imported_count = sum(1 for row in rows if (row.get("package") or {}).get("status") == "imported")
    needs_input_count = sum(1 for row in rows if not row.get("ok")) + len(errors)
    status = "imported" if imported_count and not req.dry_run and not needs_input_count else ("ready_to_import" if ok_count == len(req.items) and not errors else "needs_input")
    return {
        "object": "media2api.proxy_kernel.account_materials_bulk",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "dry_run": bool(req.dry_run),
        "status": status,
        "ok": not errors and needs_input_count == 0,
        "summary": {
            "total": len(req.items),
            "processed": len(rows),
            "ready": ok_count,
            "imported": imported_count,
            "needs_input": needs_input_count,
            "failed": len(errors),
        },
        "data": rows,
        "errors": errors,
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "dry_run_default": True,
            "credential_value_echo": "redacted",
            "real_import_requires_dry_run_false": True,
            "no_fake_account_created": True,
        },
    }


def proxy_kernel_production_unblock_priority(row: dict[str, Any]) -> int:
    value = row.get("production_unblock_priority")
    if value is None:
        return 999
    try:
        return int(value)
    except (TypeError, ValueError):
        return 999


def proxy_kernel_production_unblock_greedy(rows: list[dict[str, Any]], required_operations: set[str]) -> list[str]:
    remaining = set(required_operations)
    selected: list[str] = []
    candidates = sorted(
        rows,
        key=lambda row: (
            -len(set(row.get("covered_operations") or []) & remaining),
            proxy_kernel_production_unblock_priority(row),
            row.get("provider_id") or "",
        ),
    )
    while remaining:
        best = next((row for row in candidates if row.get("provider_id") not in selected and set(row.get("covered_operations") or []) & remaining), None)
        if not best:
            break
        selected.append(str(best.get("provider_id") or ""))
        remaining -= set(best.get("covered_operations") or [])
    return selected


def build_proxy_kernel_production_unblock_package(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    required_operations = set(PRODUCTION_EXTERNAL_REQUIRED_OPERATIONS)
    preference = {
        "gemini_cli_oauth": 0,
        "gemini_web_session": 10,
        "doubao_web_session": 20,
        "qwen_ai_web_session": 30,
        "qianwen_web_session": 31,
        "antigravity": 40,
        "openai_codex": 50,
        "openai_web_session": 51,
    }
    matrix = build_proxy_kernel_account_materials_matrix(db, selected)
    readiness = build_readiness_snapshot(db)
    matrix_by_provider = {row.get("provider_id"): row for row in matrix.get("data") or []}
    candidates: list[dict[str, Any]] = []
    for provider_id in selected:
        template = PROVIDER_TEMPLATES.get(provider_id)
        if not template:
            continue
        operations = set(template.operations or [])
        mapping_operations = {
            operation
            for mapping in template.mappings
            for operation in getattr(mapping, "operations", [])
        }
        covered = sorted((operations | mapping_operations) & required_operations)
        missing = sorted(required_operations - set(covered))
        matrix_row = matrix_by_provider.get(provider_id) or {}
        kernel = proxy_kernel_service.kernel_summary(db, provider_id)
        process = kernel.get("process") if isinstance(kernel.get("process"), dict) else {}
        runtime_registered = bool(kernel.get("runtime_registered"))
        runtime_loopback_only = bool(kernel.get("runtime_loopback_only"))
        managed_process_running = bool(process.get("running"))
        if runtime_registered and managed_process_running:
            runtime_status = "running"
        elif runtime_registered and runtime_loopback_only:
            runtime_status = "registered"
        elif runtime_registered:
            runtime_status = "non_loopback_registered"
        else:
            runtime_status = "missing_runtime"
        account_connection = proxy_kernel_account_connection_package_row(matrix_row)
        complete_coverage = not missing
        candidates.append(
            {
                "provider_id": provider_id,
                "selection_id": matrix_row.get("selection_id"),
                "name": matrix_row.get("name") or template.name,
                "coverage_score": len(covered),
                "complete_coverage": complete_coverage,
                "production_unblock_priority": preference.get(provider_id, 999),
                "covered_operations": covered,
                "missing_operations": missing,
                "account_ready": bool(matrix_row.get("account_ready")),
                "active_account_count": int(matrix_row.get("active_account_count") or 0),
                "available_account_count": int(matrix_row.get("available_account_count") or 0),
                "route_config_ready": bool(matrix_row.get("route_config_ready")),
                "runtime": {
                    "status": runtime_status,
                    "runtime_registered": bool(kernel.get("runtime_registered")),
                    "runtime_loopback_only": bool(kernel.get("runtime_loopback_only")),
                    "runtime_base_url": kernel.get("runtime_base_url") or "",
                    "managed_process_running": managed_process_running,
                    "installed_verified": bool(kernel.get("installed_verified")),
                },
                "account_connection": account_connection,
                "go_live_next_action": {"label": "查看上线包", "id": "go_live_package"},
                "commands": {
                    "account_connection_package": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {settings.public_base_url}/v1/admin/proxy-kernels/account-connection-package?provider_ids={provider_id}",
                    "runtime_delivery_plan": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {settings.public_base_url}/v1/admin/proxy-kernels/{provider_id}/runtime-delivery-plan",
                    "go_live_package": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {settings.public_base_url}/v1/admin/proxy-kernels/{provider_id}/go-live-package",
                    "live_acceptance": f"curl -X POST -H \"Authorization: Bearer $MEDIA2API_API_KEY\" -H \"Content-Type: application/json\" {settings.public_base_url}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{{\"dry_run\":true,\"run_runtime_health\":true,\"require_runtime_health\":true,\"run_samples\":true,\"max_samples\":1}}'",
                },
            }
        )
    candidates.sort(key=lambda row: (not row.get("complete_coverage"), -int(row.get("coverage_score") or 0), proxy_kernel_production_unblock_priority(row), row.get("provider_id") or ""))
    complete = [row for row in candidates if row.get("complete_coverage")]
    recommended_provider_ids = [str(complete[0]["provider_id"])] if complete else proxy_kernel_production_unblock_greedy(candidates, required_operations)
    recommended = [row for row in candidates if row.get("provider_id") in set(recommended_provider_ids)]
    recommended_items = [
        row.get("account_connection", {}).get("submission_item_template") or {}
        for row in recommended
        if row.get("account_connection", {}).get("submission_item_template")
    ]
    return {
        "object": "media2api.proxy_kernel.production_unblock_package",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "status": "blocked_by_real_account_material" if not readiness.get("production_ready") else "production_ready",
        "required_operations": sorted(required_operations),
        "recommended_provider_ids": recommended_provider_ids,
        "summary": {
            "candidate_count": len(candidates),
            "complete_coverage_candidates": len(complete),
            "recommended_count": len(recommended_provider_ids),
            "production_ready": bool(readiness.get("production_ready")),
            "core_ready": bool(readiness.get("core_ready")),
        },
        "recommended": recommended,
        "candidates": candidates,
        "account_connection_package": {
            "object": "media2api.proxy_kernel.account_connection_package",
            "summary": {
                "total": len(recommended_items),
                "needs_account_material": sum(1 for row in recommended if not row.get("account_ready")),
            },
            "bulk_submission_json_template": {
                "dry_run": True,
                "continue_on_error": True,
                "items": recommended_items,
            },
        },
        "final_acceptance": {
            "blocked_by": "authorized_external_connector_accounts" if not readiness.get("production_ready") else "",
            "core_ready": readiness.get("core_ready"),
            "production_ready": readiness.get("production_ready"),
            "action_items": [
                item
                for item in readiness.get("action_items", [])
                if item.get("scope") == "production"
            ],
        },
        "next_steps": [
            "Pick one recommended provider with complete coverage, or use the greedy set if no single provider covers every required operation.",
            "Send its account_connection copyable_request to the real account holder.",
            "Replace placeholders in bulk_submission_json_template, run /account-materials-bulk with dry_run=true, then rerun with dry_run=false.",
            "Install/register the loopback runtime, run runtime health, live acceptance, and downstream call package.",
        ],
        "policy": {
            "read_only": True,
            "upstream_calls": False,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "no_fake_account_created": True,
            "real_account_material_required_for_production_ready": True,
        },
    }


def proxy_kernel_credential_intake_sheet_item(row: dict[str, Any]) -> dict[str, Any]:
    credential_template = row.get("credential_value_json_template") or {}
    profile_template = row.get("resource_profile_json_template") or {}
    submission_template = dict(row.get("submission_item_template") or {})
    submission_template["dry_run"] = True
    return {
        "provider_id": row.get("provider_id"),
        "selection_id": row.get("selection_id"),
        "name": row.get("name"),
        "status": row.get("status"),
        "account_ready": bool(row.get("account_ready")),
        "required_items": row.get("required_items") or [],
        "copyable_request": row.get("copyable_request") or {},
        "credential_value_json_template": credential_template,
        "resource_profile_json_template": profile_template,
        "submission_item_template": submission_template,
        "operator_notes": [
            "Put sensitive cookie/session/OAuth/profile/token material only under credential_value.",
            "Put non-secret routing fields such as guild_id, channel_id, project_id, region, or plan under resource_profile.",
            "Leave dry_run=true for preflight. Change only the top-level bulk payload to dry_run=false after preflight passes.",
            "Do not provide official SDK/API keys; this platform accepts only reverse-proxy/session/agent material.",
        ],
    }


def build_proxy_kernel_credential_intake_sheet(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    unblock = build_proxy_kernel_production_unblock_package(db, provider_ids)
    selected = [item.strip() for item in provider_ids or [] if item.strip()]
    if not selected:
        selected = [str(item) for item in unblock.get("recommended_provider_ids") or [] if str(item)]
    connection = build_proxy_kernel_account_connection_package(db, selected)
    rows = [proxy_kernel_credential_intake_sheet_item(row) for row in connection.get("data") or []]
    bulk_payload = {
        "dry_run": True,
        "continue_on_error": True,
        "items": [row.get("submission_item_template") or {} for row in rows],
    }
    base = settings.public_base_url
    return {
        "object": "media2api.proxy_kernel.credential_intake_sheet",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "status": "production_ready" if unblock.get("status") == "production_ready" else "waiting_for_real_account_material",
        "provider_ids": selected,
        "required_operations": unblock.get("required_operations") or [],
        "recommended_provider_ids": unblock.get("recommended_provider_ids") or [],
        "summary": {
            "total": len(rows),
            "account_ready": sum(1 for row in rows if row.get("account_ready")),
            "needs_real_account_material": sum(1 for row in rows if not row.get("account_ready")),
            "production_ready": bool((unblock.get("summary") or {}).get("production_ready")),
            "core_ready": bool((unblock.get("summary") or {}).get("core_ready")),
        },
        "forbidden_materials": [
            "official OpenAI API key",
            "official Gemini API key",
            "official SDK credential",
            "third-party hosted proxy URL that is not your controlled loopback runtime",
        ],
        "accepted_materials": [
            "web cookie/session header or exported session JSON",
            "CLI OAuth credential JSON/profile directory",
            "agent-provider credential/profile material from the selected reverse-proxy project",
            "Discord/user-session token plus non-secret guild/channel profile when the selected kernel requires it",
            "loopback runtime base_url only when the selected release/source runtime requires one",
        ],
        "data": rows,
        "bulk_submission_json_template": bulk_payload,
        "commands": {
            "inspect": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {base}/v1/admin/proxy-kernels/credential-intake-sheet",
            "inspect_openai_gemini": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {base}/v1/admin/proxy-kernels/credential-intake-sheet?provider_ids=openai_web_session,gemini_cli_oauth",
            "bulk_preflight": f"curl -X POST -H \"Authorization: Bearer $MEDIA2API_API_KEY\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/account-materials-bulk -d '{json.dumps(bulk_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "bulk_import": f"curl -X POST -H \"Authorization: Bearer $MEDIA2API_API_KEY\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/account-materials-bulk -d '{json.dumps({**bulk_payload, 'dry_run': False}, ensure_ascii=False, separators=(',', ':'))}'",
            "production_unblock_package": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {base}/v1/admin/proxy-kernels/production-unblock-package",
            "account_acceptance_suite": f"curl -X POST -H \"Authorization: Bearer $MEDIA2API_API_KEY\" -H \"Content-Type: application/json\" {base}/v1/admin/account-acceptance-suite -d '{{\"dry_run\":false,\"external_only\":true,\"active_only\":true,\"operations\":{json.dumps(unblock.get('required_operations') or [], ensure_ascii=False)},\"run_samples\":true,\"max_samples\":1,\"require_production_ready\":true}}'",
        },
        "operator_steps": [
            {"step": 1, "name": "collect_material", "detail": "Copy data[].copyable_request to the real account owner and collect only the requested reverse-proxy/session material."},
            {"step": 2, "name": "replace_placeholders", "detail": "Replace every <...> placeholder in bulk_submission_json_template.items with real material."},
            {"step": 3, "name": "dry_run_preflight", "detail": "POST the filled payload to /v1/admin/proxy-kernels/account-materials-bulk with dry_run=true."},
            {"step": 4, "name": "import", "detail": "If preflight is ready_to_import, resend the same payload with dry_run=false."},
            {"step": 5, "name": "runtime_and_acceptance", "detail": "Start or sync the selected loopback runtime if required, then run account acceptance and final acceptance matrix."},
        ],
        "policy": {
            "read_only": True,
            "upstream_calls": False,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "credential_value_echo": "redacted",
            "no_fake_account_created": True,
            "real_account_material_required_for_production_ready": True,
        },
    }


def proxy_kernel_operator_material_questions(materials: dict[str, Any]) -> list[dict[str, Any]]:
    questions: list[dict[str, Any]] = []
    account_materials = materials.get("account_materials") or {}
    runtime_materials = materials.get("runtime_materials") or {}
    if account_materials.get("status") != "ready":
        for field in account_materials.get("required_fields") or []:
            questions.append(
                {
                    "section": "account",
                    "name": field.get("name"),
                    "label": field.get("label") or field.get("name"),
                    "required": True,
                    "where_to_put": field.get("where_to_put") or "credential_value/resource_profile",
                    "example": field.get("example") or field.get("placeholder") or "",
                }
            )
        for group in account_materials.get("any_of_groups") or []:
            questions.append(
                {
                    "section": "account",
                    "name": group.get("group"),
                    "label": " / ".join(str(field.get("label") or field.get("name")) for field in group.get("fields", [])),
                    "required": bool(group.get("required")),
                    "choose": group.get("choose") or "one_of",
                    "where_to_put": "credential_value or credential_ref",
                    "fields": group.get("fields", []),
                }
            )
    if runtime_materials.get("status") != "ready":
        for field in runtime_materials.get("release_required_fields") or []:
            questions.append(
                {
                    "section": "runtime_release",
                    "name": field.get("name"),
                    "label": field.get("name"),
                    "required": bool(field.get("required")),
                    "where_to_put": "install_release",
                }
            )
        for field in runtime_materials.get("start_runtime_required_fields") or []:
            questions.append(
                {
                    "section": "runtime_start",
                    "name": field.get("name"),
                    "label": field.get("name"),
                    "required": bool(field.get("required")),
                    "where_to_put": "start_runtime",
                    "default": field.get("default"),
                    "example": field.get("example") or "",
                }
            )
    return questions


def build_proxy_kernel_operator_handoff(db: Session, provider_id: str) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    materials = build_proxy_kernel_materials_request(db, provider_id)
    delivery = build_proxy_kernel_runtime_delivery_plan(db, provider_id)
    readiness = build_proxy_kernel_production_readiness(db, provider_id)
    go_live = build_proxy_kernel_go_live_checklist(db, provider_id)
    guide = connector_registry_service.provider_guide(db, provider_id)
    account_payload = proxy_kernel_operator_account_payload_template(provider_id, template, materials, guide)
    account_ref_payload = {**account_payload, "credential_value": "", "credential_ref": guide.get("credential_ref_example") or "secret://<credential-secret-id>"}
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    onboarding_command_payload = {key: value for key, value in account_payload.items() if value not in ("", None)}
    onboarding_ref_command_payload = {key: value for key, value in account_ref_payload.items() if value not in ("", None)}
    install_payload = (delivery.get("runtime") or {}).get("install_payload_template") or {}
    start_payload = (delivery.get("runtime") or {}).get("start_payload_template") or {}
    default_base_url = proxy_kernel_service.default_runtime_base_url(provider_id)
    source_plan = proxy_kernel_service.source_runtime_plan(provider_id, base_url=default_base_url)
    source_setup_catalog = proxy_kernel_service.source_runtime_setup_catalog(source_plan)
    source_setup_command = next((item for item in source_setup_catalog if not item.get("reference_only")), {}) if source_setup_catalog else {}
    source_setup_payload = {
        "dry_run": True,
        "command_id": source_setup_command.get("id") or "",
        "command": source_setup_command.get("command") or [],
        "cwd": source_setup_command.get("cwd") or "",
        "env": {},
        "timeout_seconds": 900,
        "notes": "source-repo dependency/build setup before launcher",
    }
    source_launcher_template = source_plan.get("launcher_payload_template") or {}
    source_launcher_payload = {
        "dry_run": True,
        "base_url": source_launcher_template.get("base_url") or default_base_url,
        "command": source_launcher_template.get("command") or [],
        "cwd": source_launcher_template.get("cwd") or "",
        "env": source_launcher_template.get("env") or {},
        "version": source_launcher_template.get("version") or "",
        "notes": source_launcher_template.get("notes") or "source-repo launcher",
    }
    live_dry_payload = {"dry_run": True, "operations": list(template.operations), "run_runtime_health": True, "require_runtime_health": True, "run_samples": True, "max_samples": 1}
    live_payload = {**live_dry_payload, "dry_run": False}
    run_payload = {
        "dry_run": True,
        "steps": ["apply_routing", "submit_account_material", "install_release", "source_runtime_setup", "source_runtime_launcher", "start_runtime", "runtime_health_check", "live_acceptance_dry_run"],
        "account_onboarding": onboarding_command_payload,
        "apply_routing": (materials.get("routing_materials") or {}).get("apply_payload") or {},
        "install_release": install_payload,
        "source_runtime_setup": source_setup_payload,
        "source_runtime_launcher": source_launcher_payload,
        "start_runtime": start_payload,
        "runtime_health_check": {"sync_provider_base_url": True, "require_running_process": False, "fail_on_health_check": False},
        "live_acceptance": live_dry_payload,
    }
    steps = [
        {
            "id": "apply_routing",
            "label": "补齐 provider/model 路由",
            "status": "done" if (materials.get("routing_materials") or {}).get("status") == "ready" else "action_required",
            "operator_required": False,
            "platform_can_run": True,
            "command": (materials.get("commands") or {}).get("apply_routing"),
            "payload_template": (materials.get("routing_materials") or {}).get("apply_payload"),
        },
        {
            "id": "submit_account_material",
            "label": "提交真实账号材料",
            "status": "done" if (materials.get("account_materials") or {}).get("status") == "ready" else "action_required",
            "operator_required": (materials.get("account_materials") or {}).get("status") != "ready",
            "platform_can_run": False,
            "command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/account-onboarding -d '{json.dumps(onboarding_command_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "credential_ref_command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/account-onboarding -d '{json.dumps(onboarding_ref_command_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "payload_template": account_payload,
            "credential_ref_payload_template": account_ref_payload,
        },
        {
            "id": "source_runtime_setup",
            "label": "Source-repo 依赖 / 构建准备",
            "status": "ready" if source_plan.get("source_available") and source_setup_payload.get("command_id") else "waiting",
            "operator_required": False,
            "platform_can_run": bool(source_plan.get("source_available") and source_setup_payload.get("command_id")),
            "source_available": bool(source_plan.get("source_available")),
            "payload_template": source_setup_payload,
            "command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/source-runtime-setup -d '{json.dumps(source_setup_payload, ensure_ascii=False, separators=(',', ':'))}'",
        },
        {
            "id": "source_runtime_launcher",
            "label": "生成 source-repo hash 启动器",
            "status": "ready" if source_plan.get("source_available") and source_launcher_payload.get("command") else "waiting",
            "operator_required": False,
            "platform_can_run": bool(source_plan.get("source_available") and source_launcher_payload.get("command")),
            "source_available": bool(source_plan.get("source_available")),
            "payload_template": source_launcher_payload,
            "command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/source-runtime-launcher -d '{json.dumps(source_launcher_payload, ensure_ascii=False, separators=(',', ':'))}'",
        },
        {
            "id": "install_or_register_runtime",
            "label": "安装或登记 loopback runtime",
            "status": "done" if (materials.get("runtime_materials") or {}).get("status") == "ready" else "action_required",
            "operator_required": (materials.get("runtime_materials") or {}).get("status") != "ready",
            "platform_can_run": True,
            "install_payload_template": install_payload,
            "source_runtime_plan": {
                "source_available": source_plan.get("source_available"),
                "detected_project_types": source_plan.get("detected_project_types") or [],
                "dependency_commands": source_plan.get("dependency_commands") or [],
                "build_commands": source_plan.get("build_commands") or [],
                "preferred_start_command": source_plan.get("preferred_start_command") or {},
            },
            "source_setup_payload_template": source_setup_payload,
            "source_launcher_payload_template": source_launcher_payload,
            "start_payload_template": start_payload,
            "install_command": (delivery.get("commands") or {}).get("install_release"),
            "source_runtime_plan_command": f"curl -H \"Authorization: Bearer {admin_key}\" \"{base}/v1/admin/proxy-kernels/{provider_id}/source-runtime-plan?base_url={default_base_url}\"",
            "source_runtime_setup_command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/source-runtime-setup -d '{json.dumps(source_setup_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "source_runtime_launcher_command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/source-runtime-launcher -d '{json.dumps(source_launcher_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "start_command": (delivery.get("commands") or {}).get("start_runtime"),
            "runtime_health_command": (delivery.get("commands") or {}).get("runtime_health_check"),
        },
        {
            "id": "dry_run_live_acceptance",
            "label": "Dry-run 真实样本验收",
            "status": "ready" if readiness.get("ready_for_live_acceptance") else "waiting",
            "operator_required": False,
            "platform_can_run": True,
            "payload_template": live_dry_payload,
            "command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{json.dumps(live_dry_payload, ensure_ascii=False, separators=(',', ':'))}'",
        },
        {
            "id": "live_acceptance",
            "label": "Live 运行 1 条真实样本",
            "status": "ready" if readiness.get("ready_for_live_acceptance") else "waiting",
            "operator_required": False,
            "platform_can_run": True,
            "payload_template": live_payload,
            "command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{json.dumps(live_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "quota_warning": "Live mode calls the real upstream runtime and may consume account quota.",
        },
        {
            "id": "run_handoff",
            "label": "执行交付包 dry-run",
            "status": "ready",
            "operator_required": False,
            "platform_can_run": True,
            "payload_template": run_payload,
            "command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/operator-handoff/run -d '{json.dumps(run_payload, ensure_ascii=False, separators=(',', ':'))}'",
        },
    ]
    return {
        "object": "media2api.proxy_kernel.operator_handoff",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": materials.get("selection_id"),
        "status": "ready_for_live_acceptance" if readiness.get("ready_for_live_acceptance") else "materials_required",
        "production_ready": bool(readiness.get("production_ready")),
        "next_step": readiness.get("next_step") or go_live.get("next_step") or delivery.get("next_step"),
        "operator_questions": proxy_kernel_operator_material_questions(materials),
        "steps": steps,
        "submission_templates": {
            "account_onboarding_inline_secret": account_payload,
            "account_onboarding_secret_ref": account_ref_payload,
            "install_release": install_payload,
            "source_runtime_plan": source_plan,
            "source_runtime_setup": source_setup_payload,
            "source_runtime_launcher": source_launcher_payload,
            "start_runtime": start_payload,
            "live_acceptance_dry_run": live_dry_payload,
            "live_acceptance": live_payload,
            "operator_handoff_run": run_payload,
        },
        "evidence": {
            "materials_request": materials,
            "runtime_delivery": {
                "status": delivery.get("status"),
                "state": delivery.get("state"),
                "next_step": delivery.get("next_step"),
            },
            "production_readiness": {
                "status": readiness.get("status"),
                "state": readiness.get("state"),
                "next_step": readiness.get("next_step"),
            },
            "go_live": {
                "status": go_live.get("status"),
                "steps": go_live.get("steps"),
            },
        },
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_preferred": True,
            "source_repo_only_when_needed": True,
            "managed_runtime_listener": "loopback_only",
            "no_fake_account_created": True,
            "live_mode_consumes_real_quota": True,
        },
    }


def build_proxy_kernel_operator_handoffs(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_operator_handoff(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.operator_handoff.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": {
            "total": len(rows),
            "ready_for_live_acceptance": sum(1 for row in rows if row.get("status") == "ready_for_live_acceptance"),
            "materials_required": sum(1 for row in rows if row.get("status") == "materials_required"),
            "operator_question_count": sum(len(row.get("operator_questions") or []) for row in rows),
        },
        "data": rows,
    }


def proxy_kernel_activation_stage(
    stage_id: str,
    label: str,
    status: str,
    *,
    ui_tab: str = "",
    primary_api: str = "",
    payload_template: dict[str, Any] | None = None,
    command: str = "",
    operator_required: bool = False,
    platform_can_run: bool = False,
    detail: dict[str, Any] | None = None,
) -> dict[str, Any]:
    return {
        "id": stage_id,
        "label": label,
        "status": status,
        "ui_tab": ui_tab,
        "primary_api": primary_api,
        "payload_template": payload_template or {},
        "command": command,
        "operator_required": operator_required,
        "platform_can_run": platform_can_run,
        "detail": detail or {},
    }


def build_proxy_kernel_activation_workflow(db: Session, provider_id: str) -> dict[str, Any]:
    if provider_id not in PROVIDER_TEMPLATES:
        raise KeyError(provider_id)
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    routing = proxy_kernel_routing_plan(db, provider_id)
    materials = build_proxy_kernel_materials_request(db, provider_id)
    handoff = build_proxy_kernel_operator_handoff(db, provider_id)
    readiness = build_proxy_kernel_production_readiness(db, provider_id)
    runtime_contract = build_proxy_kernel_runtime_contract(db, provider_id)
    active_user_count = db.query(models.User).filter(models.User.status == "active").count()
    active_api_key_count = db.query(models.ApiKey).filter(models.ApiKey.status == "active").count()
    template = PROVIDER_TEMPLATES[provider_id]
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    user_key_payload = {
        "user_id": "usr_admin",
        "name": f"{provider_id}-client-key",
    }
    user_create_payload = {
        "id": f"usr_{provider_id}_client",
        "email": f"{provider_id}.client@example.com",
        "tier": "default",
        "wallet_balance": 100000,
    }
    handoff_templates = handoff.get("submission_templates") or {}
    operator_questions = handoff.get("operator_questions") or []
    account_questions = [item for item in operator_questions if item.get("section") == "account"]
    runtime_questions = [item for item in operator_questions if str(item.get("section") or "").startswith("runtime")]
    routing_ready = bool(routing.get("route_config_ready"))
    account_ready = bool(routing.get("active_account_count", 0) > 0)
    runtime_ready = bool(kernel.get("runtime_registered") and kernel.get("runtime_loopback_only"))
    health_ready = bool((readiness.get("state") or {}).get("runtime_health_ok") or kernel.get("health_ok"))
    ready_for_acceptance = bool(readiness.get("ready_for_live_acceptance") or kernel.get("ready_for_live_acceptance"))
    production_ready = bool(readiness.get("production_ready") or kernel.get("usable"))
    source_plan = handoff_templates.get("source_runtime_plan") or {}
    source_available = bool(source_plan.get("source_available"))
    source_setup_ready = bool((handoff_templates.get("source_runtime_setup") or {}).get("command_id"))
    source_launcher_ready = bool((handoff_templates.get("source_runtime_launcher") or {}).get("command"))
    stages = [
        proxy_kernel_activation_stage(
            "route",
            "补齐模型路由",
            "done" if routing_ready else "action_required",
            ui_tab="kernels",
            primary_api="/v1/admin/proxy-kernels/{provider_id}/apply-routing",
            payload_template=(materials.get("routing_materials") or {}).get("apply_payload") or {},
            command=(materials.get("commands") or {}).get("apply_routing") or "",
            platform_can_run=True,
            detail={"enabled_mapping_count": routing.get("enabled_mapping_count", 0), "template_mapping_count": routing.get("template_mapping_count", 0)},
        ),
        proxy_kernel_activation_stage(
            "account",
            "导入真实上游账号",
            "done" if account_ready else "needs_input",
            ui_tab="oauth",
            primary_api="/v1/admin/account-onboarding",
            payload_template=handoff_templates.get("account_onboarding_inline_secret") or {},
            command=(handoff.get("steps") or [{}, {}])[1].get("command") if len(handoff.get("steps") or []) > 1 else "",
            operator_required=not account_ready,
            platform_can_run=False,
            detail={"active_account_count": routing.get("active_account_count", 0), "questions": account_questions, "credential_boundary": kernel.get("credential_boundary") or ""},
        ),
        proxy_kernel_activation_stage(
            "runtime",
            "准备并启动 loopback 内核",
            "done" if runtime_ready else "action_required",
            ui_tab="kernels",
            primary_api="/v1/admin/proxy-kernels/{provider_id}/operator-handoff/run",
            payload_template=handoff_templates.get("operator_handoff_run") or {},
            command=((handoff.get("steps") or [{}])[-1].get("command") if handoff.get("steps") else ""),
            operator_required=not runtime_ready and bool(runtime_questions),
            platform_can_run=True,
            detail={
                "runtime_registered": bool(kernel.get("runtime_registered")),
                "runtime_base_url": kernel.get("runtime_base_url") or "",
                "release_install_payload": handoff_templates.get("install_release") or {},
                "source_available": source_available,
                "source_setup_ready": source_setup_ready,
                "source_launcher_ready": source_launcher_ready,
                "source_setup_payload": handoff_templates.get("source_runtime_setup") or {},
                "source_launcher_payload": handoff_templates.get("source_runtime_launcher") or {},
                "questions": runtime_questions,
            },
        ),
        proxy_kernel_activation_stage(
            "health",
            "检查 runtime 健康",
            "done" if health_ready else "waiting" if runtime_ready else "blocked",
            ui_tab="kernels",
            primary_api="/v1/admin/proxy-kernels/{provider_id}/runtime-health-check",
            payload_template={"sync_provider_base_url": True, "require_running_process": False, "fail_on_health_check": False},
            command=(runtime_contract.get("commands") or {}).get("runtime_health_check") or "",
            platform_can_run=runtime_ready,
            detail={"runtime_contract_status": runtime_contract.get("status"), "latest_health": kernel.get("latest_health") or {}},
        ),
        proxy_kernel_activation_stage(
            "live_acceptance",
            "运行真实样本验收",
            "done" if production_ready else "waiting" if ready_for_acceptance else "blocked",
            ui_tab="kernels",
            primary_api="/v1/admin/proxy-kernels/{provider_id}/live-acceptance",
            payload_template=handoff_templates.get("live_acceptance_dry_run") or {"dry_run": True, "operations": list(template.operations), "max_samples": 1},
            command=(materials.get("commands") or {}).get("live_acceptance") or "",
            platform_can_run=ready_for_acceptance,
            detail={"ready_for_live_acceptance": ready_for_acceptance, "operations": list(template.operations), "live_mode_consumes_real_quota": True},
        ),
        proxy_kernel_activation_stage(
            "user_api_key",
            "准备下游调用 API Key",
            "done" if active_api_key_count > 0 else "action_required",
            ui_tab="users",
            primary_api="/v1/admin/api-keys",
            payload_template=user_key_payload,
            command=f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/api-keys -d '{json.dumps(user_key_payload, ensure_ascii=False, separators=(',', ':'))}'",
            operator_required=False,
            platform_can_run=active_user_count > 0,
            detail={"active_user_count": active_user_count, "active_api_key_count": active_api_key_count, "create_user_payload": user_create_payload},
        ),
    ]
    next_stage = next((stage for stage in stages if stage["status"] not in {"done"}), stages[-1] if stages else {})
    return {
        "object": "media2api.proxy_kernel.activation_workflow",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "status": "production_ready" if production_ready else "ready_for_live_acceptance" if ready_for_acceptance else "action_required",
        "usable": bool(kernel.get("usable")),
        "ready_for_live_acceptance": ready_for_acceptance,
        "next_stage": next_stage,
        "stages": stages,
        "required_user_inputs": [item for item in operator_questions if item.get("required") is not False],
        "sample_requests": {
            "image_generation": {
                "method": "POST",
                "url": f"{base}/v1/images/generations",
                "headers": {"Authorization": "Bearer $MEDIA2API_USER_API_KEY"},
                "body": {"model": "t2i-fast", "prompt": "one small verification image"},
            },
            "video_generation": {
                "method": "POST",
                "url": f"{base}/v1/videos/generations",
                "headers": {"Authorization": "Bearer $MEDIA2API_USER_API_KEY"},
                "body": {"model": "i2v-fast", "prompt": "one short verification video"},
            },
        },
        "evidence": {
            "kernel": kernel,
            "routing": {"route_config_ready": routing_ready, "active_account_count": routing.get("active_account_count", 0), "blockers": routing.get("blockers", [])},
            "materials": {"status": materials.get("status"), "next_step": materials.get("next_step")},
            "handoff": {"status": handoff.get("status"), "operator_question_count": len(operator_questions)},
            "production_readiness": {"status": readiness.get("status"), "next_step": readiness.get("next_step")},
        },
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "release_binary_preferred": True,
            "source_repo_only_when_needed": True,
            "dry_run_first": True,
        },
    }


def build_proxy_kernel_activation_workflows(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_activation_workflow(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.activation_workflow.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": {
            "total": len(rows),
            "production_ready": sum(1 for row in rows if row.get("status") == "production_ready"),
            "ready_for_live_acceptance": sum(1 for row in rows if row.get("ready_for_live_acceptance")),
            "action_required": sum(1 for row in rows if row.get("status") == "action_required"),
            "needs_user_input": sum(1 for row in rows if row.get("required_user_inputs")),
        },
        "data": rows,
    }


PROXY_KERNEL_GAP_ACTIONS = {
    "route": {"action_id": "apply-routing", "label": "补齐路由", "ui_tab": "kernels", "safe_to_run": True},
    "account": {"action_id": "open-account", "label": "导入真实账号", "ui_tab": "oauth", "safe_to_run": False},
    "runtime": {"action_id": "open-runtime", "label": "准备并启动 runtime", "ui_tab": "kernels", "safe_to_run": False},
    "health": {"action_id": "health-check", "label": "运行健康检查", "ui_tab": "kernels", "safe_to_run": True},
    "live_acceptance": {"action_id": "live-acceptance", "label": "运行验收 dry-run", "ui_tab": "kernels", "safe_to_run": True},
    "user_api_key": {"action_id": "open-users", "label": "发放下游 API Key", "ui_tab": "users", "safe_to_run": False},
}


def proxy_kernel_gap_from_stage(stage: dict[str, Any]) -> dict[str, Any]:
    action = dict(PROXY_KERNEL_GAP_ACTIONS.get(stage.get("id") or "", {}))
    status = stage.get("status") or "waiting"
    if stage.get("id") == "health" and not stage.get("platform_can_run"):
        action.update({"action_id": "open-runtime", "label": "先打开 runtime", "safe_to_run": False})
    if stage.get("id") == "live_acceptance" and not stage.get("platform_can_run"):
        action.update({"action_id": "go-live", "label": "查看上线清单", "safe_to_run": False})
    severity = "operator_action"
    if status == "needs_input":
        severity = "user_input"
    elif status in {"waiting", "blocked"}:
        severity = "blocked"
    return {
        "stage": stage.get("id"),
        "label": stage.get("label"),
        "status": status,
        "severity": severity,
        "ui_tab": stage.get("ui_tab") or action.get("ui_tab") or "",
        "primary_api": stage.get("primary_api") or "",
        "operator_required": bool(stage.get("operator_required")),
        "platform_can_run": bool(stage.get("platform_can_run")),
        "action": action,
        "detail": stage.get("detail") or {},
    }


def build_proxy_kernel_production_gap_report(db: Session, provider_id: str) -> dict[str, Any]:
    workflow = build_proxy_kernel_activation_workflow(db, provider_id)
    stages = list(workflow.get("stages") or [])
    gaps = [proxy_kernel_gap_from_stage(stage) for stage in stages if stage.get("status") != "done"]
    blocking_stages = [gap["stage"] for gap in gaps]
    next_gap = gaps[0] if gaps else {}
    ready_to_use = not gaps and bool(workflow.get("usable"))
    return {
        "object": "media2api.proxy_kernel.production_gap_report",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": workflow.get("selection_id"),
        "status": "ready_to_use" if ready_to_use else workflow.get("status") or "action_required",
        "ready_to_use": ready_to_use,
        "usable": bool(workflow.get("usable")),
        "ready_for_live_acceptance": bool(workflow.get("ready_for_live_acceptance")),
        "next_stage": workflow.get("next_stage") or {},
        "next_gap": next_gap,
        "blocking_stages": blocking_stages,
        "gaps": gaps,
        "stages": stages,
        "required_user_inputs": workflow.get("required_user_inputs") or [],
        "sample_requests": workflow.get("sample_requests") or {},
        "commands": {
            "activation_workflow": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {settings.public_base_url}/v1/admin/proxy-kernels/{provider_id}/activation-workflow",
            "production_gap_report": f"curl -H \"Authorization: Bearer $MEDIA2API_API_KEY\" {settings.public_base_url}/v1/admin/proxy-kernels/{provider_id}/production-gap-report",
        },
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "release_binary_preferred": True,
            "source_repo_only_when_needed": True,
            "ready_to_use_requires_user_api_key": True,
            "ready_to_use_requires_live_acceptance": True,
        },
    }


def build_proxy_kernel_production_gap_reports(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_production_gap_report(db, provider_id) for provider_id in selected]
    next_stage_counts: dict[str, int] = {}
    gap_counts: dict[str, int] = {}
    for row in rows:
        next_stage_id = (row.get("next_stage") or {}).get("id") or "none"
        next_stage_counts[next_stage_id] = next_stage_counts.get(next_stage_id, 0) + 1
        for stage_id in row.get("blocking_stages") or []:
            gap_counts[stage_id] = gap_counts.get(stage_id, 0) + 1
    return {
        "object": "media2api.proxy_kernel.production_gap_report.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": {
            "total": len(rows),
            "ready_to_use": sum(1 for row in rows if row.get("ready_to_use")),
            "usable": sum(1 for row in rows if row.get("usable")),
            "ready_for_live_acceptance": sum(1 for row in rows if row.get("ready_for_live_acceptance")),
            "action_required": sum(1 for row in rows if row.get("gaps")),
            "needs_user_input": sum(1 for row in rows if row.get("required_user_inputs")),
            "next_stage_counts": next_stage_counts,
            "gap_counts": gap_counts,
        },
        "data": rows,
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_preferred": True,
            "source_repo_only_when_needed": True,
            "ready_to_use_requires_user_api_key": True,
            "ready_to_use_requires_live_acceptance": True,
        },
    }


PROXY_KERNEL_HANDOFF_DEFAULT_STEPS = [
    "apply_routing",
    "submit_account_material",
    "install_release",
    "source_runtime_setup",
    "source_runtime_launcher",
    "start_runtime",
    "runtime_health_check",
    "live_acceptance_dry_run",
]

PROXY_KERNEL_ACTIVATION_RUN_DEFAULT_STEPS = [*PROXY_KERNEL_HANDOFF_DEFAULT_STEPS, "user_api_key"]


def proxy_kernel_payload_has_placeholder(value: Any) -> bool:
    if value is None:
        return False
    if isinstance(value, str):
        text = value.strip()
        if not text:
            return False
        lowered = text.lower()
        return any(
            marker in lowered
            for marker in [
                "<",
                ">",
                "paste provider-specific",
                "v x.y.z",
                "vx.y.z",
                "64-hex",
                "release-asset-name",
                "verified-artifact-path",
                "example-linux",
            ]
        )
    if isinstance(value, list):
        return any(proxy_kernel_payload_has_placeholder(item) for item in value)
    if isinstance(value, dict):
        return any(proxy_kernel_payload_has_placeholder(item) for item in value.values())
    return False


def proxy_kernel_handoff_step_result(step: str, status: str, *, executed: bool = False, detail: dict[str, Any] | None = None, message: str = "") -> dict[str, Any]:
    return {
        "step": step,
        "status": status,
        "executed": executed,
        "message": message,
        "detail": detail or {},
    }


def run_proxy_kernel_operator_handoff(
    db: Session,
    provider_id: str,
    req: ProxyKernelOperatorHandoffRunRequest,
    ctx: AuthContext,
) -> dict[str, Any]:
    if provider_id not in PROVIDER_TEMPLATES:
        raise KeyError(provider_id)
    proxy_kernel_service.require_spec(provider_id)
    handoff_before = build_proxy_kernel_operator_handoff(db, provider_id)
    templates = handoff_before.get("submission_templates") or {}
    requested_steps = [str(step).strip() for step in req.steps if str(step).strip()] or list(PROXY_KERNEL_HANDOFF_DEFAULT_STEPS)
    allowed_steps = set(PROXY_KERNEL_HANDOFF_DEFAULT_STEPS + ["live_acceptance"])
    unknown_steps = [step for step in requested_steps if step not in allowed_steps]
    if unknown_steps:
        raise ValueError("UNKNOWN_HANDOFF_STEPS:" + ",".join(unknown_steps))

    payloads = {
        "apply_routing": req.apply_routing or (templates.get("operator_handoff_run") or {}).get("apply_routing") or {},
        "submit_account_material": req.account_onboarding or {},
        "install_release": req.install_release or {},
        "source_runtime_setup": req.source_runtime_setup or {},
        "source_runtime_launcher": req.source_runtime_launcher or {},
        "start_runtime": req.start_runtime or {},
        "runtime_health_check": req.runtime_health_check or {"sync_provider_base_url": True, "require_running_process": False, "fail_on_health_check": False},
        "live_acceptance_dry_run": {**(templates.get("live_acceptance_dry_run") or {}), **(req.live_acceptance or {})},
        "live_acceptance": {**(templates.get("live_acceptance") or {}), **(req.live_acceptance or {})},
    }
    if not payloads["submit_account_material"]:
        payloads["submit_account_material"] = templates.get("account_onboarding_inline_secret") or {}
    if not payloads["install_release"]:
        payloads["install_release"] = templates.get("install_release") or {}
    if not payloads["source_runtime_setup"]:
        payloads["source_runtime_setup"] = templates.get("source_runtime_setup") or {}
    if not payloads["source_runtime_launcher"]:
        payloads["source_runtime_launcher"] = templates.get("source_runtime_launcher") or {}
    if not payloads["start_runtime"]:
        payloads["start_runtime"] = templates.get("start_runtime") or {}

    results: list[dict[str, Any]] = []
    for step in requested_steps:
        payload = payloads.get(step) or {}
        try:
            if req.dry_run:
                results.append(
                    proxy_kernel_handoff_step_result(
                        step,
                        "planned",
                        detail={"payload": payload, "has_placeholder": proxy_kernel_payload_has_placeholder(payload)},
                        message="Dry-run only; no state was changed.",
                    )
                )
                continue

            if step == "apply_routing":
                routing_req = ProxyKernelRoutingApplyRequest(**payload)
                result = apply_proxy_kernel_routing(
                    db,
                    provider_id,
                    status=routing_req.status,
                    enable_mappings=routing_req.enable_mappings,
                    priority_offset=routing_req.priority_offset,
                    update_provider_base_url=routing_req.update_provider_base_url,
                )
                results.append(proxy_kernel_handoff_step_result(step, "executed", executed=True, detail=result))
            elif step == "submit_account_material":
                if proxy_kernel_payload_has_placeholder(payload):
                    results.append(proxy_kernel_handoff_step_result(step, "skipped_placeholder", detail={"payload": payload}, message="Replace placeholder account material before live execution."))
                    continue
                account_req = AccountOnboardingRequest(**{**payload, "provider_id": provider_id})
                result = apply_account_onboarding(db, account_req)
                results.append(proxy_kernel_handoff_step_result(step, "executed", executed=True, detail=result))
            elif step == "install_release":
                if proxy_kernel_payload_has_placeholder(payload) or not str(payload.get("expected_sha256") or "").strip():
                    results.append(proxy_kernel_handoff_step_result(step, "skipped_missing_material", detail={"payload": payload}, message="Provide release asset_name and expected_sha256 before live execution."))
                    continue
                install_req = ProxyKernelReleaseInstallRequest(**payload)
                result = proxy_kernel_service.install_release(
                    provider_id=provider_id,
                    expected_sha256=install_req.expected_sha256,
                    asset_name=install_req.asset_name,
                    tag_name=install_req.tag_name,
                    force=install_req.force,
                )
                results.append(proxy_kernel_handoff_step_result(step, "executed", executed=True, detail=result))
            elif step == "source_runtime_setup":
                if proxy_kernel_payload_has_placeholder(payload) or (not payload.get("command_id") and not payload.get("command")):
                    results.append(proxy_kernel_handoff_step_result(step, "skipped_missing_material", detail={"payload": payload}, message="Sync source-repo and choose a source-runtime-plan setup command before live execution."))
                    continue
                setup_req = ProxyKernelSourceRuntimeSetupRequest(**{**payload, "dry_run": False})
                result = proxy_kernel_service.prepare_source_runtime_setup(
                    provider_id,
                    dry_run=False,
                    command_id=setup_req.command_id,
                    command=setup_req.command,
                    cwd=setup_req.cwd,
                    env=setup_req.env,
                    timeout_seconds=setup_req.timeout_seconds,
                    notes=setup_req.notes,
                    allow_reference_commands=setup_req.allow_reference_commands,
                )
                results.append(proxy_kernel_handoff_step_result(step, "executed" if result.get("status") == "completed" else str(result.get("status") or "executed"), executed=result.get("status") == "completed", detail=result))
            elif step == "source_runtime_launcher":
                if proxy_kernel_payload_has_placeholder(payload) or not payload.get("command"):
                    results.append(proxy_kernel_handoff_step_result(step, "skipped_missing_material", detail={"payload": payload}, message="Sync source-repo and choose a source-runtime-plan start command before live execution."))
                    continue
                launcher_req = ProxyKernelSourceRuntimeLauncherRequest(**{**payload, "dry_run": False})
                result = proxy_kernel_service.prepare_source_runtime_launcher(
                    provider_id,
                    base_url=launcher_req.base_url,
                    command=launcher_req.command,
                    cwd=launcher_req.cwd,
                    env=launcher_req.env,
                    version=launcher_req.version,
                    notes=launcher_req.notes,
                )
                if not req.start_runtime and result.get("start_payload_template"):
                    payloads["start_runtime"] = result["start_payload_template"]
                results.append(proxy_kernel_handoff_step_result(step, "executed", executed=True, detail=result))
            elif step == "start_runtime":
                if proxy_kernel_payload_has_placeholder(payload) or not payload.get("command"):
                    results.append(proxy_kernel_handoff_step_result(step, "skipped_missing_material", detail={"payload": payload}, message="Provide verified artifact path, command, base_url, and expected_sha256 before live execution."))
                    continue
                start_req = ProxyKernelRuntimeStartRequest(**payload)
                result = admin_proxy_kernel_start_runtime(provider_id, start_req, ctx, db)
                results.append(proxy_kernel_handoff_step_result(step, "executed", executed=True, detail=result))
            elif step == "runtime_health_check":
                health_req = ProxyKernelRuntimeHealthCheckRequest(**payload)
                result = run_proxy_kernel_runtime_health_check(
                    db,
                    provider_id,
                    sync_provider_base_url_value=health_req.sync_provider_base_url,
                    require_running_process=health_req.require_running_process,
                    fail_on_health_check=health_req.fail_on_health_check,
                )
                results.append(proxy_kernel_handoff_step_result(step, "executed", executed=True, detail=result))
            elif step in {"live_acceptance_dry_run", "live_acceptance"}:
                acceptance_payload = dict(payload)
                if step == "live_acceptance_dry_run":
                    acceptance_payload["dry_run"] = True
                elif proxy_kernel_payload_has_placeholder(acceptance_payload):
                    results.append(proxy_kernel_handoff_step_result(step, "skipped_placeholder", detail={"payload": acceptance_payload}, message="Replace placeholders before live acceptance."))
                    continue
                acceptance_req = ProxyKernelLiveAcceptanceRequest(**acceptance_payload)
                result = run_proxy_kernel_live_acceptance(db, provider_id, acceptance_req, ctx)
                results.append(proxy_kernel_handoff_step_result(step, "executed", executed=not acceptance_req.dry_run, detail=result))
        except Exception as exc:
            error_detail = {"error": str(getattr(exc, "detail", "") or exc), "type": type(exc).__name__}
            results.append(proxy_kernel_handoff_step_result(step, "failed", detail=error_detail))
            if not req.continue_on_error:
                break

    handoff_after = build_proxy_kernel_operator_handoff(db, provider_id)
    return {
        "object": "media2api.proxy_kernel.operator_handoff_run",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "dry_run": req.dry_run,
        "requested_steps": requested_steps,
        "results": results,
        "ok": all(item.get("status") in {"planned", "executed", "skipped_placeholder", "skipped_missing_material"} for item in results),
        "handoff_before": {
            "status": handoff_before.get("status"),
            "next_step": handoff_before.get("next_step"),
            "operator_question_count": len(handoff_before.get("operator_questions") or []),
        },
        "handoff_after": {
            "status": handoff_after.get("status"),
            "next_step": handoff_after.get("next_step"),
            "operator_question_count": len(handoff_after.get("operator_questions") or []),
        },
        "policy": {
            "default_mode": "dry_run",
            "dry_run_mutates_state": False,
            "live_mode_requires_explicit_payloads": True,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
        },
    }


def run_proxy_kernel_activation_user_api_key_step(
    db: Session,
    provider_id: str,
    req: ProxyKernelActivationRunRequest,
) -> dict[str, Any]:
    active_keys = db.query(models.ApiKey).filter(models.ApiKey.status == "active").order_by(models.ApiKey.created_at.desc()).all()
    payload = {
        "user_id": "usr_admin",
        "name": f"{provider_id}-client-key",
        **(req.user_api_key or {}),
    }
    if active_keys and not req.force_user_api_key:
        return proxy_kernel_handoff_step_result(
            "user_api_key",
            "skipped_existing",
            detail={
                "active_api_key_count": len(active_keys),
                "latest_key": serialize_api_key(active_keys[0]),
                "payload": payload,
            },
            message="An active downstream API key already exists.",
        )
    if req.dry_run:
        return proxy_kernel_handoff_step_result(
            "user_api_key",
            "planned",
            detail={"payload": payload, "requires_create_user_api_key": True},
            message="Dry-run only; no API key was created.",
        )
    if not req.create_user_api_key:
        return proxy_kernel_handoff_step_result(
            "user_api_key",
            "needs_confirmation",
            detail={"payload": payload},
            message="Set create_user_api_key=true to create and return a new downstream API key.",
        )
    user_id = str(payload.get("user_id") or "usr_admin")
    if not db.get(models.User, user_id):
        return proxy_kernel_handoff_step_result(
            "user_api_key",
            "blocked",
            detail={"payload": payload, "missing_user_id": user_id},
            message="Create or activate the target user before creating a downstream API key.",
        )
    raw_key = str(payload.get("key") or f"mk_{new_id('key')}")
    item = models.ApiKey(
        id=new_id("key"),
        user_id=user_id,
        name=str(payload.get("name") or f"{provider_id}-client-key"),
        key_hash=hash_api_key(raw_key),
        status="active",
    )
    db.add(item)
    db.commit()
    result = serialize_api_key(item)
    result["api_key"] = raw_key
    return proxy_kernel_handoff_step_result(
        "user_api_key",
        "executed",
        executed=True,
        detail=result,
        message="A new downstream API key was created. This plaintext key is only returned in this response.",
    )


def run_proxy_kernel_activation_run(
    db: Session,
    provider_id: str,
    req: ProxyKernelActivationRunRequest,
    ctx: AuthContext,
) -> dict[str, Any]:
    if provider_id not in PROVIDER_TEMPLATES:
        raise KeyError(provider_id)
    proxy_kernel_service.require_spec(provider_id)
    requested_steps = [str(step).strip() for step in req.steps if str(step).strip()] or list(PROXY_KERNEL_ACTIVATION_RUN_DEFAULT_STEPS)
    allowed_steps = set(PROXY_KERNEL_ACTIVATION_RUN_DEFAULT_STEPS + ["live_acceptance"])
    unknown_steps = [step for step in requested_steps if step not in allowed_steps]
    if unknown_steps:
        raise ValueError("UNKNOWN_ACTIVATION_STEPS:" + ",".join(unknown_steps))

    before_gap = build_proxy_kernel_production_gap_report(db, provider_id)
    handoff_steps = [step for step in requested_steps if step in set(PROXY_KERNEL_HANDOFF_DEFAULT_STEPS + ["live_acceptance"])]
    results: list[dict[str, Any]] = []
    if handoff_steps:
        handoff_req = ProxyKernelOperatorHandoffRunRequest(
            dry_run=req.dry_run,
            steps=handoff_steps,
            continue_on_error=req.continue_on_error,
            account_onboarding=req.account_onboarding,
            apply_routing=req.apply_routing,
            install_release=req.install_release,
            source_runtime_setup=req.source_runtime_setup,
            source_runtime_launcher=req.source_runtime_launcher,
            start_runtime=req.start_runtime,
            runtime_health_check=req.runtime_health_check,
            live_acceptance=req.live_acceptance,
        )
        handoff_run = run_proxy_kernel_operator_handoff(db, provider_id, handoff_req, ctx)
        results.extend(handoff_run.get("results") or [])
    else:
        handoff_run = {
            "object": "media2api.proxy_kernel.operator_handoff_run",
            "provider_id": provider_id,
            "dry_run": req.dry_run,
            "requested_steps": [],
            "results": [],
            "ok": True,
        }

    if "user_api_key" in requested_steps:
        results.append(run_proxy_kernel_activation_user_api_key_step(db, provider_id, req))

    after_gap = build_proxy_kernel_production_gap_report(db, provider_id)
    failures = [item for item in results if item.get("status") in {"failed", "blocked"}]
    needs_confirmation = [item for item in results if item.get("status") in {"needs_confirmation", "skipped_placeholder", "skipped_missing_material"}]
    next_gap = after_gap.get("next_gap") if isinstance(after_gap.get("next_gap"), dict) else {}
    if after_gap.get("ready_to_use"):
        status = "ready_to_use"
    elif failures:
        status = "failed"
    elif req.dry_run:
        status = "planned"
    else:
        status = "action_required"
    return {
        "object": "media2api.proxy_kernel.activation_run",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "dry_run": req.dry_run,
        "status": status,
        "ok": not failures,
        "ready_to_use": bool(after_gap.get("ready_to_use")),
        "requested_steps": requested_steps,
        "results": results,
        "needs_confirmation": needs_confirmation,
        "next_required_action": next_gap,
        "before_gap_report": before_gap,
        "handoff_run": {
            "object": handoff_run.get("object"),
            "ok": handoff_run.get("ok"),
            "requested_steps": handoff_run.get("requested_steps"),
            "handoff_before": handoff_run.get("handoff_before"),
            "handoff_after": handoff_run.get("handoff_after"),
        },
        "after_gap_report": after_gap,
        "policy": {
            "default_mode": "dry_run",
            "dry_run_mutates_state": False,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_preferred": True,
            "source_repo_only_when_needed": True,
            "live_mode_requires_real_materials": True,
            "user_api_key_creation_requires_create_user_api_key": True,
        },
    }


def proxy_kernel_default_downstream_user_id(provider_id: str) -> str:
    return f"usr_{provider_id}_client"[:64]


def downstream_api_key_candidates(db: Session) -> list[models.ApiKey]:
    rows = (
        db.query(models.ApiKey)
        .join(models.User, models.ApiKey.user_id == models.User.id)
        .filter(models.ApiKey.status == "active", models.User.status == "active")
        .order_by(models.ApiKey.created_at.desc())
        .limit(500)
        .all()
    )
    return [item for item in rows if not is_admin_user(item.user)]


def proxy_kernel_downstream_model_hints(provider_id: str) -> dict[str, str]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    operations = set(template.operations if template else [])
    image_model = "t2i-fast" if "text_to_image" in operations else "image-edit" if operations.intersection({"image_edit", "image_to_image"}) else "t2i-fast"
    video_model = "t2v-general" if "text_to_video" in operations else "i2v-fast" if "image_to_video" in operations else "video-extend"
    return {
        "image_generation": image_model,
        "image_edit": "image-edit",
        "video_generation": video_model,
    }


def proxy_kernel_downstream_sample_requests(provider_id: str, user_key_env: str = "$MEDIA2API_USER_API_KEY") -> dict[str, Any]:
    base = settings.public_base_url.rstrip("/")
    models_ = proxy_kernel_downstream_model_hints(provider_id)
    template = PROVIDER_TEMPLATES.get(provider_id)
    operations = set(template.operations if template else [])
    samples = {
        "image_generation": {
            "supported": bool(not operations or "text_to_image" in operations),
            "method": "POST",
            "url": f"{base}/v1/images/generations",
            "headers": {"Authorization": f"Bearer {user_key_env}", "Content-Type": "application/json"},
            "body": {"model": models_["image_generation"], "prompt": "one verification image, clean product photo lighting", "size": "1024x1024", "n": 1},
            "curl": (
                f"curl -X POST {base}/v1/images/generations "
                f"-H \"Authorization: Bearer {user_key_env}\" "
                f"-H \"Content-Type: application/json\" "
                f"-d '{json.dumps({'model': models_['image_generation'], 'prompt': 'one verification image, clean product photo lighting', 'size': '1024x1024', 'n': 1}, ensure_ascii=False, separators=(',', ':'))}'"
            ),
        },
        "image_edit": {
            "supported": bool(not operations or operations.intersection({"image_edit", "image_to_image"})),
            "method": "POST",
            "url": f"{base}/v1/images/edits",
            "headers": {"Authorization": f"Bearer {user_key_env}", "Content-Type": "application/json"},
            "body": {"model": models_["image_edit"], "prompt": "replace the background with a dark studio backdrop", "image": "asset://input-image-id"},
            "curl": (
                f"curl -X POST {base}/v1/images/edits "
                f"-H \"Authorization: Bearer {user_key_env}\" "
                f"-H \"Content-Type: application/json\" "
                f"-d '{json.dumps({'model': models_['image_edit'], 'prompt': 'replace the background with a dark studio backdrop', 'image': 'asset://input-image-id'}, ensure_ascii=False, separators=(',', ':'))}'"
            ),
        },
        "video_generation": {
            "supported": bool(not operations or operations.intersection({"text_to_video", "image_to_video", "video_extend"})),
            "method": "POST",
            "url": f"{base}/v1/videos/generations",
            "headers": {"Authorization": f"Bearer {user_key_env}", "Content-Type": "application/json"},
            "body": {"model": models_["video_generation"], "prompt": "a short product turntable shot, five seconds", "duration": 5},
            "curl": (
                f"curl -X POST {base}/v1/videos/generations "
                f"-H \"Authorization: Bearer {user_key_env}\" "
                f"-H \"Content-Type: application/json\" "
                f"-d '{json.dumps({'model': models_['video_generation'], 'prompt': 'a short product turntable shot, five seconds', 'duration': 5}, ensure_ascii=False, separators=(',', ':'))}'"
            ),
        },
    }
    return samples


def build_proxy_kernel_downstream_call_package(
    db: Session,
    provider_id: str,
    req: ProxyKernelDownstreamCallPackageRequest | None = None,
) -> dict[str, Any]:
    if provider_id not in PROVIDER_TEMPLATES:
        raise KeyError(provider_id)
    req = req or ProxyKernelDownstreamCallPackageRequest()
    gap_report = build_proxy_kernel_production_gap_report(db, provider_id)
    existing_downstream_keys = downstream_api_key_candidates(db)
    chosen_existing_key = existing_downstream_keys[0] if existing_downstream_keys and not req.force_user_api_key else None
    target_user_id = str(req.user_id or proxy_kernel_default_downstream_user_id(provider_id))
    target_email = str(req.user_email or f"{provider_id}.client@media2api.local")
    key_name = str(req.key_name or f"{provider_id}-downstream-key")
    user_before = db.get(models.User, target_user_id)
    created_user: models.User | None = None
    created_api_key: dict[str, Any] | None = None
    api_key_action = "reuse_existing" if chosen_existing_key else "none"
    api_key_message = "已有普通下游 API Key，可复用或选择强制创建新 key。" if chosen_existing_key else "尚未发现普通下游 API Key。"

    if not chosen_existing_key and req.create_user_api_key:
        if req.dry_run:
            api_key_action = "planned_create"
            api_key_message = "Dry-run only; no user or API key was created."
        else:
            user = user_before
            if not user:
                if not req.create_user:
                    api_key_action = "blocked_missing_user"
                    api_key_message = "Target downstream user does not exist. Set create_user=true or create the user first."
                else:
                    user = models.User(id=target_user_id, email=target_email, status="active", tier=req.user_tier or "default", wallet_balance=req.wallet_balance)
                    db.add(user)
                    db.flush()
                    created_user = user
            if user and is_admin_user(user):
                api_key_action = "blocked_admin_user"
                api_key_message = "Downstream call package will not create customer keys for an admin user."
            elif user and api_key_action != "blocked_missing_user":
                raw_key = str(req.key or f"mk_{new_id('key')}")
                item = models.ApiKey(id=new_id("key"), user_id=user.id, name=key_name, key_hash=hash_api_key(raw_key), status="active")
                db.add(item)
                db.commit()
                created_api_key = serialize_api_key(item)
                created_api_key["api_key"] = raw_key
                api_key_action = "created"
                api_key_message = "A new downstream API key was created. The plaintext key is returned only in this response."
    elif not chosen_existing_key:
        api_key_action = "requires_confirmation"
        api_key_message = "Set create_user_api_key=true to create a downstream API key."

    if created_user and not created_api_key:
        db.commit()

    downstream_key_ready = bool(chosen_existing_key or created_api_key)
    core_gaps = [gap for gap in gap_report.get("gaps") or [] if gap.get("stage") != "user_api_key"]
    blockers = list(core_gaps)
    if not downstream_key_ready:
        blockers.append(
            {
                "stage": "user_api_key",
                "label": "发放下游 API Key",
                "status": "action_required" if api_key_action not in {"planned_create"} else "planned",
                "severity": "operator_action",
                "ui_tab": "users",
                "primary_api": "/v1/admin/proxy-kernels/{provider_id}/downstream-call-package",
                "operator_required": False,
                "platform_can_run": True,
                "action": {"action_id": "create-downstream-key", "label": "创建下游调用 Key", "safe_to_run": False},
                "detail": {"target_user_id": target_user_id, "api_key_action": api_key_action},
            }
        )
    ready_to_call = bool(not blockers and gap_report.get("usable") and downstream_key_ready)
    existing_key_payload = serialize_api_key(chosen_existing_key) if chosen_existing_key else None
    latest_key = created_api_key or existing_key_payload
    create_payload = {
        "dry_run": True,
        "create_user": True,
        "create_user_api_key": True,
        "force_user_api_key": False,
        "user_id": target_user_id,
        "user_email": target_email,
        "user_tier": req.user_tier,
        "wallet_balance": req.wallet_balance,
        "key_name": key_name,
    }
    base = settings.public_base_url.rstrip("/")
    admin_key = "$MEDIA2API_API_KEY"
    return {
        "object": "media2api.proxy_kernel.downstream_call_package",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": gap_report.get("selection_id"),
        "dry_run": bool(req.dry_run),
        "ready_to_call": ready_to_call,
        "status": "ready_to_call" if ready_to_call else "action_required",
        "next_action": blockers[0] if blockers else {"stage": "none", "label": "可以发起下游调用", "status": "done"},
        "blockers": blockers,
        "downstream_api_key": {
            "ready": downstream_key_ready,
            "action": api_key_action,
            "message": api_key_message,
            "target_user": serialize_user(db.get(models.User, target_user_id)) if db.get(models.User, target_user_id) else None,
            "created_user": serialize_user(created_user) if created_user else None,
            "latest_key": latest_key,
            "existing_active_downstream_key_count": len(existing_downstream_keys),
            "plaintext_key_returned": bool(created_api_key and created_api_key.get("api_key")),
        },
        "environment": {
            "MEDIA2API_BASE_URL": base,
            "MEDIA2API_USER_API_KEY": "<paste-created-api_key-here>" if created_api_key else "$MEDIA2API_USER_API_KEY",
            "PROVIDER_ID": provider_id,
        },
        "sample_requests": proxy_kernel_downstream_sample_requests(provider_id),
        "commands": {
            "inspect": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/downstream-call-package",
            "create_key_dry_run": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/downstream-call-package -d '{json.dumps(create_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "create_key": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/downstream-call-package -d '{json.dumps({**create_payload, 'dry_run': False}, ensure_ascii=False, separators=(',', ':'))}'",
        },
        "evidence": {
            "production_gap_report": {
                "status": gap_report.get("status"),
                "ready_to_use": gap_report.get("ready_to_use"),
                "usable": gap_report.get("usable"),
                "blocking_stages": gap_report.get("blocking_stages") or [],
            },
            "core_gap_count": len(core_gaps),
            "downstream_key_ready": downstream_key_ready,
        },
        "policy": {
            "default_mode": "dry_run",
            "dry_run_mutates_state": False,
            "admin_bootstrap_key_is_not_downstream_key": True,
            "create_user_api_key_requires_explicit_true": True,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_preferred": True,
            "source_repo_only_when_needed": True,
            "ready_to_call_requires_live_acceptance": True,
        },
    }


def build_proxy_kernel_downstream_call_packages(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_downstream_call_package(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.downstream_call_package.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": {
            "total": len(rows),
            "ready_to_call": sum(1 for row in rows if row.get("ready_to_call")),
            "action_required": sum(1 for row in rows if not row.get("ready_to_call")),
            "missing_downstream_key": sum(1 for row in rows if not ((row.get("downstream_api_key") or {}).get("ready"))),
            "blocked_by_core_readiness": sum(1 for row in rows if (row.get("evidence") or {}).get("core_gap_count")),
        },
        "data": rows,
        "policy": {
            "default_mode": "read_only",
            "admin_bootstrap_key_is_not_downstream_key": True,
            "official_sdk_api": "forbidden",
            "release_binary_preferred": True,
        },
    }


def proxy_kernel_go_live_operator_questions(
    provider_id: str,
    account_materials: dict[str, Any],
    handoff: dict[str, Any],
    runtime_delivery: dict[str, Any],
) -> list[dict[str, Any]]:
    questions: list[dict[str, Any]] = []
    required_fields = account_materials.get("required_fields") or []
    if required_fields:
        field_labels = ", ".join(str(field.get("label") or field.get("name")) for field in required_fields)
        questions.append(
            {
                "section": "account",
                "label": f"提供 {provider_id} 的真实账号材料",
                "input": "credential_value / credential_ref",
                "required": True,
                "message": f"请把 {field_labels} 替换成真实 Web session、CLI OAuth 或 Agent profile；不要保留 <...> 占位符。",
                "fields": required_fields,
            }
        )
    for group in account_materials.get("any_of_groups") or []:
        questions.append(
            {
                "section": "account",
                "label": "任选一种账号凭据输入",
                "input": group.get("group"),
                "required": bool(group.get("required")),
                "message": "该 provider 接受多种凭据形态，请任选一种真实材料填写。",
                "fields": group.get("fields") or [],
            }
        )

    runtime_state = runtime_delivery.get("state") or {}
    if not runtime_state.get("release_or_runtime_ready"):
        questions.append(
            {
                "section": "runtime",
                "label": "提供 release 资产和 SHA256，或确认 source-repo 兜底",
                "input": "tag_name / asset_name / expected_sha256",
                "required": True,
                "message": "优先使用目标仓库 release 中的 Linux 二进制或压缩包；没有可安装 release 时才同步 source-repo 做协议参考、构建或重写 adapter。",
            }
        )
    if not runtime_state.get("runtime_registered"):
        questions.append(
            {
                "section": "runtime",
                "label": "提供 loopback runtime 启动参数",
                "input": "base_url / command / artifact_path",
                "required": True,
                "message": "runtime 只能监听 127.0.0.1、localhost 或 ::1；公开 API 仍由 media2api 对外提供。",
            }
        )

    seen = {(item.get("section"), item.get("label")) for item in questions}
    for item in handoff.get("operator_questions") or []:
        key = (item.get("section"), item.get("label"))
        if key not in seen:
            questions.append(item)
            seen.add(key)
    return questions


def proxy_kernel_go_live_step(
    step_id: str,
    label: str,
    ok: bool,
    *,
    status: str | None = None,
    action: str = "",
    ui_tab: str = "",
    primary_api: str = "",
    detail: dict[str, Any] | None = None,
) -> dict[str, Any]:
    return {
        "id": step_id,
        "label": label,
        "status": status or ("done" if ok else "action_required"),
        "ok": bool(ok),
        "action": action,
        "ui_tab": ui_tab,
        "primary_api": primary_api,
        "detail": detail or {},
    }


def proxy_kernel_go_live_next_action(steps: list[dict[str, Any]], downstream: dict[str, Any]) -> dict[str, Any]:
    if downstream.get("ready_to_call"):
        return {
            "id": "call_downstream_api",
            "label": "复制下游调用样例",
            "action": "使用普通用户 API Key 调用 /v1/images/* 或 /v1/videos/*。",
            "ui_tab": "上线包",
        }
    for step in steps:
        if not step.get("ok"):
            return {
                "id": step.get("id"),
                "label": step.get("label"),
                "action": step.get("action"),
                "ui_tab": step.get("ui_tab"),
                "primary_api": step.get("primary_api"),
                "detail": step.get("detail") or {},
            }
    next_action = downstream.get("next_action") or {}
    return {
        "id": str(next_action.get("stage") or "inspect_downstream"),
        "label": str(next_action.get("label") or "检查下游调用包"),
        "action": "刷新下游调用包，确认普通用户 API Key 和调用样例。",
        "ui_tab": "上线包",
        "detail": next_action,
    }


def build_proxy_kernel_go_live_package(db: Session, provider_id: str) -> dict[str, Any]:
    if provider_id not in PROVIDER_TEMPLATES:
        raise KeyError(provider_id)
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    account_materials = build_proxy_kernel_account_materials(db, provider_id)
    runtime_delivery = build_proxy_kernel_runtime_delivery_plan(db, provider_id)
    readiness = build_proxy_kernel_production_readiness(db, provider_id)
    activation = build_proxy_kernel_activation_workflow(db, provider_id)
    handoff = build_proxy_kernel_operator_handoff(db, provider_id)
    downstream = build_proxy_kernel_downstream_call_package(db, provider_id)
    contract = build_proxy_kernel_runtime_contract(db, provider_id)
    production_state = readiness.get("state") or {}
    downstream_key = downstream.get("downstream_api_key") or {}
    runtime_state = runtime_delivery.get("state") or {}
    account_ready = bool(production_state.get("account_ready"))
    runtime_ready = bool(production_state.get("runtime_ready"))
    health_ok = bool(production_state.get("health_ok"))
    live_ok = bool(production_state.get("live_acceptance_ok"))
    downstream_key_ready = bool(downstream_key.get("ready"))
    route_ready = bool(production_state.get("route_ready"))
    contract_ready = bool(production_state.get("contract_ready"))
    ready_to_call = bool(downstream.get("ready_to_call"))
    steps = [
        proxy_kernel_go_live_step(
            "routing",
            "确认模型路由",
            route_ready and contract_ready,
            action="点击“补齐路由映射”，让逻辑模型指向这个 provider 声明的图片/视频能力。",
            ui_tab="启动执行器",
            primary_api=f"/v1/admin/proxy-kernels/{provider_id}/apply-routing",
            detail={"route_ready": route_ready, "contract_ready": contract_ready, "contract_status": contract.get("status")},
        ),
        proxy_kernel_go_live_step(
            "account",
            "连接真实上游账号",
            account_ready,
            status="done" if account_ready else "needs_input",
            action="按账号材料模板提交真实 Web session、CLI OAuth 或 Agent profile；预检通过后导入账号池。",
            ui_tab="上线包 / 授权资源",
            primary_api=f"/v1/admin/proxy-kernels/{provider_id}/account-materials",
            detail={
                "status": account_materials.get("status"),
                "required_fields": account_materials.get("required_fields") or [],
                "any_of_groups": account_materials.get("any_of_groups") or [],
            },
        ),
        proxy_kernel_go_live_step(
            "runtime",
            "准备并启动反代内核",
            runtime_ready,
            action="优先安装 release 二进制并校验 SHA256；没有可用 release 时同步 source-repo 做参考或构建，再启动 loopback runtime。",
            ui_tab="启动执行器",
            primary_api=f"/v1/admin/proxy-kernels/{provider_id}/runtime-delivery-plan",
            detail={
                "status": runtime_delivery.get("status"),
                "next_step": runtime_delivery.get("next_step"),
                "release_or_runtime_ready": runtime_state.get("release_or_runtime_ready"),
                "runtime_registered": runtime_state.get("runtime_registered"),
                "process": kernel.get("process") or {},
            },
        ),
        proxy_kernel_go_live_step(
            "health",
            "运行 runtime 健康检查",
            health_ok,
            action="启动或登记 loopback runtime 后运行健康检查，确认 media2api 可以访问执行器。",
            ui_tab="启动执行器",
            primary_api=f"/v1/admin/proxy-kernels/{provider_id}/runtime-health-check",
            detail={"latest_health": (readiness.get("evidence") or {}).get("latest_health")},
        ),
        proxy_kernel_go_live_step(
            "live_acceptance",
            "跑 1 条真实样本验收",
            live_ok,
            status="done" if live_ok else ("waiting" if not (route_ready and account_ready and runtime_ready and health_ok) else "action_required"),
            action="先 dry-run，再切到 Live 模式运行 1 条真实样本，确认有可下载图片或视频资产。",
            ui_tab="启动执行器",
            primary_api=f"/v1/admin/proxy-kernels/{provider_id}/live-acceptance",
            detail={"ready_for_live_acceptance": readiness.get("ready_for_live_acceptance")},
        ),
        proxy_kernel_go_live_step(
            "downstream_key",
            "发放普通用户 API Key",
            downstream_key_ready,
            action="创建或复用普通用户 API Key。不要把管理员 bootstrap key 当成客户调用 key。",
            ui_tab="用户与鉴权",
            primary_api=f"/v1/admin/proxy-kernels/{provider_id}/downstream-call-package",
            detail=downstream_key,
        ),
        proxy_kernel_go_live_step(
            "call_downstream_api",
            "复制调用样例验证",
            ready_to_call,
            status="done" if ready_to_call else "waiting",
            action="使用下游 Key 调用 /v1/images/generations、/v1/images/edits 或 /v1/videos/generations。",
            ui_tab="上线包",
            primary_api="/v1/images/* /v1/videos/*",
            detail={"sample_requests": downstream.get("sample_requests") or {}},
        ),
    ]
    questions = proxy_kernel_go_live_operator_questions(provider_id, account_materials, handoff, runtime_delivery)
    next_action = proxy_kernel_go_live_next_action(steps, downstream)
    base = settings.public_base_url.rstrip("/")
    admin_key = "$MEDIA2API_API_KEY"
    status = (
        "ready_to_call"
        if ready_to_call
        else "ready_for_live_acceptance"
        if readiness.get("ready_for_live_acceptance")
        else "materials_required"
        if any(step.get("status") == "needs_input" for step in steps)
        else "action_required"
    )
    return {
        "object": "media2api.proxy_kernel.go_live_package",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "repo": (kernel.get("spec") or {}).get("repo"),
        "repo_url": (kernel.get("spec") or {}).get("repo_url"),
        "status": status,
        "ready_to_call": ready_to_call,
        "production_ready": bool(readiness.get("production_ready")),
        "ready_for_live_acceptance": bool(readiness.get("ready_for_live_acceptance")),
        "next_action": next_action,
        "steps": steps,
        "missing_external_inputs": questions,
        "account_connection": {
            "ready": account_ready,
            "status": account_materials.get("status"),
            "auth_method": (account_materials.get("payload_template") or {}).get("auth_method"),
            "resource_type": (account_materials.get("payload_template") or {}).get("resource_type"),
            "required_fields": account_materials.get("required_fields") or [],
            "any_of_groups": account_materials.get("any_of_groups") or [],
            "credential_value_json_template": account_materials.get("credential_value_json_template"),
            "payload_template": account_materials.get("payload_template"),
            "payload_preview": account_materials.get("payload_preview"),
            "preflight": account_materials.get("preflight"),
            "guide": account_materials.get("guide"),
            "commands": account_materials.get("commands"),
        },
        "runtime_connection": {
            "ready": runtime_ready,
            "status": runtime_delivery.get("status"),
            "next_step": runtime_delivery.get("next_step"),
            "state": runtime_delivery.get("state"),
            "release_binary_preferred": True,
            "source_repo_only_when_needed": True,
            "runtime": runtime_delivery.get("runtime"),
            "source_repo": kernel.get("source_repo") or proxy_kernel_service.source_repo_status(provider_id),
            "process": kernel.get("process") or {},
            "commands": runtime_delivery.get("commands"),
        },
        "verification": {
            "health_ok": health_ok,
            "live_acceptance_ok": live_ok,
            "production_readiness": {
                "status": readiness.get("status"),
                "state": readiness.get("state"),
                "next_step": readiness.get("next_step"),
            },
            "activation_workflow": {
                "status": activation.get("status"),
                "next_stage": activation.get("next_stage"),
                "required_user_inputs": activation.get("required_user_inputs") or [],
            },
        },
        "downstream_call": {
            "ready": ready_to_call,
            "status": downstream.get("status"),
            "downstream_api_key": downstream_key,
            "environment": downstream.get("environment"),
            "sample_requests": downstream.get("sample_requests"),
            "commands": downstream.get("commands"),
            "blockers": downstream.get("blockers") or [],
        },
        "commands": {
            "inspect": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/go-live-package",
            "apply_routing": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/apply-routing -d '{{\"status\":\"active\",\"enable_mappings\":true,\"priority_offset\":0,\"update_provider_base_url\":true}}'",
            "account_materials": (account_materials.get("commands") or {}).get("inspect"),
            "account_preflight": (account_materials.get("commands") or {}).get("preflight"),
            "runtime_delivery_plan": (runtime_delivery.get("commands") or {}).get("inspect") or f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/runtime-delivery-plan",
            "release_probe": (runtime_delivery.get("commands") or {}).get("release_probe"),
            "install_release": (runtime_delivery.get("commands") or {}).get("install_release"),
            "source_repo_sync": (runtime_delivery.get("commands") or {}).get("source_repo_sync"),
            "start_runtime": (runtime_delivery.get("commands") or {}).get("start_runtime"),
            "runtime_health_check": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/runtime-health-check -d '{{\"sync_provider_base_url\":true,\"require_running_process\":false,\"fail_on_health_check\":false}}'",
            "live_acceptance_dry_run": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{{\"dry_run\":true,\"run_runtime_health\":true,\"require_runtime_health\":true,\"run_samples\":true,\"max_samples\":1}}'",
            "live_acceptance": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{{\"dry_run\":false,\"run_runtime_health\":true,\"require_runtime_health\":true,\"run_samples\":true,\"max_samples\":1}}'",
            "downstream_call_package": (downstream.get("commands") or {}).get("inspect"),
            "create_downstream_key": (downstream.get("commands") or {}).get("create_key"),
        },
        "ui_navigation": [
            {"label": "先看上线包", "tab": "反代内核", "pane": "上线包"},
            {"label": "填账号材料", "tab": "反代内核", "pane": "上线包 / 授权资源"},
            {"label": "安装并启动 runtime", "tab": "反代内核", "pane": "启动执行器"},
            {"label": "发放下游 Key", "tab": "用户与鉴权", "pane": "API Key / 创建与发放"},
        ],
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "release_binary_first": True,
            "source_repo_only_when": "release missing, asset unusable, protocol inspection, local build input, or adapter rewrite reference",
            "managed_runtime_listener": "loopback_only",
            "admin_bootstrap_key_is_not_downstream_key": True,
            "ready_to_call_requires_real_account_runtime_health_live_acceptance_and_user_api_key": True,
        },
    }


def build_proxy_kernel_go_live_packages(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_go_live_package(db, provider_id) for provider_id in selected]
    next_action_counts: dict[str, int] = {}
    for row in rows:
        action_id = str((row.get("next_action") or {}).get("id") or "unknown")
        next_action_counts[action_id] = next_action_counts.get(action_id, 0) + 1
    return {
        "object": "media2api.proxy_kernel.go_live_package.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": {
            "total": len(rows),
            "ready_to_call": sum(1 for row in rows if row.get("ready_to_call")),
            "ready_for_live_acceptance": sum(1 for row in rows if row.get("ready_for_live_acceptance")),
            "production_ready": sum(1 for row in rows if row.get("production_ready")),
            "materials_required": sum(1 for row in rows if row.get("status") == "materials_required"),
            "action_required": sum(1 for row in rows if row.get("status") == "action_required"),
            "missing_external_input_count": sum(len(row.get("missing_external_inputs") or []) for row in rows),
            "next_action_counts": next_action_counts,
        },
        "data": rows,
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "ready_to_call_requires_real_acceptance": True,
        },
    }


def proxy_kernel_runtime_default_base_url(provider_id: str) -> str:
    try:
        index = FINALIZED_PROVIDER_IDS.index(provider_id)
    except ValueError:
        index = 0
    return f"http://127.0.0.1:{19081 + index}"


def proxy_kernel_runtime_start_templates(
    provider_id: str,
    artifact_path: str,
    expected_sha: str,
    base_url: str,
    version: str,
    notes: str,
) -> dict[str, Any]:
    try:
        parsed = urlparse(base_url)
        host = parsed.hostname or "127.0.0.1"
        port = str(parsed.port or (443 if parsed.scheme == "https" else 80))
    except Exception:
        host = "127.0.0.1"
        port = proxy_kernel_runtime_default_base_url(provider_id).rsplit(":", 1)[-1]
    env = {"HOST": host, "PORT": port, "BASE_URL": base_url}
    candidates = [
        {
            "id": "env_only",
            "label": "Executable with HOST/PORT environment",
            "command": [artifact_path],
            "env": env,
            "config_files": [],
            "confidence": "low",
            "operator_note": "Use when the selected runtime reads HOST/PORT from environment or its own config file.",
        },
        {
            "id": "host_port_flags",
            "label": "Executable with --host/--port flags",
            "command": [artifact_path, "--host", host, "--port", port],
            "env": {"NO_COLOR": "1"},
            "config_files": [],
            "confidence": "low",
            "operator_note": "Use only after the runtime help output confirms --host and --port are supported.",
        },
        {
            "id": "port_flag",
            "label": "Executable with --port flag",
            "command": [artifact_path, "--port", port],
            "env": {"HOST": host, "BASE_URL": base_url},
            "config_files": [],
            "confidence": "low",
            "operator_note": "Use only after the runtime help output confirms --port is supported.",
        },
    ]
    if provider_id == "gemini_cli_oauth":
        config_path = str(Path(artifact_path).with_name("config.yaml")) if artifact_path and not artifact_path.startswith("<") else "<runtime-config-path>"
        auth_dir = str((settings.proxy_kernel_dir / provider_id / "auth").expanduser().resolve())
        try:
            port_value = int(port)
        except ValueError:
            port_value = 19083
        config_content = "\n".join([
            f"host: {json.dumps(host)}",
            f"port: {port_value}",
            "tls:",
            "  enable: false",
            "remote-management:",
            "  allow-remote: false",
            "  secret-key: \"\"",
            "  disable-control-panel: true",
            f"auth-dir: {json.dumps(auth_dir)}",
            "api-keys: []",
            "debug: false",
            "logging-to-file: false",
            "usage-statistics-enabled: false",
            "enable-gemini-cli-endpoint: false",
            "",
        ])
        candidates.insert(0, {
            "id": "cliproxyapi_config_standalone",
            "label": "CLIProxyAPI embedded standalone server",
            "command": [artifact_path, "-config", config_path, "-standalone"],
            "env": env,
            "config_files": [{"path": config_path, "content": config_content}],
            "confidence": "high",
            "operator_note": "CLIProxyAPI requires config.yaml. The platform writes a loopback-only config before starting the process.",
        })
    recommended = candidates[0] if candidates else {"id": "env_only", "command": [artifact_path], "env": env}
    payload = {
        "command": recommended.get("command") or [artifact_path],
        "base_url": base_url,
        "artifact_path": artifact_path,
        "expected_sha256": expected_sha,
        "cwd": "",
        "env": recommended.get("env") or {},
        "config_files": recommended.get("config_files") or [],
        "version": version,
        "notes": notes,
        "replace_existing": True,
        "update_provider_base_url": True,
        "run_health_check": True,
        "fail_on_health_check": False,
    }
    return {
        "recommended_template_id": recommended.get("id") or "env_only",
        "recommended_payload": payload,
        "candidates": candidates,
        "operator_confirmation_required": True,
        "preflight_required": True,
    }


def proxy_kernel_runtime_delivery_next_step(
    *,
    routing: dict[str, Any],
    kernel: dict[str, Any],
    source_repo: dict[str, Any],
) -> dict[str, Any]:
    installed = kernel.get("installed") if isinstance(kernel.get("installed"), dict) else {}
    process = kernel.get("process") if isinstance(kernel.get("process"), dict) else {}
    source_available = bool(source_repo.get("exists") and source_repo.get("is_git_repo"))
    if not routing.get("route_config_ready"):
        return {
            "id": "apply_routing",
            "label": "补齐路由映射",
            "ui_pane": "运行状态",
            "reason": "Provider 或模型映射还没有按定型模板准备好。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/apply-routing",
        }
    if not installed and not kernel.get("runtime_registered"):
        return {
            "id": "probe_release",
            "label": "先探测 release",
            "ui_pane": "启动执行器",
            "reason": "还没有已校验 release 资产；优先探测 GitHub release，再填写 asset 名称和 SHA256。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-probe",
            "fallback": "如果 release 没有可用资产，再同步 source-repo 做协议参考。" if not source_available else "source-repo 已同步，但仍建议优先使用 release 二进制。",
        }
    if installed and not kernel.get("installed_verified"):
        return {
            "id": "install_release",
            "label": "补充 SHA256 并安装 release",
            "ui_pane": "启动执行器",
            "reason": "资产存在但 hash 证据不完整或不匹配，不能作为受控执行器启动。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/install-release",
        }
    preflight = kernel.get("runtime_preflight") if isinstance(kernel.get("runtime_preflight"), dict) else {}
    if installed and kernel.get("installed_verified") and not kernel.get("runtime_registered") and not preflight:
        return {
            "id": "runtime_preflight",
            "label": "Run executable preflight",
            "ui_pane": "启动执行器",
            "reason": "Release and SHA256 are ready. Before starting it as a managed runtime, verify the executable can run on this server.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/runtime-preflight",
        }
    if installed and kernel.get("installed_verified") and preflight and not preflight.get("ok"):
        return {
            "id": "source_runtime_plan",
            "label": "Use source-repo/build fallback",
            "ui_pane": "source-repo 源码参考",
            "reason": "The verified release artifact failed executable preflight on this server. Use source-repo only now, for protocol inspection, local build, or adapter rewrite.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/source-runtime-plan",
            "preflight": preflight,
        }
    if not kernel.get("runtime_registered"):
        return {
            "id": "start_runtime",
            "label": "启动或登记 loopback runtime",
            "ui_pane": "启动执行器",
            "reason": "release/hash 已准备，但 provider 还没有 loopback runtime。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/start-runtime",
        }
    if process.get("pid") and not process.get("running"):
        return {
            "id": "restart_runtime",
            "label": "重启受控 runtime",
            "ui_pane": "日志与停止",
            "reason": "平台记录过受控进程，但当前进程未运行。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/start-runtime",
        }
    if int(routing.get("active_account_count") or 0) <= 0:
        return {
            "id": "import_account",
            "label": "导入真实账号",
            "ui_pane": "授权资源",
            "reason": "执行器和路由准备后，仍需要真实 Web session 或 Agent Provider 账号材料。",
            "primary_api": "/v1/admin/account-onboarding",
        }
    return {
        "id": "live_acceptance",
        "label": "运行真实样本验收",
        "ui_pane": "交付",
        "reason": "路由、runtime 和账号都具备后，需要用真实图片/视频样本确认上游调用与资产入库。",
        "primary_api": "/v1/admin/account-acceptance-suite",
    }


def build_proxy_kernel_runtime_delivery_plan(db: Session, provider_id: str) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    routing = proxy_kernel_routing_plan(db, provider_id)
    materials = build_proxy_kernel_materials_request(db, provider_id)
    go_live = build_proxy_kernel_go_live_checklist(db, provider_id)
    source_repo = proxy_kernel_service.source_repo_status(provider_id)
    installed = kernel.get("installed") if isinstance(kernel.get("installed"), dict) else {}
    process = kernel.get("process") if isinstance(kernel.get("process"), dict) else {}
    default_base_url = kernel.get("runtime_base_url") or proxy_kernel_runtime_default_base_url(provider_id)
    executable_candidates = [
        item
        for item in installed.get("executable_candidates") or []
        if isinstance(item, dict) and item.get("path")
    ] if isinstance(installed, dict) else []
    executable_candidate = executable_candidates[0] if executable_candidates else {}
    artifact_path = str(executable_candidate.get("path") or installed.get("path") or "<verified-artifact-path>")
    expected_sha = str(executable_candidate.get("sha256") or installed.get("expected_sha256") or installed.get("sha256") or "<64-hex-sha256>")
    start_templates = proxy_kernel_runtime_start_templates(
        provider_id,
        artifact_path,
        expected_sha,
        default_base_url,
        str(installed.get("tag_name") or "vX.Y.Z"),
        f"{kernel.get('selection_id') or provider_id} verified release",
    )
    start_payload = start_templates["recommended_payload"]
    install_payload = {
        "tag_name": str(installed.get("tag_name") or "vX.Y.Z"),
        "asset_name": str(installed.get("asset_name") or "<release-asset-name>"),
        "expected_sha256": expected_sha,
        "force": False,
    }
    source_payload = {"ref": "", "force": False}
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    next_step = proxy_kernel_runtime_delivery_next_step(routing=routing, kernel=kernel, source_repo=source_repo)
    route_ready = bool(routing.get("route_config_ready"))
    runtime_ready = bool(kernel.get("runtime_registered") and kernel.get("runtime_loopback_only") and (not process.get("pid") or process.get("running")))
    account_ready = int(routing.get("active_account_count") or 0) > 0
    return {
        "object": "media2api.proxy_kernel.runtime_delivery_plan",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "status": "ready_for_live_acceptance" if route_ready and runtime_ready and account_ready else "action_required",
        "ready_for_live_acceptance": bool(route_ready and runtime_ready and account_ready),
        "next_step": next_step,
        "state": {
            "provider_initialized": bool(routing.get("provider_initialized")),
            "route_config_ready": route_ready,
            "installed": bool(installed),
            "installed_verified": bool(kernel.get("installed_verified")),
            "runtime_registered": bool(kernel.get("runtime_registered")),
            "runtime_loopback_only": bool(kernel.get("runtime_loopback_only")),
            "runtime_preflight_ok": bool(kernel.get("runtime_preflight_ok")),
            "managed_process_configured": bool(process.get("pid")),
            "managed_process_running": bool(process.get("running")),
            "active_account_count": int(routing.get("active_account_count") or 0),
            "source_repo_synced": bool(source_repo.get("exists") and source_repo.get("is_git_repo")),
        },
        "runtime": {
            "preferred_source": "github_release_binary",
            "default_base_url": default_base_url,
            "installed": installed,
            "process": process,
            "source_repo": source_repo,
            "release_required_fields": ["tag_name", "asset_name", "expected_sha256"],
            "start_required_fields": ["command", "base_url", "artifact_path", "expected_sha256"],
            "install_payload_template": install_payload,
            "start_payload_template": start_payload,
            "start_template_id": start_templates.get("recommended_template_id"),
            "start_command_candidates": start_templates.get("candidates", []),
            "start_operator_confirmation_required": bool(start_templates.get("operator_confirmation_required")),
            "runtime_preflight": kernel.get("runtime_preflight") if isinstance(kernel.get("runtime_preflight"), dict) else {},
            "preflight_payload_template": {
                "artifact_path": artifact_path,
                "expected_sha256": expected_sha,
                "timeout_seconds": 8,
            },
            "source_repo_payload_template": source_payload,
        },
        "materials": {
            "account_materials": materials.get("account_materials", {}),
            "runtime_materials": materials.get("runtime_materials", {}),
            "routing_materials": materials.get("routing_materials", {}),
            "validation_materials": materials.get("validation_materials", {}),
            "message_to_user": materials.get("message_to_user", []),
        },
        "routing": routing,
        "go_live": {
            "status": go_live.get("status"),
            "next_step": go_live.get("next_step"),
            "steps": go_live.get("steps", []),
        },
        "commands": {
            "runtime_delivery_plan": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/runtime-delivery-plan",
            "routing_plan": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/routing-plan",
            "apply_routing": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/apply-routing -d '{{\"status\":\"active\",\"enable_mappings\":true,\"priority_offset\":0,\"update_provider_base_url\":true}}'",
            "release_probe": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-probe",
            "install_release": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/install-release -d '{json.dumps(install_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "runtime_preflight": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/runtime-preflight -d '{json.dumps({'artifact_path': artifact_path, 'expected_sha256': expected_sha, 'timeout_seconds': 8}, ensure_ascii=False, separators=(',', ':'))}'",
            "start_runtime": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/start-runtime -d '{json.dumps(start_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "runtime_health_check": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/runtime-health-check -d '{{\"sync_provider_base_url\":true,\"require_running_process\":false,\"fail_on_health_check\":false}}'",
            "source_repo_sync": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/source-repo/sync -d '{json.dumps(source_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "account_guide": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/account-guides/{provider_id}",
        },
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "preferred_runtime_source": "release_binary",
            "source_repo_only_when": "release missing, asset unusable, protocol inspection, local build input, or adapter rewrite reference",
            "managed_runtime_listener": "loopback_only",
            "third_party_public_service": "forbidden",
            "no_fake_account_created": True,
        },
    }


def proxy_kernel_runtime_delivery_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    next_step_counts: dict[str, int] = {}
    for row in rows:
        step_id = str((row.get("next_step") or {}).get("id") or "unknown")
        next_step_counts[step_id] = next_step_counts.get(step_id, 0) + 1
    return {
        "total": len(rows),
        "ready_for_live_acceptance": sum(1 for row in rows if row.get("ready_for_live_acceptance")),
        "route_ready": sum(1 for row in rows if (row.get("state") or {}).get("route_config_ready")),
        "installed": sum(1 for row in rows if (row.get("state") or {}).get("installed")),
        "installed_verified": sum(1 for row in rows if (row.get("state") or {}).get("installed_verified")),
        "runtime_registered": sum(1 for row in rows if (row.get("state") or {}).get("runtime_registered")),
        "process_running": sum(1 for row in rows if (row.get("state") or {}).get("managed_process_running")),
        "active_account": sum(1 for row in rows if int((row.get("state") or {}).get("active_account_count") or 0) > 0),
        "source_repo_synced": sum(1 for row in rows if (row.get("state") or {}).get("source_repo_synced")),
        "next_step_counts": next_step_counts,
    }


def build_proxy_kernel_runtime_delivery_plans(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_runtime_delivery_plan(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.runtime_delivery_plan.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": proxy_kernel_runtime_delivery_summary(rows),
        "data": rows,
        "policy": {
            "read_only": True,
            "release_binary_first": True,
            "source_repo_root": str(settings.source_repo_dir),
            "proxy_kernel_root": str(settings.proxy_kernel_dir),
        },
    }


def proxy_kernel_release_probe_next_step(status: str, asset_count: int, preferred_count: int, dry_run: bool = False) -> dict[str, Any]:
    if dry_run:
        return {
            "id": "probe_release",
            "label": "探测 GitHub release",
            "reason": "当前为 dry_run，只列出将被探测的定型仓库，不访问 GitHub、不下载资产。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-probe",
        }
    if status == "ok" and preferred_count > 0:
        return {
            "id": "install_release",
            "label": "选择候选资产并提供 SHA256",
            "reason": "已找到适合受控 loopback runtime 的 release 资产；安装前必须人工提供 expected_sha256。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/install-release",
        }
    if status == "ok" and asset_count > 0:
        return {
            "id": "inspect_release_assets",
            "label": "人工确认 release 资产",
            "reason": "仓库存在 release 资产，但没有自动命中 Linux/amd64 可执行候选；需要人工确认资产、架构和启动方式。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-probe",
        }
    if status in {"release_without_assets", "no_release"}:
        return {
            "id": "source_repo_reference",
            "label": "同步 source-repo 做协议参考",
            "reason": "当前没有可直接安装的 release 二进制；仅在此情况下使用 source-repo 参考协议、本地构建或 adapter 重写。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/source-repo/sync",
        }
    if status == "failed":
        return {
            "id": "retry_or_source_repo_reference",
            "label": "重试探测或进入源码参考",
            "reason": "release 探测失败；先检查 GitHub 网络/权限，仍不可用时再同步 source-repo。",
            "primary_api": "/v1/admin/proxy-kernels/release-probe-matrix",
        }
    return {
        "id": "probe_release",
        "label": "探测 GitHub release",
        "reason": "尚未获得 release 状态。",
        "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-probe",
    }


def proxy_kernel_release_probe_matrix_row(db: Session, provider_id: str, dry_run: bool = False) -> dict[str, Any]:
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    spec = kernel.get("spec") if isinstance(kernel.get("spec"), dict) else {}
    source_repo = proxy_kernel_service.source_repo_status(provider_id)
    installed = kernel.get("installed") if isinstance(kernel.get("installed"), dict) else {}
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    if dry_run:
        probe = {
            "status": "planned",
            "release": {},
            "assets": [],
            "preferred_assets": [],
            "message": "dry_run=true; no GitHub request was made.",
        }
    else:
        try:
            probe = proxy_kernel_service.probe_release(provider_id)
        except Exception as exc:  # pragma: no cover - defensive envelope for unstable upstream metadata
            probe = {
                "object": "media2api.proxy_kernel.release_probe",
                "provider_id": provider_id,
                "status": "failed",
                "error": exc.__class__.__name__,
                "message": str(exc),
                "repo_url": spec.get("repo_url"),
            }
    assets = [item for item in (probe.get("assets") or []) if isinstance(item, dict)]
    preferred_assets = [item for item in (probe.get("preferred_assets") or []) if isinstance(item, dict)]
    checksum_assets = [
        item for item in assets
        if any(token in str(item.get("name") or "").lower() for token in ("sha256", "checksum", "checksums", ".sig", ".asc"))
    ]
    status = str(probe.get("status") or "unknown")
    next_step = proxy_kernel_release_probe_next_step(status, len(assets), len(preferred_assets), dry_run=dry_run)
    return {
        "object": "media2api.proxy_kernel.release_probe_matrix.item",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "repo": spec.get("repo"),
        "repo_url": spec.get("repo_url"),
        "runtime_kind": spec.get("runtime_kind"),
        "media_scope": spec.get("media_scope"),
        "credential_boundary": spec.get("credential_boundary"),
        "status": status,
        "message": probe.get("message") or probe.get("error") or "",
        "release": probe.get("release") if isinstance(probe.get("release"), dict) else {},
        "asset_count": len(assets),
        "preferred_asset_count": len(preferred_assets),
        "checksum_asset_count": len(checksum_assets),
        "assets": assets,
        "preferred_assets": preferred_assets,
        "checksum_assets": checksum_assets,
        "install_ready": bool(status == "ok" and preferred_assets),
        "hash_required": True,
        "installed": installed,
        "installed_verified": bool(kernel.get("installed_verified")),
        "runtime_registered": bool(kernel.get("runtime_registered")),
        "runtime_base_url": kernel.get("runtime_base_url") or proxy_kernel_runtime_default_base_url(provider_id),
        "source_repo": source_repo,
        "source_repo_fallback": next_step.get("id") in {"source_repo_reference", "retry_or_source_repo_reference"},
        "next_step": next_step,
        "commands": {
            "release_probe": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-probe",
            "install_release": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/install-release -d '{{\"tag_name\":\"vX.Y.Z\",\"asset_name\":\"example-linux-amd64.tar.gz\",\"expected_sha256\":\"64-hex-sha256\"}}'",
            "source_repo_sync": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/source-repo/sync -d '{{\"ref\":\"\",\"force\":false}}'",
        },
        "policy": {
            "official_sdk_api": "forbidden",
            "release_binary_first": True,
            "downloaded": False,
            "source_repo_only_when": "release missing, asset unusable, protocol inspection, local build input, or adapter rewrite reference",
            "managed_runtime_listener": "loopback_only",
        },
    }


def proxy_kernel_release_probe_matrix_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    status_counts: dict[str, int] = {}
    next_step_counts: dict[str, int] = {}
    for row in rows:
        status = str(row.get("status") or "unknown")
        status_counts[status] = status_counts.get(status, 0) + 1
        step_id = str((row.get("next_step") or {}).get("id") or "unknown")
        next_step_counts[step_id] = next_step_counts.get(step_id, 0) + 1
    return {
        "total": len(rows),
        "planned": status_counts.get("planned", 0),
        "ok": status_counts.get("ok", 0),
        "release_without_assets": status_counts.get("release_without_assets", 0),
        "no_release": status_counts.get("no_release", 0),
        "failed": status_counts.get("failed", 0),
        "with_assets": sum(1 for row in rows if int(row.get("asset_count") or 0) > 0),
        "with_preferred_assets": sum(1 for row in rows if int(row.get("preferred_asset_count") or 0) > 0),
        "install_ready": sum(1 for row in rows if row.get("install_ready")),
        "needs_hash": sum(1 for row in rows if row.get("install_ready") and row.get("hash_required")),
        "needs_source_repo_reference": sum(1 for row in rows if row.get("source_repo_fallback")),
        "candidate_asset_total": sum(int(row.get("preferred_asset_count") or 0) for row in rows),
        "status_counts": status_counts,
        "next_step_counts": next_step_counts,
    }


def build_proxy_kernel_release_probe_matrix(db: Session, provider_ids: list[str] | None = None, dry_run: bool = False) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [proxy_kernel_release_probe_matrix_row(db, provider_id, dry_run=dry_run) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.release_probe_matrix",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "dry_run": bool(dry_run),
        "summary": proxy_kernel_release_probe_matrix_summary(rows),
        "data": rows,
        "policy": {
            "read_only": True,
            "release_binary_first": True,
            "hash_required": True,
            "downloaded": False,
            "source_repo_root": str(settings.source_repo_dir),
            "proxy_kernel_root": str(settings.proxy_kernel_dir),
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
        },
    }


PROXY_KERNEL_SHA256_RE = re.compile(r"\b[0-9a-fA-F]{64}\b")
PROXY_KERNEL_CHECKSUM_NAME_TOKENS = ("sha256", "sha256sum", "shasum", "checksum", "checksums")
PROXY_KERNEL_SIGNATURE_SUFFIXES = (".sig", ".asc", ".minisig", ".pem", ".cert")


def proxy_kernel_asset_name(asset: dict[str, Any]) -> str:
    return str(asset.get("name") or "").strip()


def proxy_kernel_normalized_asset_name(value: str) -> str:
    name = str(value or "").strip().strip("\"'")
    name = name.lstrip("*").strip()
    name = name.replace("\\", "/").rsplit("/", 1)[-1]
    if name.startswith("./"):
        name = name[2:]
    return name.lower()


def proxy_kernel_asset_digest_sha256(asset: dict[str, Any]) -> str:
    raw = str(asset.get("digest") or "").strip()
    if not raw:
        return ""
    if raw.lower().startswith("sha256:"):
        raw = raw.split(":", 1)[1].strip()
    match = PROXY_KERNEL_SHA256_RE.fullmatch(raw)
    return match.group(0).lower() if match else ""


def proxy_kernel_is_signature_asset(asset: dict[str, Any]) -> bool:
    lower = proxy_kernel_asset_name(asset).lower()
    return lower.endswith(PROXY_KERNEL_SIGNATURE_SUFFIXES) or "signature" in lower


def proxy_kernel_is_checksum_asset(asset: dict[str, Any]) -> bool:
    lower = proxy_kernel_asset_name(asset).lower()
    if proxy_kernel_is_signature_asset(asset):
        return False
    return any(token in lower for token in PROXY_KERNEL_CHECKSUM_NAME_TOKENS)


def proxy_kernel_implied_checksum_target(source_asset_name: str) -> str:
    name = str(source_asset_name or "").strip()
    lower = name.lower()
    suffixes = (
        ".sha256sum.txt",
        ".sha256sums.txt",
        ".sha256.txt",
        ".sha256sum",
        ".sha256sums",
        ".sha256",
        ".checksum.txt",
        ".checksums.txt",
    )
    for suffix in suffixes:
        if lower.endswith(suffix) and len(name) > len(suffix):
            return name[: -len(suffix)]
    return ""


def proxy_kernel_clean_checksum_filename(value: str) -> str:
    cleaned = str(value or "").strip().strip("\"'")
    cleaned = cleaned.strip(" \t:=()")
    cleaned = cleaned.lstrip("*").strip()
    if cleaned.startswith("./"):
        cleaned = cleaned[2:]
    cleaned = cleaned.replace("\\", "/").rsplit("/", 1)[-1]
    if not cleaned or cleaned in {"-", "."} or PROXY_KERNEL_SHA256_RE.fullmatch(cleaned):
        return ""
    return cleaned


def proxy_kernel_checksum_entry(asset_name: str, expected_sha256: str, source_line: str, source_path: str = "") -> dict[str, Any] | None:
    sha = str(expected_sha256 or "").strip().lower()
    name = proxy_kernel_clean_checksum_filename(asset_name)
    if not name or not PROXY_KERNEL_SHA256_RE.fullmatch(sha):
        return None
    return {
        "asset_name": name,
        "normalized_asset_name": proxy_kernel_normalized_asset_name(name),
        "expected_sha256": sha,
        "source_line": source_line[:240],
        "source_path": source_path,
    }


def proxy_kernel_collect_checksum_json(value: Any, source_path: str = "$") -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    if isinstance(value, dict):
        lowered = {str(key).lower(): raw_value for key, raw_value in value.items()}
        name_value = (
            lowered.get("name")
            or lowered.get("filename")
            or lowered.get("file")
            or lowered.get("asset")
            or lowered.get("path")
        )
        hash_value = (
            lowered.get("sha256")
            or lowered.get("sha256sum")
            or lowered.get("checksum")
            or lowered.get("digest")
            or lowered.get("hash")
        )
        if isinstance(name_value, str) and isinstance(hash_value, str):
            entry = proxy_kernel_checksum_entry(name_value, hash_value, source_path, source_path)
            if entry:
                entries.append(entry)
        for key, item in value.items():
            entries.extend(proxy_kernel_collect_checksum_json(item, f"{source_path}.{key}"))
    elif isinstance(value, list):
        for index, item in enumerate(value):
            entries.extend(proxy_kernel_collect_checksum_json(item, f"{source_path}[{index}]"))
    return entries


def proxy_kernel_parse_checksum_text(text: str, source_asset_name: str) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    implied_target = proxy_kernel_implied_checksum_target(source_asset_name)
    stripped = (text or "").strip()
    if stripped.startswith("{") or stripped.startswith("["):
        try:
            entries.extend(proxy_kernel_collect_checksum_json(json.loads(stripped)))
        except Exception:
            pass
    for line_number, raw_line in enumerate((text or "").splitlines(), start=1):
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue
        bsd = re.search(r"SHA256\s*\((?P<name>[^)]+)\)\s*=\s*(?P<sha>[0-9a-fA-F]{64})", line, flags=re.IGNORECASE)
        if bsd:
            entry = proxy_kernel_checksum_entry(bsd.group("name"), bsd.group("sha"), f"line {line_number}: {line}")
            if entry:
                entries.append(entry)
            continue
        hashes = PROXY_KERNEL_SHA256_RE.findall(line)
        if len(hashes) != 1:
            continue
        sha = hashes[0]
        before, _, after = line.partition(sha)
        filename = ""
        if before.strip():
            filename = before.strip()
        elif after.strip():
            filename = after.strip()
        elif implied_target:
            filename = implied_target
        filename = filename.strip(" \t:=*-")
        if " " in filename:
            filename = filename.split()[0]
        entry = proxy_kernel_checksum_entry(filename, sha, f"line {line_number}: {line}")
        if entry:
            entries.append(entry)
    deduped: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    for entry in entries:
        key = (entry["normalized_asset_name"], entry["expected_sha256"], entry.get("source_path") or entry.get("source_line") or "")
        if key in seen:
            continue
        seen.add(key)
        deduped.append(entry)
    return deduped


def proxy_kernel_download_checksum_asset(asset: dict[str, Any], max_checksum_bytes: int) -> dict[str, Any]:
    name = proxy_kernel_asset_name(asset)
    url = str(asset.get("browser_download_url") or "")
    source = {
        "asset_name": name,
        "status": "skipped",
        "size": asset.get("size"),
        "parsed_count": 0,
        "entries": [],
    }
    if not url:
        return {**source, "status": "failed", "error": "CHECKSUM_ASSET_URL_MISSING"}
    try:
        declared_size = int(asset.get("size") or 0)
    except Exception:
        declared_size = 0
    if declared_size > max_checksum_bytes:
        return {**source, "status": "too_large", "error": "CHECKSUM_ASSET_TOO_LARGE"}
    request = urllib.request.Request(url, headers=proxy_kernel_service.github_headers())
    try:
        with urllib.request.urlopen(request, timeout=20) as response:
            content_length = response.headers.get("Content-Length")
            try:
                if content_length and int(content_length) > max_checksum_bytes:
                    return {**source, "status": "too_large", "error": "CHECKSUM_ASSET_TOO_LARGE"}
            except Exception:
                pass
            data = response.read(max_checksum_bytes + 1)
    except urllib.error.HTTPError as exc:
        return {**source, "status": "failed", "error": "GITHUB_HTTP_ERROR", "status_code": exc.code}
    except Exception as exc:
        return {**source, "status": "failed", "error": exc.__class__.__name__, "message": str(exc)}
    if len(data) > max_checksum_bytes:
        return {**source, "status": "too_large", "error": "CHECKSUM_ASSET_TOO_LARGE"}
    text = data.decode("utf-8", errors="replace")
    entries = proxy_kernel_parse_checksum_text(text, name)
    return {**source, "status": "parsed", "parsed_count": len(entries), "entries": entries}


def proxy_kernel_release_checksum_next_step(
    status: str,
    dry_run: bool,
    resolved_count: int,
    preferred_count: int,
    checksum_count: int,
) -> dict[str, Any]:
    if dry_run:
        return {
            "id": "probe_release",
            "label": "探测 GitHub release",
            "reason": "dry_run=true 只展示计划，不访问 GitHub，也不读取 checksum 文件。",
            "primary_api": "/v1/admin/proxy-kernels/release-checksum-matrix",
        }
    if status == "failed":
        return {
            "id": "retry_release_probe",
            "label": "重试 release 探测",
            "reason": "release 或 checksum 文件读取失败；先确认 GitHub 网络、仓库权限和 release 可见性。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-checksums",
        }
    if status in {"release_without_assets", "no_release"}:
        return {
            "id": "source_repo_reference",
            "label": "同步 source-repo 参考",
            "reason": "当前没有可直接安装的 release 资产；仅在这种情况下进入 source-repo 参考、构建或重写 adapter。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/source-repo/sync",
        }
    if resolved_count:
        return {
            "id": "install_release_with_resolved_sha256",
            "label": "使用已解析 SHA256 安装 release",
            "reason": "checksum 文件已匹配 release 资产；复制 install_payload_template 调用 install-release。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/install-release",
        }
    if preferred_count:
        return {
            "id": "manual_sha256_required",
            "label": "人工确认 SHA256",
            "reason": "找到了候选 runtime 资产，但 release 中没有可匹配的 checksum；必须人工从可信来源提供 SHA256。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/install-release",
        }
    if checksum_count:
        return {
            "id": "inspect_release_assets",
            "label": "人工确认 release 资产",
            "reason": "仓库有 checksum 文件，但没有自动命中 Linux/amd64 runtime 资产；需要人工确认架构、启动方式和文件名。",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-probe",
        }
    return {
        "id": "probe_release",
        "label": "探测或确认 release",
        "reason": "尚未拿到可安装资产与 SHA256 的组合。",
        "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-probe",
    }


def proxy_kernel_release_candidate_sort_key(item: dict[str, Any]) -> tuple[int, int, int, int, int, int, int, int, str]:
    name = str(item.get("asset_name") or item.get("name") or "").lower()
    score = int(item.get("candidate_score") or 0)
    linux = 1 if any(token in name for token in ("linux", "ubuntu", "debian")) else 0
    x64 = 1 if any(token in name for token in ("amd64", "x86_64", "x64")) else 0
    non_docker = 0 if "docker" in name else 1
    non_desktop = 0 if any(token in name for token in ("darwin", "macos", "osx", "windows", "win32", "win64")) else 1
    full_feature = 0 if any(token in name for token in ("no-plugin", "no_plugin", "minimal", "lite")) else 1
    archive = 1 if any(name.endswith(ext) for ext in (".tar.gz", ".tgz", ".zip", ".gz", ".bin", ".exe")) else 0
    return (
        1 if item.get("preferred") else 0,
        score,
        linux,
        x64,
        non_docker,
        non_desktop,
        full_feature,
        archive,
        name,
    )


def proxy_kernel_best_release_candidate(candidates: list[dict[str, Any]], *, require_preferred: bool = False) -> dict[str, Any]:
    selected = [item for item in candidates if isinstance(item, dict)]
    if require_preferred:
        selected = [item for item in selected if item.get("preferred")]
    selected.sort(key=proxy_kernel_release_candidate_sort_key, reverse=True)
    return selected[0] if selected else {}


def build_proxy_kernel_release_checksums(
    db: Session,
    provider_id: str,
    dry_run: bool = False,
    max_checksum_bytes: int = 1024 * 1024,
) -> dict[str, Any]:
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    spec = kernel.get("spec") if isinstance(kernel.get("spec"), dict) else {}
    source_repo = proxy_kernel_service.source_repo_status(provider_id)
    installed = kernel.get("installed") if isinstance(kernel.get("installed"), dict) else {}
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    max_bytes = max(1024, min(int(max_checksum_bytes or 1024 * 1024), 5 * 1024 * 1024))
    if dry_run:
        probe = {
            "status": "planned",
            "release": {},
            "assets": [],
            "preferred_assets": [],
            "message": "dry_run=true; no GitHub request or checksum download was made.",
        }
    else:
        try:
            probe = proxy_kernel_service.probe_release(provider_id)
        except Exception as exc:  # pragma: no cover - defensive envelope for unstable upstream metadata
            probe = {
                "object": "media2api.proxy_kernel.release_probe",
                "provider_id": provider_id,
                "status": "failed",
                "error": exc.__class__.__name__,
                "message": str(exc),
                "repo_url": spec.get("repo_url"),
            }
    assets = [item for item in (probe.get("assets") or []) if isinstance(item, dict)]
    preferred_assets = [item for item in (probe.get("preferred_assets") or []) if isinstance(item, dict)]
    checksum_assets = [item for item in assets if proxy_kernel_is_checksum_asset(item)]
    runtime_assets = [item for item in assets if not proxy_kernel_is_checksum_asset(item) and not proxy_kernel_is_signature_asset(item)]
    checksum_sources = []
    checksums_by_asset: dict[str, list[dict[str, Any]]] = {}
    if not dry_run:
        for asset in checksum_assets:
            source = proxy_kernel_download_checksum_asset(asset, max_bytes)
            checksum_sources.append(source)
            for entry in source.get("entries") or []:
                if not isinstance(entry, dict):
                    continue
                normalized = str(entry.get("normalized_asset_name") or "")
                if not normalized:
                    continue
                checksums_by_asset.setdefault(normalized, []).append({**entry, "source_asset": proxy_kernel_asset_name(asset)})
        for asset in runtime_assets:
            asset_name = proxy_kernel_asset_name(asset)
            sha = proxy_kernel_asset_digest_sha256(asset)
            if not asset_name or not sha:
                continue
            normalized = proxy_kernel_normalized_asset_name(asset_name)
            entry = {
                "normalized_asset_name": normalized,
                "expected_sha256": sha,
                "source_asset": asset_name,
                "source_type": "github_release_asset_digest",
                "source_line": "GitHub Release asset digest",
                "source_digest": str(asset.get("digest") or ""),
            }
            checksums_by_asset.setdefault(normalized, []).append(entry)
            checksum_sources.append({
                "asset_name": asset_name,
                "status": "parsed",
                "source_type": "github_release_asset_digest",
                "size": asset.get("size"),
                "parsed_count": 1,
                "entries": [entry],
            })
    preferred_names = {proxy_kernel_asset_name(item) for item in preferred_assets}
    resolved_candidates = []
    seen_candidate_keys: set[tuple[str, str]] = set()
    release = probe.get("release") if isinstance(probe.get("release"), dict) else {}
    tag_name = str(release.get("tag_name") or "")
    for asset in runtime_assets:
        asset_name = proxy_kernel_asset_name(asset)
        normalized = proxy_kernel_normalized_asset_name(asset_name)
        for entry in checksums_by_asset.get(normalized, []):
            sha = str(entry.get("expected_sha256") or "").lower()
            key = (asset_name, sha)
            if key in seen_candidate_keys:
                continue
            seen_candidate_keys.add(key)
            install_payload = {
                "tag_name": tag_name,
                "asset_name": asset_name,
                "expected_sha256": sha,
                "force": False,
            }
            install_payload_json = json.dumps(install_payload, ensure_ascii=False, separators=(",", ":"))
            resolved_candidates.append({
                "provider_id": provider_id,
                "selection_id": kernel.get("selection_id"),
                "tag_name": tag_name,
                "asset_name": asset_name,
                "expected_sha256": sha,
                "source_asset": entry.get("source_asset"),
                "source_type": entry.get("source_type") or "checksum_asset",
                "source_digest": entry.get("source_digest") or "",
                "source_line": entry.get("source_line"),
                "candidate_score": int(asset.get("candidate_score") or 0),
                "candidate_reason": asset.get("candidate_reason") or "",
                "preferred": asset_name in preferred_names,
                "install_payload_template": install_payload,
                "install_command": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/install-release -d '{install_payload_json}'",
            })
    resolved_asset_names = {item["asset_name"] for item in resolved_candidates}
    unresolved_preferred_assets = [
        {
            "asset_name": proxy_kernel_asset_name(asset),
            "candidate_score": int(asset.get("candidate_score") or 0),
            "candidate_reason": asset.get("candidate_reason") or "",
            "manual_install_payload_template": {
                "tag_name": tag_name,
                "asset_name": proxy_kernel_asset_name(asset),
                "expected_sha256": "64-hex-sha256",
                "force": False,
            },
        }
        for asset in preferred_assets
        if proxy_kernel_asset_name(asset) not in resolved_asset_names
    ]
    resolved_candidates.sort(key=proxy_kernel_release_candidate_sort_key, reverse=True)
    unresolved_preferred_assets.sort(key=proxy_kernel_release_candidate_sort_key, reverse=True)
    status = str(probe.get("status") or "unknown")
    resolved_preferred_count = sum(1 for item in resolved_candidates if item.get("preferred"))
    next_step = proxy_kernel_release_checksum_next_step(
        status,
        dry_run=bool(dry_run),
        resolved_count=resolved_preferred_count,
        preferred_count=len(preferred_assets),
        checksum_count=len(checksum_assets),
    )
    return {
        "object": "media2api.proxy_kernel.release_checksums",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "repo": spec.get("repo"),
        "repo_url": spec.get("repo_url"),
        "dry_run": bool(dry_run),
        "status": status,
        "message": probe.get("message") or probe.get("error") or "",
        "release": release,
        "asset_count": len(assets),
        "runtime_asset_count": len(runtime_assets),
        "preferred_asset_count": len(preferred_assets),
        "checksum_asset_count": len(checksum_assets),
        "github_asset_digest_count": sum(1 for item in runtime_assets if proxy_kernel_asset_digest_sha256(item)),
        "checksum_sources": checksum_sources,
        "resolved_sha256_candidates": resolved_candidates,
        "resolved_sha256_candidate_count": len(resolved_candidates),
        "install_ready_candidate_count": resolved_preferred_count,
        "resolved_preferred_asset_count": resolved_preferred_count,
        "unresolved_preferred_assets": unresolved_preferred_assets,
        "hash_required": True,
        "installed": installed,
        "installed_verified": bool(kernel.get("installed_verified")),
        "runtime_registered": bool(kernel.get("runtime_registered")),
        "source_repo": source_repo,
        "source_repo_fallback": next_step.get("id") == "source_repo_reference",
        "next_step": next_step,
        "commands": {
            "release_probe": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-probe",
            "release_checksums": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-checksums",
            "install_release": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/install-release -d '{{\"tag_name\":\"vX.Y.Z\",\"asset_name\":\"example-linux-amd64.tar.gz\",\"expected_sha256\":\"64-hex-sha256\"}}'",
            "source_repo_sync": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/source-repo/sync -d '{{\"ref\":\"\",\"force\":false}}'",
        },
        "policy": {
            "read_only": True,
            "release_binary_first": True,
            "hash_required": True,
            "downloaded_binaries": False,
            "checksum_download_only": not bool(dry_run),
            "max_checksum_bytes": max_bytes,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "source_repo_only_when": "release missing, asset unusable, protocol inspection, local build input, or adapter rewrite reference",
        },
    }


def proxy_kernel_release_checksum_matrix_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    status_counts: dict[str, int] = {}
    next_step_counts: dict[str, int] = {}
    for row in rows:
        status = str(row.get("status") or "unknown")
        status_counts[status] = status_counts.get(status, 0) + 1
        step_id = str((row.get("next_step") or {}).get("id") or "unknown")
        next_step_counts[step_id] = next_step_counts.get(step_id, 0) + 1
    return {
        "total": len(rows),
        "planned": status_counts.get("planned", 0),
        "ok": status_counts.get("ok", 0),
        "release_without_assets": status_counts.get("release_without_assets", 0),
        "no_release": status_counts.get("no_release", 0),
        "failed": status_counts.get("failed", 0),
        "with_checksum_assets": sum(1 for row in rows if int(row.get("checksum_asset_count") or 0) > 0),
        "with_github_asset_digests": sum(1 for row in rows if int(row.get("github_asset_digest_count") or 0) > 0),
        "install_ready_candidates": sum(int(row.get("install_ready_candidate_count") or 0) for row in rows),
        "rows_with_install_ready_candidates": sum(1 for row in rows if int(row.get("install_ready_candidate_count") or 0) > 0),
        "manual_sha256_required": sum(1 for row in rows if (row.get("next_step") or {}).get("id") == "manual_sha256_required"),
        "source_repo_reference": sum(1 for row in rows if row.get("source_repo_fallback")),
        "preferred_assets_total": sum(int(row.get("preferred_asset_count") or 0) for row in rows),
        "resolved_preferred_assets": sum(int(row.get("resolved_preferred_asset_count") or 0) for row in rows),
        "status_counts": status_counts,
        "next_step_counts": next_step_counts,
    }


def build_proxy_kernel_release_checksum_matrix(
    db: Session,
    provider_ids: list[str] | None = None,
    dry_run: bool = False,
    max_checksum_bytes: int = 1024 * 1024,
) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [
        build_proxy_kernel_release_checksums(db, provider_id, dry_run=dry_run, max_checksum_bytes=max_checksum_bytes)
        for provider_id in selected
    ]
    max_bytes = max(1024, min(int(max_checksum_bytes or 1024 * 1024), 5 * 1024 * 1024))
    return {
        "object": "media2api.proxy_kernel.release_checksum_matrix",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "dry_run": bool(dry_run),
        "summary": proxy_kernel_release_checksum_matrix_summary(rows),
        "data": rows,
        "policy": {
            "read_only": True,
            "release_binary_first": True,
            "hash_required": True,
            "downloaded_binaries": False,
            "checksum_download_only": not bool(dry_run),
            "max_checksum_bytes": max_bytes,
            "source_repo_root": str(settings.source_repo_dir),
            "proxy_kernel_root": str(settings.proxy_kernel_dir),
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
        },
    }


def proxy_kernel_select_release_install_candidate(
    candidates: list[dict[str, Any]],
    asset_name: str = "",
    expected_sha256: str = "",
    tag_name: str = "",
    source_asset: str = "",
    allow_non_preferred: bool = False,
) -> dict[str, Any] | None:
    selected = [item for item in candidates if isinstance(item, dict)]
    if asset_name:
        selected = [item for item in selected if str(item.get("asset_name") or "") == asset_name]
    if expected_sha256:
        selected = [item for item in selected if str(item.get("expected_sha256") or "").lower() == expected_sha256.lower()]
    if tag_name:
        selected = [item for item in selected if str(item.get("tag_name") or "") == tag_name]
    if source_asset:
        selected = [item for item in selected if str(item.get("source_asset") or "") == source_asset]
    preferred = [item for item in selected if item.get("preferred")]
    if preferred:
        selected = preferred
    elif selected and not allow_non_preferred:
        return None
    best = proxy_kernel_best_release_candidate(selected)
    return best or None


def build_proxy_kernel_release_candidate_install(
    db: Session,
    provider_id: str,
    req: ProxyKernelReleaseCandidateInstallRequest,
) -> dict[str, Any]:
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    max_bytes = max(1024, min(int(req.max_checksum_bytes or 1024 * 1024), 5 * 1024 * 1024))
    should_resolve = bool(req.resolve_release or not req.dry_run)
    if not should_resolve:
        return {
            "object": "media2api.proxy_kernel.release_candidate_install",
            "generated_at": datetime.utcnow().isoformat() + "Z",
            "provider_id": provider_id,
            "selection_id": kernel.get("selection_id"),
            "dry_run": True,
            "resolved_release": False,
            "status": "planned",
            "message": "dry_run=true and resolve_release=false; no GitHub request, binary download, or install was performed.",
            "candidate": {},
            "install_payload_template": {
                "asset_name": req.asset_name or "release-asset-linux-amd64.tar.gz",
                "tag_name": req.tag_name or "vX.Y.Z",
                "expected_sha256": req.expected_sha256 or "64-hex-sha256",
                "force": bool(req.force),
            },
            "next_step": {
                "id": "resolve_release_checksums",
                "label": "读取 Hash 候选",
                "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-checksums",
            },
            "commands": {
                "release_checksums": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-checksums",
            },
            "policy": {
                "read_only": True,
                "release_binary_first": True,
                "hash_required": True,
                "downloaded_binaries": False,
                "official_sdk_api": "forbidden",
                "third_party_public_service": "forbidden",
                "managed_runtime_listener": "loopback_only",
            },
        }
    checksums = build_proxy_kernel_release_checksums(db, provider_id, dry_run=False, max_checksum_bytes=max_bytes)
    candidates = [item for item in checksums.get("resolved_sha256_candidates") or [] if isinstance(item, dict)]
    candidate = proxy_kernel_select_release_install_candidate(
        candidates,
        asset_name=req.asset_name.strip(),
        expected_sha256=req.expected_sha256.strip().lower(),
        tag_name=req.tag_name.strip(),
        source_asset=req.source_asset.strip(),
        allow_non_preferred=bool(req.allow_non_preferred),
    )
    if not candidate:
        status = "candidate_not_found"
        if candidates and not req.allow_non_preferred and not any(item.get("preferred") for item in candidates):
            status = "non_preferred_candidate_requires_override"
        response = {
            "object": "media2api.proxy_kernel.release_candidate_install",
            "generated_at": datetime.utcnow().isoformat() + "Z",
            "provider_id": provider_id,
            "selection_id": kernel.get("selection_id"),
            "dry_run": bool(req.dry_run),
            "resolved_release": True,
            "status": status,
            "message": "No checksum-resolved preferred release asset matched the requested filters.",
            "release_checksums": checksums,
            "candidate": {},
            "install_payload_template": {},
            "policy": {
                "read_only": bool(req.dry_run),
                "release_binary_first": True,
                "hash_required": True,
                "downloaded_binaries": False,
                "official_sdk_api": "forbidden",
                "third_party_public_service": "forbidden",
                "managed_runtime_listener": "loopback_only",
            },
        }
        if req.dry_run:
            return response
        raise ValueError(status.upper())
    install_payload = {
        "tag_name": candidate.get("tag_name") or None,
        "asset_name": candidate.get("asset_name"),
        "expected_sha256": candidate.get("expected_sha256"),
        "force": bool(req.force),
    }
    install_command = f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/install-release -d '{json.dumps(install_payload, ensure_ascii=False, separators=(',', ':'))}'"
    if req.dry_run:
        return {
            "object": "media2api.proxy_kernel.release_candidate_install",
            "generated_at": datetime.utcnow().isoformat() + "Z",
            "provider_id": provider_id,
            "selection_id": kernel.get("selection_id"),
            "dry_run": True,
            "resolved_release": True,
            "status": "installable",
            "message": "A checksum-resolved release asset was selected. Set dry_run=false to download and verify it.",
            "release_checksums": checksums,
            "candidate": candidate,
            "install_payload_template": install_payload,
            "commands": {
                "install_release": install_command,
                "release_checksums": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-checksums",
            },
            "policy": {
                "read_only": True,
                "release_binary_first": True,
                "hash_required": True,
                "downloaded_binaries": False,
                "official_sdk_api": "forbidden",
                "third_party_public_service": "forbidden",
                "managed_runtime_listener": "loopback_only",
            },
        }
    install_result = proxy_kernel_service.install_release(
        provider_id=provider_id,
        expected_sha256=str(candidate.get("expected_sha256") or ""),
        asset_name=str(candidate.get("asset_name") or ""),
        tag_name=str(candidate.get("tag_name") or "") or None,
        force=bool(req.force),
    )
    return {
        "object": "media2api.proxy_kernel.release_candidate_install",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "dry_run": False,
        "resolved_release": True,
        "status": "installed",
        "message": "Checksum-resolved release asset was downloaded, SHA256-verified, and recorded.",
        "release_checksums": checksums,
        "candidate": candidate,
        "install_payload_template": install_payload,
        "install": install_result.get("install") if isinstance(install_result, dict) else {},
        "install_result": install_result,
        "policy": {
            "read_only": False,
            "release_binary_first": True,
            "hash_required": True,
            "downloaded_binaries": True,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
        },
    }


def proxy_kernel_release_candidate_install_matrix_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    status_counts: dict[str, int] = {}
    for row in rows:
        status = str(row.get("status") or "unknown")
        status_counts[status] = status_counts.get(status, 0) + 1
    return {
        "total": len(rows),
        "planned": status_counts.get("planned", 0),
        "installable": status_counts.get("installable", 0),
        "installed": status_counts.get("installed", 0),
        "candidate_not_found": status_counts.get("candidate_not_found", 0),
        "non_preferred_candidate_requires_override": status_counts.get("non_preferred_candidate_requires_override", 0),
        "failed": status_counts.get("failed", 0),
        "resolved_release": sum(1 for row in rows if row.get("resolved_release")),
        "downloaded_binaries": sum(1 for row in rows if (row.get("policy") or {}).get("downloaded_binaries")),
        "status_counts": status_counts,
    }


def build_proxy_kernel_release_candidate_install_matrix(
    db: Session,
    req: ProxyKernelReleaseCandidateBulkInstallRequest,
) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, req.provider_ids)
    rows: list[dict[str, Any]] = []
    for provider_id in selected:
        single_req = ProxyKernelReleaseCandidateInstallRequest(
            force=bool(req.force),
            dry_run=bool(req.dry_run),
            resolve_release=bool(req.resolve_release),
            allow_non_preferred=bool(req.allow_non_preferred),
            max_checksum_bytes=int(req.max_checksum_bytes or 1024 * 1024),
        )
        try:
            rows.append(build_proxy_kernel_release_candidate_install(db, provider_id, single_req))
        except Exception as exc:
            if not req.continue_on_error:
                raise
            rows.append({
                "object": "media2api.proxy_kernel.release_candidate_install",
                "generated_at": datetime.utcnow().isoformat() + "Z",
                "provider_id": provider_id,
                "dry_run": bool(req.dry_run),
                "resolved_release": bool(req.resolve_release),
                "status": "failed",
                "error": exc.__class__.__name__,
                "message": str(exc),
                "candidate": {},
                "install_payload_template": {},
                "policy": {
                    "read_only": bool(req.dry_run),
                    "release_binary_first": True,
                    "hash_required": True,
                    "downloaded_binaries": False,
                    "official_sdk_api": "forbidden",
                    "third_party_public_service": "forbidden",
                    "managed_runtime_listener": "loopback_only",
                },
            })
    return {
        "object": "media2api.proxy_kernel.release_candidate_install_matrix",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "dry_run": bool(req.dry_run),
        "resolve_release": bool(req.resolve_release),
        "summary": proxy_kernel_release_candidate_install_matrix_summary(rows),
        "data": rows,
        "policy": {
            "read_only": bool(req.dry_run),
            "release_binary_first": True,
            "hash_required": True,
            "downloaded_binaries": any((row.get("policy") or {}).get("downloaded_binaries") for row in rows),
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "default_mode": "dry_run_planning",
        },
    }


def proxy_kernel_runtime_acquisition_next_action(
    *,
    kernel: dict[str, Any],
    release_state: dict[str, Any],
    source_repo: dict[str, Any],
    resolve_release: bool,
) -> dict[str, Any]:
    installed = kernel.get("installed") if isinstance(kernel.get("installed"), dict) else {}
    runtime_registered = bool(kernel.get("runtime_registered") and kernel.get("runtime_loopback_only"))
    source_ready = bool(source_repo.get("exists") and source_repo.get("is_git_repo"))
    installed_verified = bool(kernel.get("installed_verified"))
    install_ready = int(release_state.get("install_ready_candidate_count") or 0) > 0
    preferred_assets = int(release_state.get("preferred_asset_count") or 0)
    source_fallback = bool(release_state.get("source_repo_fallback"))
    release_status = str(release_state.get("status") or "planned")
    if runtime_registered:
        return {
            "id": "runtime_registered",
            "label": "Runtime registered",
            "reason": "A loopback runtime is already registered. Continue with account import, health check, and live acceptance.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/runtime-health-check",
        }
    if installed and installed_verified:
        preflight = kernel.get("runtime_preflight") if isinstance(kernel.get("runtime_preflight"), dict) else {}
        if not preflight:
            return {
                "id": "runtime_preflight",
                "label": "Run executable preflight",
                "reason": "A fixed release artifact is installed. Verify the extracted executable can run on this server before starting it.",
                "primary_api": "/v1/admin/proxy-kernels/{provider_id}/runtime-preflight",
            }
        if not preflight.get("ok"):
            if not source_ready:
                return {
                    "id": "source_repo_reference",
                    "label": "Sync source-repo after failed preflight",
                    "reason": "The verified release artifact failed executable preflight and no source checkout is present yet. Sync source-repo first, then inspect the source runtime plan.",
                    "primary_api": "/v1/admin/proxy-kernels/{provider_id}/source-repo/sync",
                    "follow_up_api": "/v1/admin/proxy-kernels/{provider_id}/source-runtime-plan",
                    "preflight": preflight,
                }
            return {
                "id": "source_runtime_plan",
                "label": "Use source-repo/build fallback",
                "reason": "The installed release artifact failed executable preflight. Source checkout is now allowed for build/reference or adapter rewrite.",
                "primary_api": "/v1/admin/proxy-kernels/{provider_id}/source-runtime-plan",
                "preflight": preflight,
            }
        return {
            "id": "start_runtime",
            "label": "Start verified runtime",
            "reason": "A fixed release artifact is installed, SHA256-verified, and executable preflight passed.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/start-runtime",
        }
    if install_ready:
        return {
            "id": "install_release_candidate",
            "label": "Install resolved release binary",
            "reason": "A release asset has a matching SHA256 candidate. Install it before starting runtime.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/install-release-candidate",
        }
    if not resolve_release:
        return {
            "id": "resolve_release",
            "label": "Resolve release and checksum",
            "reason": "Default inspection is offline. Set resolve_release=true to read GitHub Release metadata and small checksum files.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/runtime-acquisition-plan?resolve_release=true",
        }
    if preferred_assets:
        return {
            "id": "manual_sha256_required",
            "label": "Provide SHA256 for release asset",
            "reason": "A likely runtime asset exists, but no matching checksum file was found. Provide a trusted SHA256 manually.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/install-release",
        }
    if source_ready:
        return {
            "id": "source_runtime_plan",
            "label": "Inspect source runtime plan",
            "reason": "A source checkout is already present. Inspect dependency, build, and launcher candidates before running anything.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/source-runtime-plan",
        }
    if source_fallback or release_status in {"ok", "release_without_assets", "no_release"}:
        return {
            "id": "source_repo_reference",
            "label": "Use source-repo reference path",
            "reason": "No installable Linux/x64 release binary was found. Source checkout is now allowed for protocol inspection, build input, or adapter rewrite.",
            "primary_api": "/v1/admin/proxy-kernels/{provider_id}/source-repo/sync",
        }
    return {
        "id": "inspect_release_assets",
        "label": "Inspect release assets manually",
        "reason": "Release metadata did not produce a directly installable runtime candidate. Confirm whether an asset can be used or move to source-repo only if needed.",
        "primary_api": "/v1/admin/proxy-kernels/{provider_id}/release-checksums",
    }


def build_proxy_kernel_runtime_acquisition_plan(
    db: Session,
    provider_id: str,
    *,
    resolve_release: bool = False,
    max_checksum_bytes: int = 1024 * 1024,
) -> dict[str, Any]:
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    contract = build_proxy_kernel_runtime_contract(db, provider_id)
    source_repo = proxy_kernel_service.source_repo_status(provider_id)
    release_state = build_proxy_kernel_release_checksums(
        db,
        provider_id,
        dry_run=not bool(resolve_release),
        max_checksum_bytes=max_checksum_bytes,
    )
    next_action = proxy_kernel_runtime_acquisition_next_action(
        kernel=kernel,
        release_state=release_state,
        source_repo=source_repo,
        resolve_release=bool(resolve_release),
    )
    source_repo_allowed = next_action.get("id") in {"source_repo_reference", "source_runtime_plan"} or bool(source_repo.get("is_git_repo"))
    candidates = [item for item in release_state.get("resolved_sha256_candidates") or [] if isinstance(item, dict)]
    unresolved_preferred = [item for item in release_state.get("unresolved_preferred_assets") or [] if isinstance(item, dict)]
    preferred_candidate = proxy_kernel_best_release_candidate(candidates, require_preferred=True)
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    provider_path = f"/v1/admin/proxy-kernels/{provider_id}"
    return {
        "object": "media2api.proxy_kernel.runtime_acquisition_plan",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "repo": (kernel.get("spec") or {}).get("repo"),
        "repo_url": (kernel.get("spec") or {}).get("repo_url"),
        "resolve_release": bool(resolve_release),
        "status": "ready_to_start" if next_action.get("id") in {"runtime_registered", "start_runtime"} else "action_required",
        "next_action": next_action,
        "decision": {
            "preferred_path": "release_binary",
            "actual_path": "source_repo_reference" if source_repo_allowed and next_action.get("id") in {"source_repo_reference", "source_runtime_plan"} else "release_binary",
            "source_repo_allowed_now": bool(source_repo_allowed),
            "source_repo_reason": "Allowed only because release binary is missing/insufficient or a checkout already exists for inspection." if source_repo_allowed else "Not allowed yet. Resolve Release first and prefer a fixed binary when possible.",
            "requires_manual_sha256": next_action.get("id") == "manual_sha256_required",
            "can_install_resolved_release": bool(preferred_candidate),
            "runtime_preflight_ok": bool(kernel.get("runtime_preflight_ok")),
            "downloaded_binaries": False,
            "synced_source_repo": False,
        },
        "release": {
            "status": release_state.get("status"),
            "release": release_state.get("release") if isinstance(release_state.get("release"), dict) else {},
            "asset_count": int(release_state.get("asset_count") or 0),
            "runtime_asset_count": int(release_state.get("runtime_asset_count") or 0),
            "preferred_asset_count": int(release_state.get("preferred_asset_count") or 0),
            "checksum_asset_count": int(release_state.get("checksum_asset_count") or 0),
            "github_asset_digest_count": int(release_state.get("github_asset_digest_count") or 0),
            "install_ready_candidate_count": int(release_state.get("install_ready_candidate_count") or 0),
            "preferred_candidate": preferred_candidate,
            "unresolved_preferred_assets": unresolved_preferred,
            "install_payload_template": preferred_candidate.get("install_payload_template") or (unresolved_preferred[0].get("manual_install_payload_template") if unresolved_preferred else {}),
            "release_checksums": release_state,
        },
        "source_repo": {
            "allowed_now": bool(source_repo_allowed),
            "status": source_repo,
            "sync_payload_template": {"ref": "", "force": False},
            "runtime_plan_api": f"{provider_path}/source-runtime-plan",
        },
        "runtime_contract": {
            "contract_ready": bool(contract.get("contract_ready")),
            "contract_kind": (contract.get("adapter_contract") or {}).get("contract_kind"),
            "submit_method": (contract.get("adapter_contract") or {}).get("submit_method"),
            "health_endpoint": (contract.get("adapter_contract") or {}).get("health_endpoint"),
            "endpoints": (contract.get("adapter_contract") or {}).get("endpoints") or {},
            "image_operations": (contract.get("adapter_contract") or {}).get("image_operations") or [],
            "video_operations": (contract.get("adapter_contract") or {}).get("video_operations") or [],
            "auth_headers": (contract.get("auth_contract") or {}).get("header_names") or {},
            "standard_payload_fields": (contract.get("adapter_contract") or {}).get("standard_payload_fields") or [],
        },
        "state": {
            "installed_verified": bool(kernel.get("installed_verified")),
            "runtime_preflight": kernel.get("runtime_preflight") if isinstance(kernel.get("runtime_preflight"), dict) else {},
            "runtime_preflight_ok": bool(kernel.get("runtime_preflight_ok")),
            "runtime_registered": bool(kernel.get("runtime_registered")),
            "runtime_loopback_only": bool(kernel.get("runtime_loopback_only")),
            "runtime_base_url": kernel.get("runtime_base_url") or proxy_kernel_runtime_default_base_url(provider_id),
            "process": kernel.get("process") if isinstance(kernel.get("process"), dict) else {},
            "source_repo_synced": bool(source_repo.get("exists") and source_repo.get("is_git_repo")),
        },
        "commands": {
            "inspect": f"curl -H \"Authorization: Bearer {admin_key}\" \"{base}{provider_path}/runtime-acquisition-plan?resolve_release=false\"",
            "resolve_release": f"curl -H \"Authorization: Bearer {admin_key}\" \"{base}{provider_path}/runtime-acquisition-plan?resolve_release=true\"",
            "release_checksums": f"curl -H \"Authorization: Bearer {admin_key}\" \"{base}{provider_path}/release-checksums\"",
            "install_release_candidate": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}{provider_path}/install-release-candidate -d '{{\"dry_run\":false,\"resolve_release\":true}}'",
            "manual_install_release": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}{provider_path}/install-release -d '{{\"tag_name\":\"vX.Y.Z\",\"asset_name\":\"example-linux-amd64.tar.gz\",\"expected_sha256\":\"64-hex-sha256\"}}'",
            "runtime_preflight": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}{provider_path}/runtime-preflight -d '{{\"timeout_seconds\":8}}'",
            "source_repo_sync": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}{provider_path}/source-repo/sync -d '{{\"ref\":\"\",\"force\":false}}'",
            "source_runtime_plan": f"curl -H \"Authorization: Bearer {admin_key}\" {base}{provider_path}/source-runtime-plan",
        },
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "downloaded_binaries": False,
            "synced_source_repo": False,
            "checksum_download_only": bool(resolve_release),
            "max_checksum_bytes": max(1024, min(int(max_checksum_bytes or 1024 * 1024), 5 * 1024 * 1024)),
            "managed_runtime_listener": "loopback_only",
            "third_party_public_service": "forbidden",
        },
    }


def proxy_kernel_runtime_acquisition_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    action_counts: dict[str, int] = {}
    for row in rows:
        action = str((row.get("next_action") or {}).get("id") or "unknown")
        action_counts[action] = action_counts.get(action, 0) + 1
    return {
        "total": len(rows),
        "ready_to_start": sum(1 for row in rows if row.get("status") == "ready_to_start"),
        "can_install_resolved_release": sum(1 for row in rows if (row.get("decision") or {}).get("can_install_resolved_release")),
        "requires_manual_sha256": sum(1 for row in rows if (row.get("decision") or {}).get("requires_manual_sha256")),
        "source_repo_allowed_now": sum(1 for row in rows if (row.get("decision") or {}).get("source_repo_allowed_now")),
        "needs_runtime_preflight": sum(1 for row in rows if (row.get("next_action") or {}).get("id") == "runtime_preflight"),
        "runtime_preflight_failed": sum(1 for row in rows if (row.get("state") or {}).get("runtime_preflight") and not (row.get("state") or {}).get("runtime_preflight_ok")),
        "runtime_registered": sum(1 for row in rows if (row.get("state") or {}).get("runtime_registered")),
        "source_repo_synced": sum(1 for row in rows if (row.get("state") or {}).get("source_repo_synced")),
        "next_action_counts": action_counts,
    }


def build_proxy_kernel_runtime_acquisition_plans(
    db: Session,
    provider_ids: list[str] | None = None,
    *,
    resolve_release: bool = False,
    max_checksum_bytes: int = 1024 * 1024,
) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [
        build_proxy_kernel_runtime_acquisition_plan(
            db,
            provider_id,
            resolve_release=resolve_release,
            max_checksum_bytes=max_checksum_bytes,
        )
        for provider_id in selected
    ]
    return {
        "object": "media2api.proxy_kernel.runtime_acquisition_plan.list",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "resolve_release": bool(resolve_release),
        "summary": proxy_kernel_runtime_acquisition_summary(rows),
        "data": rows,
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "downloaded_binaries": False,
            "synced_source_repo": False,
            "managed_runtime_listener": "loopback_only",
        },
    }


def proxy_kernel_source_repo_sync_matrix_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    status_counts: dict[str, int] = {}
    for row in rows:
        status = str(row.get("status") or "unknown")
        status_counts[status] = status_counts.get(status, 0) + 1
    return {
        "total": len(rows),
        "planned": status_counts.get("planned", 0),
        "synced": status_counts.get("synced", 0),
        "skipped": status_counts.get("skipped", 0),
        "failed": status_counts.get("failed", 0),
        "needs_release_resolution": status_counts.get("needs_release_resolution", 0),
        "source_repo_ready": sum(1 for row in rows if (row.get("source_repo_after") or row.get("source_repo_before") or {}).get("is_git_repo")),
        "status_counts": status_counts,
    }


def proxy_kernel_source_repo_sync_decision(
    *,
    kernel: dict[str, Any],
    release_state: dict[str, Any],
    source_repo: dict[str, Any],
    only_when_needed: bool,
    resolve_release: bool,
) -> dict[str, Any]:
    if not only_when_needed:
        return {
            "should_sync": True,
            "reason": "source-repo sync was explicitly requested.",
            "next_action": {},
        }
    if not resolve_release:
        return {
            "should_sync": False,
            "reason": "resolve_release=false; source-repo need was not evaluated.",
            "next_action": {},
        }
    next_action = proxy_kernel_runtime_acquisition_next_action(
        kernel=kernel,
        release_state=release_state,
        source_repo=source_repo,
        resolve_release=True,
    )
    if next_action.get("id") == "source_repo_reference":
        return {
            "should_sync": True,
            "reason": str(next_action.get("reason") or "source-repo is now the required fallback path."),
            "next_action": next_action,
        }
    if release_state.get("source_repo_fallback"):
        return {
            "should_sync": True,
            "reason": "release has no installable asset; source-repo is the fallback.",
            "next_action": next_action,
        }
    next_step = release_state.get("next_step") if isinstance(release_state.get("next_step"), dict) else {}
    return {
        "should_sync": False,
        "reason": str(next_action.get("reason") or next_step.get("reason") or next_step.get("id") or "release path is still preferred"),
        "next_action": next_action,
    }


def build_proxy_kernel_source_repo_sync_matrix(
    db: Session,
    req: ProxyKernelBulkSourceRepoSyncRequest,
) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, req.provider_ids)
    rows: list[dict[str, Any]] = []
    for provider_id in selected:
        source_before = proxy_kernel_service.source_repo_status(provider_id)
        release_state: dict[str, Any] = {}
        should_sync = True
        skip_reason = ""
        sync_decision: dict[str, Any] = {}
        try:
            if req.only_when_needed:
                if req.resolve_release:
                    release_state = build_proxy_kernel_release_checksums(db, provider_id, dry_run=False)
                    sync_decision = proxy_kernel_source_repo_sync_decision(
                        kernel=proxy_kernel_service.kernel_summary(db, provider_id),
                        release_state=release_state,
                        source_repo=source_before,
                        only_when_needed=True,
                        resolve_release=True,
                    )
                    should_sync = bool(sync_decision.get("should_sync"))
                    skip_reason = str(sync_decision.get("reason") or "")
                else:
                    sync_decision = proxy_kernel_source_repo_sync_decision(
                        kernel={},
                        release_state={},
                        source_repo=source_before,
                        only_when_needed=True,
                        resolve_release=False,
                    )
                    should_sync = bool(sync_decision.get("should_sync"))
                    skip_reason = str(sync_decision.get("reason") or "")
            if req.dry_run:
                status = "planned" if should_sync else ("needs_release_resolution" if req.only_when_needed and not req.resolve_release else "skipped")
                rows.append({
                    "object": "media2api.proxy_kernel.source_repo_sync",
                    "provider_id": provider_id,
                    "dry_run": True,
                    "status": status,
                    "will_sync": bool(should_sync),
                    "reason": str((sync_decision.get("reason") if sync_decision else "") or ("release has no installable asset; source-repo is the fallback." if should_sync else skip_reason)),
                    "source_repo_before": source_before,
                    "source_repo_after": source_before,
                    "runtime_acquisition_next_action": sync_decision.get("next_action") if sync_decision else {},
                    "release_state": {
                        "status": release_state.get("status"),
                        "next_step": release_state.get("next_step"),
                        "source_repo_fallback": release_state.get("source_repo_fallback"),
                        "preferred_asset_count": release_state.get("preferred_asset_count"),
                        "install_ready_candidate_count": release_state.get("install_ready_candidate_count"),
                    } if release_state else {},
                })
                continue
            if not should_sync:
                rows.append({
                    "object": "media2api.proxy_kernel.source_repo_sync",
                    "provider_id": provider_id,
                    "dry_run": False,
                    "status": "skipped",
                    "will_sync": False,
                    "reason": skip_reason,
                    "source_repo_before": source_before,
                    "source_repo_after": source_before,
                    "runtime_acquisition_next_action": sync_decision.get("next_action") if sync_decision else {},
                    "release_state": {
                        "status": release_state.get("status"),
                        "next_step": release_state.get("next_step"),
                        "source_repo_fallback": release_state.get("source_repo_fallback"),
                        "preferred_asset_count": release_state.get("preferred_asset_count"),
                        "install_ready_candidate_count": release_state.get("install_ready_candidate_count"),
                    } if release_state else {},
                })
                continue
            source_after = proxy_kernel_service.sync_source_repo(provider_id, ref=req.ref, force=req.force)
            rows.append({
                "object": "media2api.proxy_kernel.source_repo_sync",
                "provider_id": provider_id,
                "dry_run": False,
                "status": "synced",
                "will_sync": True,
                "reason": str((sync_decision.get("reason") if sync_decision else "") or "source-repo synced because release binary is missing or insufficient."),
                "source_repo_before": source_before,
                "source_repo_after": source_after,
                "runtime_acquisition_next_action": sync_decision.get("next_action") if sync_decision else {},
                "release_state": {
                    "status": release_state.get("status"),
                    "next_step": release_state.get("next_step"),
                    "source_repo_fallback": release_state.get("source_repo_fallback"),
                    "preferred_asset_count": release_state.get("preferred_asset_count"),
                    "install_ready_candidate_count": release_state.get("install_ready_candidate_count"),
                } if release_state else {},
            })
        except Exception as exc:
            if not req.continue_on_error:
                raise
            rows.append({
                "object": "media2api.proxy_kernel.source_repo_sync",
                "provider_id": provider_id,
                "dry_run": bool(req.dry_run),
                "status": "failed",
                "will_sync": bool(should_sync),
                "error": exc.__class__.__name__,
                "message": str(exc),
                "source_repo_before": source_before,
                "source_repo_after": source_before,
                "runtime_acquisition_next_action": sync_decision.get("next_action") if sync_decision else {},
                "release_state": release_state,
            })
    return {
        "object": "media2api.proxy_kernel.source_repo_sync_matrix",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "dry_run": bool(req.dry_run),
        "provider_ids": selected,
        "summary": proxy_kernel_source_repo_sync_matrix_summary(rows),
        "data": rows,
        "policy": {
            "read_only": bool(req.dry_run),
            "release_binary_first": True,
            "only_when_needed": bool(req.only_when_needed),
            "resolve_release": bool(req.resolve_release),
            "allowlist_only": True,
            "source_repo_root": str(settings.source_repo_dir),
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "purpose": "protocol inspection, local build input, or platform-native adapter rewrite when release binaries are missing or insufficient",
        },
    }


def proxy_kernel_source_runtime_next_action(plan: dict[str, Any]) -> dict[str, Any]:
    provider_id = str(plan.get("provider_id") or "{provider_id}")
    if not plan.get("source_available"):
        return {
            "id": "source_repo_sync",
            "label": "同步 source-repo",
            "reason": "源码参考仓库尚未同步，先同步后才能识别依赖、构建和启动候选。",
            "primary_api": f"/v1/admin/proxy-kernels/{provider_id}/source-repo/sync",
        }
    setup_candidates = [
        item
        for item in [*(plan.get("dependency_commands") or []), *(plan.get("build_commands") or [])]
        if isinstance(item, dict) and item.get("command") and not item.get("reference_only")
    ]
    if setup_candidates:
        first = setup_candidates[0]
        return {
            "id": "source_runtime_setup",
            "label": "准备源码依赖/构建",
            "reason": "已识别依赖或构建命令。先 dry-run 核对命令，再决定是否实际执行。",
            "primary_api": f"/v1/admin/proxy-kernels/{provider_id}/source-runtime-setup",
            "command_id": first.get("id") or "",
            "command": first.get("command") or [],
        }
    preferred = plan.get("preferred_start_command") if isinstance(plan.get("preferred_start_command"), dict) else {}
    if preferred.get("command"):
        return {
            "id": "source_runtime_launcher",
            "label": "生成 source-runtime hash 启动器",
            "reason": "已识别启动候选。生成受控 launcher 后仍通过 start-runtime 进入 loopback runtime。",
            "primary_api": f"/v1/admin/proxy-kernels/{provider_id}/source-runtime-launcher",
            "command_id": preferred.get("id") or "",
            "command": preferred.get("command") or [],
        }
    return {
        "id": "manual_source_review",
        "label": "人工阅读源码说明",
        "reason": "源码已同步，但未识别出可直接包装的依赖、构建或启动命令。需要阅读 README 或重写 adapter/launcher。",
        "primary_api": f"/v1/admin/proxy-kernels/{provider_id}/source-runtime-plan",
    }


def proxy_kernel_source_runtime_plan_status(plan: dict[str, Any]) -> str:
    if not plan.get("source_available"):
        return "needs_source_repo"
    action_id = str((plan.get("next_action") or {}).get("id") or "")
    if action_id == "source_runtime_setup":
        return "ready_for_setup"
    if action_id == "source_runtime_launcher":
        return "ready_for_launcher"
    return "needs_manual_review"


def proxy_kernel_source_runtime_plan_matrix_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    status_counts: dict[str, int] = {}
    type_counts: dict[str, int] = {}
    for row in rows:
        status = str(row.get("status") or "unknown")
        status_counts[status] = status_counts.get(status, 0) + 1
        for item in row.get("detected_project_types") or []:
            key = str(item)
            type_counts[key] = type_counts.get(key, 0) + 1
    return {
        "total": len(rows),
        "source_available": sum(1 for row in rows if row.get("source_available")),
        "needs_source_repo": status_counts.get("needs_source_repo", 0),
        "ready_for_setup": status_counts.get("ready_for_setup", 0),
        "ready_for_launcher": status_counts.get("ready_for_launcher", 0),
        "needs_manual_review": status_counts.get("needs_manual_review", 0),
        "with_start_candidates": sum(1 for row in rows if row.get("start_command_candidates")),
        "with_dependency_commands": sum(1 for row in rows if row.get("dependency_commands")),
        "with_build_commands": sum(1 for row in rows if row.get("build_commands")),
        "detected_project_type_counts": type_counts,
        "status_counts": status_counts,
    }


def build_proxy_kernel_source_runtime_plan_matrix(
    db: Session,
    provider_ids: list[str] | None = None,
    *,
    base_url: str = "",
) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows: list[dict[str, Any]] = []
    for provider_id in selected:
        plan = proxy_kernel_service.source_runtime_plan(provider_id, base_url=base_url)
        next_action = proxy_kernel_source_runtime_next_action(plan)
        row = {
            **plan,
            "status": "",
            "next_action": next_action,
            "candidate_summary": {
                "dependency_command_count": len(plan.get("dependency_commands") or []),
                "build_command_count": len(plan.get("build_commands") or []),
                "start_command_count": len(plan.get("start_command_candidates") or []),
                "preferred_start_command_id": (plan.get("preferred_start_command") or {}).get("id") if isinstance(plan.get("preferred_start_command"), dict) else "",
                "launcher_template_ready": bool((plan.get("launcher_payload_template") or {}).get("command")),
            },
        }
        row["status"] = proxy_kernel_source_runtime_plan_status(row)
        rows.append(row)
    return {
        "object": "media2api.proxy_kernel.source_runtime_plan_matrix",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "base_url": (base_url or "").strip(),
        "summary": proxy_kernel_source_runtime_plan_matrix_summary(rows),
        "data": rows,
        "policy": {
            "read_only": True,
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "executes_source_code": False,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "shell": "forbidden",
            "managed_runtime_listener": "loopback_only",
        },
    }


def proxy_kernel_live_workspace_row(db: Session, provider_id: str) -> dict[str, Any]:
    delivery = build_proxy_kernel_runtime_delivery_plan(db, provider_id)
    readiness = build_proxy_kernel_production_readiness(db, provider_id)
    materials = build_proxy_kernel_materials_request(db, provider_id)
    go_live = build_proxy_kernel_go_live_checklist(db, provider_id)
    state = delivery.get("state") if isinstance(delivery.get("state"), dict) else {}
    blockers = [
        phase
        for phase in readiness.get("phases", [])
        if isinstance(phase, dict) and not phase.get("ok")
    ]
    return {
        "object": "media2api.proxy_kernel.live_workspace.item",
        "provider_id": provider_id,
        "selection_id": delivery.get("selection_id"),
        "status": readiness.get("status") or delivery.get("status"),
        "next_step": delivery.get("next_step") or readiness.get("next_step") or go_live.get("next_step"),
        "state": {
            "route_config_ready": bool(state.get("route_config_ready")),
            "installed_verified": bool(state.get("installed_verified")),
            "runtime_registered": bool(state.get("runtime_registered")),
            "runtime_loopback_only": bool(state.get("runtime_loopback_only")),
            "managed_process_running": bool(state.get("managed_process_running")),
            "active_account_count": int(state.get("active_account_count") or 0),
            "ready_for_live_acceptance": bool(readiness.get("ready_for_live_acceptance")),
            "production_ready": bool(readiness.get("production_ready")),
        },
        "blocking_phases": [
            {"id": item.get("id"), "label": item.get("label"), "action": item.get("action")}
            for item in blockers
        ],
        "materials": {
            "account": (materials.get("account_materials") or {}).get("status"),
            "runtime": (materials.get("runtime_materials") or {}).get("status"),
            "routing": (materials.get("routing_materials") or {}).get("status"),
            "validation": (materials.get("validation_materials") or {}).get("status"),
        },
        "evidence": {
            "runtime_delivery": delivery,
            "production_readiness": readiness,
            "materials_request": materials,
            "go_live": go_live,
        },
    }


def proxy_kernel_live_workspace_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    next_step_counts: dict[str, int] = {}
    blocking_phase_counts: dict[str, int] = {}
    for row in rows:
        next_id = str((row.get("next_step") or {}).get("id") or "unknown")
        next_step_counts[next_id] = next_step_counts.get(next_id, 0) + 1
        for phase in row.get("blocking_phases", []):
            phase_id = str(phase.get("id") or "unknown")
            blocking_phase_counts[phase_id] = blocking_phase_counts.get(phase_id, 0) + 1
    return {
        "total": len(rows),
        "route_ready": sum(1 for row in rows if (row.get("state") or {}).get("route_config_ready")),
        "runtime_registered": sum(1 for row in rows if (row.get("state") or {}).get("runtime_registered")),
        "runtime_loopback": sum(1 for row in rows if (row.get("state") or {}).get("runtime_loopback_only")),
        "active_account": sum(1 for row in rows if int((row.get("state") or {}).get("active_account_count") or 0) > 0),
        "ready_for_live_acceptance": sum(1 for row in rows if (row.get("state") or {}).get("ready_for_live_acceptance")),
        "production_ready": sum(1 for row in rows if (row.get("state") or {}).get("production_ready")),
        "action_required": sum(1 for row in rows if row.get("blocking_phases")),
        "next_step_counts": next_step_counts,
        "blocking_phase_counts": blocking_phase_counts,
    }


