def proxy_kernel_activation_dashboard_next_action(row: dict[str, Any]) -> dict[str, Any]:
    state = row.get("state") if isinstance(row.get("state"), dict) else {}
    materials = row.get("materials") if isinstance(row.get("materials"), dict) else {}
    phases = [str(item.get("id") or "") for item in row.get("blocking_phases", []) if isinstance(item, dict)]
    if state.get("production_ready"):
        action_id = "ready"
    elif not state.get("route_config_ready"):
        action_id = "route"
    elif int(state.get("active_account_count") or 0) <= 0 or materials.get("account") != "ready":
        action_id = "account"
    elif not state.get("runtime_registered") or not state.get("runtime_loopback_only") or not state.get("managed_process_running"):
        action_id = "runtime"
    elif "health" in phases:
        action_id = "health"
    elif state.get("ready_for_live_acceptance"):
        action_id = "live_acceptance"
    elif "live_acceptance" in phases:
        action_id = "live_acceptance"
    else:
        action_id = "runtime"
    action = dict(PROXY_KERNEL_ACTIVATION_DASHBOARD_ACTIONS[action_id])
    action["id"] = action_id
    return action


def proxy_kernel_activation_dashboard_parallel_actions(row: dict[str, Any]) -> list[dict[str, Any]]:
    state = row.get("state") if isinstance(row.get("state"), dict) else {}
    materials = row.get("materials") if isinstance(row.get("materials"), dict) else {}
    phases = {str(item.get("id") or "") for item in row.get("blocking_phases", []) if isinstance(item, dict)}
    action_ids: list[str] = []
    if not state.get("route_config_ready"):
        action_ids.append("route")
    if int(state.get("active_account_count") or 0) <= 0 or materials.get("account") != "ready":
        action_ids.append("account")
    if not state.get("runtime_registered") or not state.get("runtime_loopback_only") or not state.get("managed_process_running"):
        action_ids.append("runtime")
    if "health" in phases:
        action_ids.append("health")
    if state.get("ready_for_live_acceptance") or "live_acceptance" in phases:
        action_ids.append("live_acceptance")
    if state.get("production_ready"):
        action_ids.append("ready")
    unique_ids = list(dict.fromkeys(action_ids))
    return [{**PROXY_KERNEL_ACTIVATION_DASHBOARD_ACTIONS[action_id], "id": action_id} for action_id in unique_ids]


def proxy_kernel_activation_dashboard_row(row: dict[str, Any]) -> dict[str, Any]:
    evidence = row.get("evidence") if isinstance(row.get("evidence"), dict) else {}
    materials_request = evidence.get("materials_request") if isinstance(evidence.get("materials_request"), dict) else {}
    required_materials = materials_request.get("must_be_provided_by_operator") or materials_request.get("required_materials") or []
    next_action = proxy_kernel_activation_dashboard_next_action(row)
    state = row.get("state") if isinstance(row.get("state"), dict) else {}
    plain_status = "已可直接调用" if state.get("production_ready") else "需要真实材料或运行证据"
    if next_action["id"] == "account":
        plain_status = "先导入真实账号材料"
    elif next_action["id"] == "runtime":
        plain_status = "先准备并启动本地执行内核"
    elif next_action["id"] == "health":
        plain_status = "先确认 runtime 健康"
    elif next_action["id"] == "live_acceptance":
        plain_status = "可以开始真实样本验收"
    elif next_action["id"] == "route":
        plain_status = "先补齐平台路由"
    return {
        "provider_id": row.get("provider_id"),
        "selection_id": row.get("selection_id"),
        "status": row.get("status"),
        "plain_status": plain_status,
        "next_action": next_action,
        "parallel_actions": proxy_kernel_activation_dashboard_parallel_actions(row),
        "state": state,
        "materials": row.get("materials") or {},
        "blocking_phases": row.get("blocking_phases") or [],
        "required_material_count": len(required_materials),
        "required_materials": required_materials[:8],
        "go_live_next_step": (evidence.get("go_live") or {}).get("next_step") if isinstance(evidence.get("go_live"), dict) else {},
        "readiness_next_step": (evidence.get("production_readiness") or {}).get("next_step") if isinstance(evidence.get("production_readiness"), dict) else {},
        "workspace_item": row,
    }


def proxy_kernel_activation_dashboard_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    next_action_counts: dict[str, int] = {}
    for row in rows:
        action_id = str((row.get("next_action") or {}).get("id") or "unknown")
        next_action_counts[action_id] = next_action_counts.get(action_id, 0) + 1
    return {
        "total": len(rows),
        "production_ready": sum(1 for row in rows if (row.get("state") or {}).get("production_ready")),
        "ready_for_live_acceptance": sum(1 for row in rows if (row.get("state") or {}).get("ready_for_live_acceptance")),
        "needs_account": sum(1 for row in rows if (row.get("next_action") or {}).get("id") == "account"),
        "needs_runtime": sum(1 for row in rows if (row.get("next_action") or {}).get("id") == "runtime"),
        "needs_health": sum(1 for row in rows if (row.get("next_action") or {}).get("id") == "health"),
        "needs_live_acceptance": sum(1 for row in rows if (row.get("next_action") or {}).get("id") == "live_acceptance"),
        "route_ready": sum(1 for row in rows if (row.get("state") or {}).get("route_config_ready")),
        "active_account": sum(1 for row in rows if int((row.get("state") or {}).get("active_account_count") or 0) > 0),
        "runtime_registered": sum(1 for row in rows if (row.get("state") or {}).get("runtime_registered")),
        "next_action_counts": next_action_counts,
    }


def build_proxy_kernel_production_activation_dashboard(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    workspace_rows = [proxy_kernel_live_workspace_row(db, provider_id) for provider_id in selected]
    rows = [proxy_kernel_activation_dashboard_row(row) for row in workspace_rows]
    readiness = build_readiness_snapshot(db)
    return {
        "object": "media2api.proxy_kernel.production_activation_dashboard",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_ids": selected,
        "status": "production_ready" if all((row.get("state") or {}).get("production_ready") for row in rows) and rows else "action_required",
        "summary": proxy_kernel_activation_dashboard_summary(rows),
        "readiness": {
            "status": readiness.get("status"),
            "core_ready": readiness.get("core_ready"),
            "production_ready": readiness.get("production_ready"),
            "action_items": readiness.get("action_items", []),
        },
        "data": rows,
        "policy": {
            "read_only": True,
            "upstream_calls": False,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "no_fake_account_created": True,
        },
    }


def build_proxy_kernel_live_workspace(
    db: Session,
    ctx: AuthContext,
    req: ProxyKernelLiveWorkspaceRequest,
) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, req.provider_ids)
    if req.routing_status not in {"active", "disabled"}:
        raise ValueError("ROUTING_STATUS_UNSUPPORTED")
    route_result: dict[str, Any] = {
        "status": "skipped" if not req.prepare_routing else "planned",
        "dry_run": True,
        "provider_ids": selected,
    }
    if req.prepare_routing and not req.dry_run:
        route_result = apply_proxy_kernel_bulk_routing(
            db,
            selected,
            status=req.routing_status,
            enable_mappings=req.enable_mappings,
            priority_offset=req.priority_offset,
            update_provider_base_url=req.update_provider_base_url,
        )
        route_result["dry_run"] = False

    release_candidate_matrix: dict[str, Any] = {
        "status": "skipped",
        "dry_run": True,
        "data": [],
        "summary": {},
    }
    if req.include_release_candidates:
        candidate_req = ProxyKernelReleaseCandidateBulkInstallRequest(
            provider_ids=selected,
            dry_run=bool(req.dry_run or not req.install_release_candidates),
            resolve_release=bool(req.resolve_release_candidates or req.install_release_candidates),
            allow_non_preferred=False,
            force=False,
            continue_on_error=bool(req.continue_on_error),
        )
        release_candidate_matrix = build_proxy_kernel_release_candidate_install_matrix(db, candidate_req)

    source_repo_sync: dict[str, Any] = {
        "status": "skipped",
        "dry_run": True,
        "data": [],
        "summary": {},
    }
    if req.sync_source_repos:
        source_repo_sync = build_proxy_kernel_source_repo_sync_matrix(
            db,
            ProxyKernelBulkSourceRepoSyncRequest(
                provider_ids=selected,
                ref="",
                force=bool(req.force_source_repo_sync),
                dry_run=bool(req.dry_run),
                only_when_needed=bool(req.sync_source_repos_only_when_needed),
                resolve_release=bool(req.resolve_source_repo_release_state),
                continue_on_error=bool(req.continue_on_error),
            ),
        )

    loopback_contract: dict[str, Any] = {"status": "skipped", "dry_run": bool(req.dry_run)}
    if req.run_loopback_contract:
        if req.dry_run:
            loopback_contract = {
                "status": "planned",
                "dry_run": True,
                "operations": ["text_to_image", "image_edit", "text_to_video"],
            }
        else:
            loopback_contract = run_proxy_kernel_loopback_contract_test(
                db,
                ctx,
                ProxyKernelLoopbackContractTestRequest(operations=["text_to_image", "image_edit", "text_to_video"]),
            )

    rows = [proxy_kernel_live_workspace_row(db, provider_id) for provider_id in selected]
    downloaded_binaries = bool((release_candidate_matrix.get("policy") or {}).get("downloaded_binaries"))
    return {
        "object": "media2api.proxy_kernel.live_workspace",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "dry_run": bool(req.dry_run),
        "provider_ids": selected,
        "summary": proxy_kernel_live_workspace_summary(rows),
        "routing": route_result,
        "release_candidates": release_candidate_matrix,
        "source_repo_sync": source_repo_sync,
        "loopback_contract": loopback_contract,
        "data": rows,
        "next_actions": [
            "Apply routing templates if route_ready is lower than total.",
            "Install or register loopback runtimes with fixed release assets and SHA256.",
            "Import real Web session or Agent Provider credentials for providers with active_account=0.",
            "Run provider health checks, then live image/video acceptance samples.",
        ],
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "release_binary_first": True,
            "source_repo_only_when_needed": True,
            "hash_required": True,
            "downloaded_binaries": downloaded_binaries,
            "no_fake_account_created": True,
            "upstream_calls": False,
        },
    }


PROXY_KERNEL_IMAGE_OPERATIONS = {"text_to_image", "image_to_image", "image_edit"}
PROXY_KERNEL_VIDEO_OPERATIONS = {"text_to_video", "image_to_video", "video_extend"}


def proxy_kernel_runtime_contract_check(check_id: str, ok: bool, label: str, detail: dict[str, Any] | None = None) -> dict[str, Any]:
    return {"id": check_id, "ok": bool(ok), "label": label, "detail": detail or {}}


def build_proxy_kernel_runtime_contract(db: Session, provider_id: str) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    proxy_kernel_service.require_spec(provider_id)
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    routing = proxy_kernel_routing_plan(db, provider_id)
    provider = db.get(models.Provider, provider_id)
    template_config = provider_template_default_config(template.id, template.default_config)
    provider_config = provider_runtime_config(provider_id, loads(provider.base_config_json, {})) if provider else {}
    config = {**template_config, **provider_config}
    runtime_base_url = str(kernel.get("runtime_base_url") or config.get("base_url") or "").rstrip("/")
    if runtime_base_url:
        config["base_url"] = runtime_base_url
    operations, provider_models = provider_default_operations_and_models(provider_id)
    endpoint_operations = [operation for operation in operations if operation in PROXY_KERNEL_IMAGE_OPERATIONS | PROXY_KERNEL_VIDEO_OPERATIONS]
    endpoints = {
        operation: connector_runtime_endpoint_for(operation, config)
        for operation in endpoint_operations
        if connector_runtime_endpoint_for(operation, config)
    }
    image_operations = [operation for operation in endpoint_operations if operation in PROXY_KERNEL_IMAGE_OPERATIONS]
    video_operations = [operation for operation in endpoint_operations if operation in PROXY_KERNEL_VIDEO_OPERATIONS]
    image_endpoint_ready = all(str(endpoints.get(operation) or "").startswith("/v1/images/") for operation in image_operations)
    video_endpoint_ready = all(str(endpoints.get(operation) or "").startswith("/v1/videos/") for operation in video_operations)
    endpoint_complete = bool(endpoints) and all(operation in endpoints for operation in endpoint_operations)
    account_rows = db.query(models.AccountResource).filter(models.AccountResource.provider_id == provider_id).all()
    active_accounts = [account for account in account_rows if account.status == "active"]
    header_prefix = str(config.get("account_header_prefix") or "X-Media2API").strip() or "X-Media2API"
    credential_ref_headers_enabled = config.get("forward_credential_ref_headers", True) is not False
    base_url_loopback_ok = not runtime_base_url or proxy_kernel_service.is_loopback_url(runtime_base_url)
    checks = [
        proxy_kernel_runtime_contract_check("provider_template", True, "Finalized provider template is present"),
        proxy_kernel_runtime_contract_check("adapter_http", template.adapter_type == "http_adapter", "Provider uses the generic HTTP loopback adapter", {"adapter_type": template.adapter_type}),
        proxy_kernel_runtime_contract_check("endpoint_mapping", endpoint_complete, "Every declared media operation has a submit endpoint", {"operations": endpoint_operations, "endpoints": endpoints}),
        proxy_kernel_runtime_contract_check("image_endpoint_priority", image_endpoint_ready, "Image operations map to /v1/images/*", {"image_operations": image_operations}),
        proxy_kernel_runtime_contract_check("video_endpoint_priority", video_endpoint_ready, "Video operations map to /v1/videos/* or provider has no video operation", {"video_operations": video_operations}),
        proxy_kernel_runtime_contract_check("credential_ref_forwarding", credential_ref_headers_enabled, "Account credential references are forwarded to the loopback runner"),
        proxy_kernel_runtime_contract_check("loopback_only", base_url_loopback_ok, "Runtime base_url is empty or loopback-only", {"runtime_base_url": runtime_base_url}),
        proxy_kernel_runtime_contract_check("mappings_defined", bool(template.mappings), "Finalized provider/model mappings are defined"),
        proxy_kernel_runtime_contract_check("official_sdk_api_forbidden", True, "Official SDK/API key paths are excluded by policy"),
    ]
    contract_ready = all(check["ok"] for check in checks)
    next_action = "register_runtime" if not kernel.get("runtime_registered") else "import_account" if not active_accounts else "live_acceptance"
    if not contract_ready:
        next_action = "fix_contract_config"
    elif not routing.get("route_config_ready"):
        next_action = "apply_routing"
    return {
        "object": "media2api.proxy_kernel.runtime_contract",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "repo": (kernel.get("spec") or {}).get("repo"),
        "repo_url": (kernel.get("spec") or {}).get("repo_url"),
        "status": "contract_ready" if contract_ready else "action_required",
        "contract_ready": contract_ready,
        "next_action": next_action,
        "state": {
            "provider_initialized": bool(provider),
            "provider_status": provider.status if provider else "missing",
            "route_config_ready": bool(routing.get("route_config_ready")),
            "runtime_registered": bool(kernel.get("runtime_registered")),
            "runtime_loopback_only": bool(kernel.get("runtime_loopback_only")),
            "runtime_base_url": runtime_base_url,
            "active_account_count": len(active_accounts),
            "account_count": len(account_rows),
            "installed_verified": bool(kernel.get("installed_verified")),
        },
        "adapter_contract": {
            "adapter_type": template.adapter_type,
            "contract_kind": "media2api_openai_compatible_loopback",
            "submit_method": "POST",
            "health_endpoint": str(config.get("health_endpoint") or "/health"),
            "endpoints": endpoints,
            "image_operations": image_operations,
            "video_operations": video_operations,
            "poll_endpoint": str(config.get("poll_endpoint") or "{submit_endpoint}/{task_id}"),
            "poll_method": str(config.get("poll_method") or "GET").upper(),
            "poll_timeout_seconds": int(float(config.get("poll_timeout_seconds") or 180)),
            "task_id_paths": config.get("task_id_paths") or config.get("task_id_fields") or DEFAULT_TASK_ID_PATHS,
            "status_paths": config.get("status_paths") or config.get("status_fields") or DEFAULT_STATUS_PATHS,
            "output_paths": config.get("output_paths") or config.get("result_paths") or DEFAULT_OUTPUT_PATHS,
            "asset_payload_fields": ASSET_PAYLOAD_FIELDS,
            "request_templates_configured": bool(config.get("request_templates") or config.get("payload_templates") or config.get("request_template") or config.get("payload_template")),
            "request_template_operations": sorted((config.get("request_templates") or config.get("payload_templates") or {}).keys()) if isinstance(config.get("request_templates") or config.get("payload_templates"), dict) else [],
            "standard_payload_fields": ["operation", "provider_id", "model", "prompt", "account", "image", "assets"],
        },
        "auth_contract": {
            "credential_ref_headers_enabled": credential_ref_headers_enabled,
            "supported_reference_prefixes": list(CONNECTOR_REFERENCE_PREFIXES),
            "header_names": {
                "provider_id": str(config.get("provider_id_header") or f"{header_prefix}-Provider-ID"),
                "account_id": str(config.get("account_id_header") or f"{header_prefix}-Account-ID"),
                "account_label": str(config.get("account_label_header") or f"{header_prefix}-Account-Label"),
                "credential_ref": str(config.get("credential_ref_header") or f"{header_prefix}-Credential-Ref"),
                "credential_type": str(config.get("credential_type_header") or f"{header_prefix}-Credential-Type"),
                "credential_reference_only": str(config.get("credential_reference_only_header") or f"{header_prefix}-Credential-Reference-Only"),
            },
            "payload_account_fields": ["id", "label", "credential_ref", "credential_ref_type", "credential_reference_only", "supported_operations", "supported_provider_models", "region", "plan"],
        },
        "media_contract": {
            "provider_models": provider_models,
            "logical_mappings": [proxy_kernel_mapping_template_payload(provider_id, item) for item in template.mappings],
            "priority": "/v1/images/* and /v1/videos/* are the public platform API and the preferred loopback contract.",
        },
        "checks": checks,
        "routing": routing,
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "no_fake_account_created": True,
        },
    }


def proxy_kernel_runtime_contract_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    next_action_counts: dict[str, int] = {}
    for row in rows:
        action = str(row.get("next_action") or "unknown")
        next_action_counts[action] = next_action_counts.get(action, 0) + 1
    return {
        "total": len(rows),
        "contract_ready": sum(1 for row in rows if row.get("contract_ready")),
        "image_capable": sum(1 for row in rows if (row.get("adapter_contract") or {}).get("image_operations")),
        "video_capable": sum(1 for row in rows if (row.get("adapter_contract") or {}).get("video_operations")),
        "endpoint_complete": sum(1 for row in rows if any(check.get("id") == "endpoint_mapping" and check.get("ok") for check in row.get("checks", []))),
        "route_ready": sum(1 for row in rows if (row.get("state") or {}).get("route_config_ready")),
        "runtime_registered": sum(1 for row in rows if (row.get("state") or {}).get("runtime_registered")),
        "runtime_loopback": sum(1 for row in rows if (row.get("state") or {}).get("runtime_loopback_only")),
        "active_account": sum(1 for row in rows if int((row.get("state") or {}).get("active_account_count") or 0) > 0),
        "next_action_counts": next_action_counts,
    }


def build_proxy_kernel_runtime_contract_matrix(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_runtime_contract(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.runtime_contract_matrix",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": proxy_kernel_runtime_contract_summary(rows),
        "data": rows,
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "release_binary_first": True,
            "loopback_contract_first": True,
            "public_api_priority": ["/v1/images/*", "/v1/videos/*"],
        },
    }


def latest_provider_health_check(db: Session, provider_id: str) -> dict[str, Any] | None:
    check = (
        db.query(models.ProviderHealthCheck)
        .filter(models.ProviderHealthCheck.provider_id == provider_id)
        .order_by(models.ProviderHealthCheck.created_at.desc())
        .first()
    )
    return serialize_health_check(check) if check else None


def proxy_kernel_acceptance_sample_evidence(db: Session, provider_id: str, operations: list[str]) -> dict[str, Any]:
    operation_rows: dict[str, dict[str, Any]] = {}
    for operation in operations:
        job = (
            db.query(models.MediaJob)
            .filter(
                models.MediaJob.provider_id == provider_id,
                models.MediaJob.operation == operation,
                models.MediaJob.status == "completed",
                models.MediaJob.output_asset_ids_json != "[]",
            )
            .order_by(models.MediaJob.updated_at.desc(), models.MediaJob.created_at.desc())
            .first()
        )
        if not job:
            operation_rows[operation] = {"operation": operation, "ok": False, "status": "missing"}
            continue
        assets = []
        for asset_id in loads(job.output_asset_ids_json, []):
            asset = db.get(models.MediaAsset, asset_id)
            if asset:
                assets.append(
                    {
                        "asset_id": asset.id,
                        "kind": asset.kind,
                        "mime_type": asset.mime_type,
                        "size_bytes": asset.size_bytes,
                        "created_at": asset.created_at.isoformat() + "Z",
                    }
                )
        operation_rows[operation] = {
            "operation": operation,
            "ok": bool(assets),
            "status": "passed" if assets else "asset_missing",
            "job_id": job.id,
            "logical_model": job.logical_model,
            "provider_model": job.provider_model,
            "account_id": job.account_id,
            "provider_task_id": job.provider_task_id,
            "completed_at": job.updated_at.isoformat() + "Z",
            "assets": assets,
        }
    missing = [operation for operation, item in operation_rows.items() if not item.get("ok")]
    return {
        "required_operations": operations,
        "passed_operations": [operation for operation, item in operation_rows.items() if item.get("ok")],
        "missing_operations": missing,
        "operation_evidence": operation_rows,
        "ok": not missing and bool(operations),
    }


def proxy_kernel_production_phase(phase_id: str, label: str, ok: bool, detail: dict[str, Any], action: str) -> dict[str, Any]:
    return {
        "id": phase_id,
        "label": label,
        "status": "done" if ok else "action_required",
        "ok": bool(ok),
        "detail": detail,
        "action": action,
    }


def proxy_kernel_production_next_step(phases: list[dict[str, Any]]) -> dict[str, Any]:
    for phase in phases:
        if not phase.get("ok"):
            return {
                "id": phase["id"],
                "label": phase["label"],
                "action": phase["action"],
                "detail": phase.get("detail", {}),
            }
    return {
        "id": "production_ready",
        "label": "生产可用",
        "action": "保持健康检查、额度同步和真实样本回归。",
    }


def build_proxy_kernel_production_readiness(db: Session, provider_id: str) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    kernel = proxy_kernel_service.kernel_summary(db, provider_id)
    routing = proxy_kernel_routing_plan(db, provider_id)
    contract = build_proxy_kernel_runtime_contract(db, provider_id)
    delivery = build_proxy_kernel_runtime_delivery_plan(db, provider_id)
    go_live = build_proxy_kernel_go_live_checklist(db, provider_id)
    materials = build_proxy_kernel_materials_request(db, provider_id)
    health = latest_provider_health_check(db, provider_id)
    accounts = db.query(models.AccountResource).filter(models.AccountResource.provider_id == provider_id).all()
    active_accounts = [account for account in accounts if account.status == "active"]
    available_accounts = [account for account in active_accounts if account_credential_available(db, account)]
    process = kernel.get("process") if isinstance(kernel.get("process"), dict) else {}
    runtime_process_ok = not process.get("pid") or bool(process.get("running"))
    route_ok = bool(routing.get("route_config_ready"))
    contract_ok = bool(contract.get("contract_ready"))
    runtime_ok = bool(kernel.get("runtime_registered") and kernel.get("runtime_loopback_only") and runtime_process_ok)
    release_ok = bool(kernel.get("installed_verified") or kernel.get("runtime_registered"))
    account_ok = bool(available_accounts)
    health_ok = bool(health and health.get("status") == "ok")
    sample_evidence = proxy_kernel_acceptance_sample_evidence(db, provider_id, template.operations)
    live_acceptance_ok = bool(sample_evidence.get("ok"))
    phases = [
        proxy_kernel_production_phase(
            "routing",
            "路由映射",
            route_ok,
            {"provider_status": routing.get("provider_status"), "enabled_mapping_count": routing.get("enabled_mapping_count"), "blockers": routing.get("blockers", [])},
            "调用 apply-routing 或在后台点击“补齐路由映射”。",
        ),
        proxy_kernel_production_phase(
            "runtime_contract",
            "运行合同",
            contract_ok,
            {"status": contract.get("status"), "checks": contract.get("checks", [])},
            "修正 provider 配置，确保媒体操作映射到 /v1/images/* 和 /v1/videos/*。",
        ),
        proxy_kernel_production_phase(
            "runtime",
            "Loopback 执行器",
            runtime_ok,
            {"runtime_registered": kernel.get("runtime_registered"), "runtime_loopback_only": kernel.get("runtime_loopback_only"), "runtime_base_url": kernel.get("runtime_base_url"), "process": process},
            "安装/登记或启动已校验的 loopback runtime。",
        ),
        proxy_kernel_production_phase(
            "release_or_runtime_artifact",
            "Release/执行器资产",
            release_ok,
            {"installed": kernel.get("installed", {}), "installed_verified": kernel.get("installed_verified"), "runtime_registered": kernel.get("runtime_registered")},
            "优先使用 release 二进制并提供 SHA256；无 release 时同步 source-repo 做协议参考或本地构建。",
        ),
        proxy_kernel_production_phase(
            "account",
            "真实账号",
            account_ok,
            {"account_count": len(accounts), "active_account_count": len(active_accounts), "available_account_count": len(available_accounts), "materials": materials.get("account_materials", {})},
            "在授权资源/账号池导入真实 Web session、CLI OAuth 或 Agent Provider 账号材料。",
        ),
        proxy_kernel_production_phase(
            "health",
            "运行时健康检查",
            health_ok,
            {"latest_health": health},
            "调用 provider health-check，确认 loopback runner 可达。",
        ),
        proxy_kernel_production_phase(
            "live_acceptance",
            "真实样本验收",
            live_acceptance_ok,
            sample_evidence,
            "运行 account acceptance suite，并至少让每个声明操作产生可下载资产。",
        ),
    ]
    production_ready = all(phase["ok"] for phase in phases)
    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    readiness = {
        "object": "media2api.proxy_kernel.production_readiness",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "provider_id": provider_id,
        "selection_id": kernel.get("selection_id"),
        "repo": (kernel.get("spec") or {}).get("repo"),
        "repo_url": (kernel.get("spec") or {}).get("repo_url"),
        "status": "production_ready" if production_ready else "ready_for_live_acceptance" if route_ok and contract_ok and runtime_ok and account_ok and health_ok else "action_required",
        "production_ready": production_ready,
        "ready_for_live_acceptance": bool(route_ok and contract_ok and runtime_ok and account_ok and health_ok),
        "next_step": proxy_kernel_production_next_step(phases),
        "phases": phases,
        "state": {
            "route_ready": route_ok,
            "contract_ready": contract_ok,
            "runtime_ready": runtime_ok,
            "release_or_runtime_ready": release_ok,
            "account_ready": account_ok,
            "health_ok": health_ok,
            "live_acceptance_ok": live_acceptance_ok,
        },
        "evidence": {
            "kernel": kernel,
            "routing": routing,
            "runtime_contract": {
                "status": contract.get("status"),
                "adapter_contract": contract.get("adapter_contract"),
                "checks": contract.get("checks"),
            },
            "runtime_delivery": {
                "status": delivery.get("status"),
                "next_step": delivery.get("next_step"),
                "state": delivery.get("state"),
            },
            "go_live": {
                "status": go_live.get("status"),
                "ready_for_live_acceptance": go_live.get("ready_for_live_acceptance"),
                "next_step": go_live.get("next_step"),
            },
            "materials": materials,
            "latest_health": health,
            "acceptance_samples": sample_evidence,
        },
        "commands": {
            "production_readiness": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/production-readiness",
            "apply_routing": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/apply-routing -d '{{\"status\":\"active\",\"enable_mappings\":true,\"priority_offset\":0,\"update_provider_base_url\":true}}'",
            "runtime_contract": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/runtime-contract",
            "release_probe": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/release-probe",
            "runtime_delivery_plan": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/runtime-delivery-plan",
            "health_check": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/providers/{provider_id}/health-check",
            "materials_request": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/materials-request",
            "account_acceptance_suite": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/account-acceptance-suite -d '{json.dumps({'dry_run': False, 'external_only': True, 'provider_ids': [provider_id], 'operations': template.operations, 'run_samples': True, 'max_samples': max(1, min(len(template.operations), 3)), 'require_production_ready': False}, ensure_ascii=False, separators=(',', ':'))}'",
            "live_acceptance": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{json.dumps({'dry_run': True, 'operations': template.operations, 'run_samples': True, 'max_samples': 1}, ensure_ascii=False, separators=(',', ':'))}'",
        },
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "requires_real_acceptance_samples": True,
        },
    }
    return readiness


def run_proxy_kernel_live_acceptance(
    db: Session,
    provider_id: str,
    req: ProxyKernelLiveAcceptanceRequest,
    ctx: AuthContext,
) -> dict[str, Any]:
    template = PROVIDER_TEMPLATES.get(provider_id)
    if not template:
        raise KeyError(provider_id)
    proxy_kernel_service.require_spec(provider_id)
    requested_operations = [str(item).strip() for item in req.operations if str(item).strip()]
    operations = requested_operations or list(template.operations)
    unsupported_operations = [operation for operation in operations if operation not in template.operations]
    if unsupported_operations:
        raise ValueError("OPERATION_NOT_DECLARED:" + ",".join(unsupported_operations))

    max_samples = max(0, min(int(req.max_samples or 0), 6))
    max_accounts = max(1, min(int(req.max_accounts or 1), 20))
    readiness_before = build_proxy_kernel_production_readiness(db, provider_id)
    runtime_health: dict[str, Any] | None = None
    runtime_health_failed = False
    runtime_health_error = ""

    if req.run_runtime_health and req.dry_run:
        runtime_health = {
            "object": "media2api.proxy_kernel.runtime_health_check",
            "provider_id": provider_id,
            "ok": None,
            "status": "skipped_dry_run",
            "message": "Dry-run mode does not mutate provider health evidence.",
        }
    elif req.run_runtime_health:
        try:
            runtime_health = run_proxy_kernel_runtime_health_check(
                db,
                provider_id,
                sync_provider_base_url_value=req.sync_provider_base_url,
                require_running_process=req.require_running_process,
                fail_on_health_check=False,
            )
            runtime_health_failed = not bool(runtime_health.get("ok"))
        except (HTTPException, ValueError) as exc:
            runtime_health_failed = True
            runtime_health_error = str(getattr(exc, "detail", "") or exc)
            runtime_health = {
                "object": "media2api.proxy_kernel.runtime_health_check",
                "provider_id": provider_id,
                "ok": False,
                "error": runtime_health_error,
            }

    runtime_blocked = bool(runtime_health_failed and req.require_runtime_health)
    suite_request = AccountAcceptanceSuiteRequest(
        dry_run=req.dry_run,
        provider_ids=[provider_id],
        active_only=True,
        external_only=True,
        operations=operations,
        run_health_check=req.run_health_check,
        run_contract_tests=req.run_contract_tests,
        contract_run_submit=req.contract_run_submit,
        run_quota_sync=req.run_quota_sync,
        run_samples=req.run_samples,
        max_samples=max_samples,
        max_accounts=max_accounts,
        require_production_ready=req.require_production_ready,
    )
    if runtime_blocked and not req.dry_run:
        acceptance: dict[str, Any] = {
            "object": "media2api.account_acceptance_suite",
            "ok": False,
            "status": "skipped_runtime_health_failed",
            "action_items": [
                {
                    "check": "runtime_health",
                    "detail": runtime_health,
                }
            ],
        }
    else:
        acceptance = admin_account_acceptance_suite(suite_request, ctx, db)

    readiness_after = build_proxy_kernel_production_readiness(db, provider_id)
    if req.dry_run:
        status = "ready_to_run" if readiness_before.get("ready_for_live_acceptance") else "materials_required"
    elif runtime_blocked:
        status = "blocked"
    else:
        status = "passed" if acceptance.get("ok") else "failed"

    action_items: list[dict[str, Any]] = []
    if not readiness_before.get("ready_for_live_acceptance"):
        action_items.append({"check": "production_readiness", "detail": readiness_before.get("next_step")})
    if runtime_blocked:
        action_items.append({"check": "runtime_health", "detail": runtime_health})
    action_items.extend(acceptance.get("action_items") or [])

    if req.dry_run and readiness_before.get("ready_for_live_acceptance"):
        next_step = {
            "id": "switch_to_live",
            "label": "切换 Live 运行 1 条真实样本",
            "action": "将真实验收模式切换为 Live，保留 max_samples=1，再运行真实样本验收。",
        }
    elif action_items:
        next_step = {
            "id": str(action_items[0].get("check") or "action_required"),
            "label": "处理验收阻塞项",
            "action": "按 action_items 中的第一项补齐材料或修复 runtime。",
            "detail": action_items[0].get("detail"),
        }
    else:
        next_step = {
            "id": "production_readiness",
            "label": "刷新生产就绪",
            "action": "查看 production-readiness，确认真实样本资产已入库。",
        }

    base = settings.public_base_url
    admin_key = "$MEDIA2API_API_KEY"
    live_payload = suite_request.model_dump()
    live_payload["dry_run"] = False
    return {
        "object": "media2api.proxy_kernel.live_acceptance",
        "provider_id": provider_id,
        "selection_id": proxy_kernel_service.kernel_summary(db, provider_id).get("selection_id"),
        "status": status,
        "ok": bool((not req.dry_run) and acceptance.get("ok") and not runtime_blocked),
        "dry_run": req.dry_run,
        "operations": operations,
        "runtime_health_check": runtime_health,
        "account_acceptance": acceptance,
        "readiness_before": readiness_before,
        "readiness_after": readiness_after,
        "action_items": action_items,
        "next_step": next_step,
        "commands": {
            "dry_run": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{json.dumps({**live_payload, 'dry_run': True}, ensure_ascii=False, separators=(',', ':'))}'",
            "live": f"curl -X POST -H \"Authorization: Bearer {admin_key}\" -H \"Content-Type: application/json\" {base}/v1/admin/proxy-kernels/{provider_id}/live-acceptance -d '{json.dumps(live_payload, ensure_ascii=False, separators=(',', ':'))}'",
            "production_readiness": f"curl -H \"Authorization: Bearer {admin_key}\" {base}/v1/admin/proxy-kernels/{provider_id}/production-readiness",
        },
        "policy": {
            "default_mode": "dry_run",
            "live_mode_consumes_real_quota": True,
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "managed_runtime_listener": "loopback_only",
            "no_fake_account_created": True,
        },
    }


def proxy_kernel_production_readiness_summary(rows: list[dict[str, Any]]) -> dict[str, Any]:
    next_step_counts: dict[str, int] = {}
    phase_blockers: dict[str, int] = {}
    for row in rows:
        step_id = str((row.get("next_step") or {}).get("id") or "unknown")
        next_step_counts[step_id] = next_step_counts.get(step_id, 0) + 1
        for phase in row.get("phases", []):
            if not phase.get("ok"):
                phase_id = str(phase.get("id") or "unknown")
                phase_blockers[phase_id] = phase_blockers.get(phase_id, 0) + 1
    return {
        "total": len(rows),
        "production_ready": sum(1 for row in rows if row.get("production_ready")),
        "ready_for_live_acceptance": sum(1 for row in rows if row.get("ready_for_live_acceptance")),
        "route_ready": sum(1 for row in rows if (row.get("state") or {}).get("route_ready")),
        "contract_ready": sum(1 for row in rows if (row.get("state") or {}).get("contract_ready")),
        "runtime_ready": sum(1 for row in rows if (row.get("state") or {}).get("runtime_ready")),
        "account_ready": sum(1 for row in rows if (row.get("state") or {}).get("account_ready")),
        "health_ok": sum(1 for row in rows if (row.get("state") or {}).get("health_ok")),
        "live_acceptance_ok": sum(1 for row in rows if (row.get("state") or {}).get("live_acceptance_ok")),
        "next_step_counts": next_step_counts,
        "phase_blockers": phase_blockers,
    }


def build_proxy_kernel_production_readiness_matrix(db: Session, provider_ids: list[str] | None = None) -> dict[str, Any]:
    selected = proxy_kernel_routing_provider_ids(db, provider_ids)
    rows = [build_proxy_kernel_production_readiness(db, provider_id) for provider_id in selected]
    return {
        "object": "media2api.proxy_kernel.production_readiness_matrix",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "summary": proxy_kernel_production_readiness_summary(rows),
        "data": rows,
        "policy": {
            "read_only": True,
            "official_sdk_api": "forbidden",
            "release_binary_first": True,
            "loopback_contract_first": True,
            "requires_real_acceptance_samples": True,
        },
    }


def run_proxy_kernel_loopback_contract_test(db: Session, ctx: AuthContext, req: ProxyKernelLoopbackContractTestRequest) -> dict[str, Any]:
    allowed_operations = ["text_to_image", "image_edit", "text_to_video"]
    requested = [item for item in req.operations if item in allowed_operations]
    if req.include_image_edit and "image_edit" not in requested:
        requested.append("image_edit")
    if req.include_video and "text_to_video" not in requested:
        requested.append("text_to_video")
    if not requested:
        requested = ["text_to_image"]

    class LoopbackContractHandler(BaseHTTPRequestHandler):
        server_version = "media2api-loopback-contract/1.0"

        def _json(self, status: int, payload: dict[str, Any]) -> None:
            body = json.dumps(payload, ensure_ascii=False).encode("utf-8")
            self.send_response(status)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

        def log_message(self, format: str, *args: Any) -> None:
            return

        def do_GET(self) -> None:
            if self.path == "/health":
                self.server.request_log.append({"method": "GET", "path": self.path})  # type: ignore[attr-defined]
                self._json(200, {"status": "ok", "object": "media2api.proxy_kernel.loopback_contract.runner"})
                return
            self._json(404, {"error": "NOT_FOUND"})

        def do_POST(self) -> None:
            raw = self.rfile.read(int(self.headers.get("Content-Length") or "0"))
            try:
                payload = json.loads(raw.decode("utf-8") or "{}")
            except Exception:
                payload = {}
            self.server.request_log.append(  # type: ignore[attr-defined]
                {
                    "method": "POST",
                    "path": self.path,
                    "model": payload.get("model"),
                    "operation": payload.get("operation"),
                    "account_id": (payload.get("account") or {}).get("id") if isinstance(payload.get("account"), dict) else "",
                    "credential_reference_only": (payload.get("account") or {}).get("credential_reference_only") if isinstance(payload.get("account"), dict) else None,
                    "asset_count": len(payload.get("assets") or []) if isinstance(payload.get("assets"), list) else int(bool(payload.get("assets"))),
                }
            )
            if self.path in {"/v1/images/generations", "/v1/images/edits"}:
                self._json(
                    200,
                    {
                        "id": f"contract_image_{int(time.time() * 1000)}",
                        "status": "completed",
                        "data": [{"b64_json": EXTERNAL_ACCEPTANCE_REFERENCE_PNG_B64, "mime_type": "image/png"}],
                    },
                )
                return
            if self.path == "/v1/videos/generations":
                self._json(
                    200,
                    {
                        "id": f"contract_video_{int(time.time() * 1000)}",
                        "status": "completed",
                        "data": [{"video_base64": TINY_MP4_BASE64, "mime_type": "video/mp4"}],
                    },
                )
                return
            self._json(404, {"error": "NOT_FOUND"})

    suffix = str(int(time.time() * 1000))
    provider_id = f"pk_contract_{suffix}"
    account_id = f"acct_pk_contract_{suffix}"
    image_model_id = f"pk-contract-image-{suffix}"
    video_model_id = f"pk-contract-video-{suffix}"
    image_provider_model = "loopback-contract-image"
    video_provider_model = "loopback-contract-video"
    image_mapping_id = f"{image_model_id}:{provider_id}:{image_provider_model}"
    video_mapping_id = f"{video_model_id}:{provider_id}:{video_provider_model}"
    image_pricing_id = f"price_{image_model_id}"
    edit_pricing_id = f"price_{image_model_id}_edit"
    video_pricing_id = f"price_{video_model_id}"
    job_results: list[dict[str, Any]] = []
    created_asset_ids: list[str] = []
    server = ThreadingHTTPServer(("127.0.0.1", 0), LoopbackContractHandler)
    server.request_log = []  # type: ignore[attr-defined]
    thread = threading.Thread(target=server.serve_forever, daemon=True)
    thread.start()
    port = int(server.server_address[1])
    base_url = f"http://127.0.0.1:{port}"
    ok = False
    error_payload: dict[str, Any] | None = None
    health_result: dict[str, Any] = {"status": "not_run"}
    try:
        db.add(
            models.Provider(
                id=provider_id,
                name="Proxy Kernel Loopback Contract Self Test",
                adapter_type="http_adapter",
                status="active",
                base_config_json=dumps(
                    {
                        "base_url": base_url,
                        "health_endpoint": "/health",
                        "timeout_seconds": 20,
                        "poll_timeout_seconds": 30,
                        "endpoints": {
                            "text_to_image": "/v1/images/generations",
                            "image_edit": "/v1/images/edits",
                            "image_to_image": "/v1/images/edits",
                            "text_to_video": "/v1/videos/generations",
                        },
                    }
                ),
                notes="Temporary loopback contract self-test provider. Disabled after the run.",
            )
        )
        db.flush()
        db.add(
            models.LogicalModel(
                id=image_model_id,
                display_name="Proxy Kernel Contract Image",
                operations_json=dumps(["text_to_image", "image_edit"]),
                constraints_json=dumps({}),
                default_params_json=dumps({"quality": "standard", "n": 1}),
                billing_class="proxy_kernel_contract_image",
                enabled=True,
            )
        )
        db.add(
            models.LogicalModel(
                id=video_model_id,
                display_name="Proxy Kernel Contract Video",
                operations_json=dumps(["text_to_video"]),
                constraints_json=dumps({}),
                default_params_json=dumps({"duration": 1, "quality": "standard"}),
                billing_class="proxy_kernel_contract_video",
                enabled=True,
            )
        )
        db.add(
            models.AccountResource(
                id=account_id,
                provider_id=provider_id,
                label="Proxy Kernel Loopback Contract Account",
                resource_type="agent_provider",
                credential_ref=f"connector://self-test/{provider_id}/{account_id}",
                resource_profile_json=dumps({"resource_type": "agent_provider", "contract": "loopback"}),
                supported_operations_json=dumps(["text_to_image", "image_edit", "text_to_video"]),
                supported_provider_models_json=dumps([image_provider_model, video_provider_model]),
                quota_buckets_json=dumps([{"type": "tasks", "remaining_estimate": 10, "confidence": 1.0, "source": "self_test"}]),
                concurrency_limit=1,
                current_leases=0,
                region="loopback",
                plan="self_test",
                status="active",
            )
        )
        for pricing_id, logical_model, operation, billing_class, unit in [
            (image_pricing_id, image_model_id, "text_to_image", "proxy_kernel_contract_image", "image"),
            (edit_pricing_id, image_model_id, "image_edit", "proxy_kernel_contract_image", "image"),
            (video_pricing_id, video_model_id, "text_to_video", "proxy_kernel_contract_video", "second"),
        ]:
            db.add(
                models.PricingRule(
                    id=pricing_id,
                    name=f"Proxy Kernel Contract {operation}",
                    logical_model=logical_model,
                    billing_class=billing_class,
                    operation=operation,
                    unit=unit,
                    base_amount=0,
                    unit_amount=1,
                    input_asset_amount=0,
                    provider_cost_base=0,
                    provider_cost_unit=0,
                    provider_cost_input_asset=0,
                    quality_multipliers_json=dumps({"standard": 1}),
                    currency="credits",
                    enabled=True,
                )
            )
        db.add(
            models.ProviderModelMapping(
                id=image_mapping_id,
                logical_model=image_model_id,
                provider_id=provider_id,
                provider_model=image_provider_model,
                operations_json=dumps(["text_to_image", "image_edit"]),
                priority=0,
                weight=1,
                cost_score=0.8,
                speed_score=0.8,
                quality_score=0.5,
                reliability_score=0.8,
                enabled=True,
            )
        )
        db.add(
            models.ProviderModelMapping(
                id=video_mapping_id,
                logical_model=video_model_id,
                provider_id=provider_id,
                provider_model=video_provider_model,
                operations_json=dumps(["text_to_video"]),
                priority=0,
                weight=1,
                cost_score=0.8,
                speed_score=0.8,
                quality_score=0.5,
                reliability_score=0.8,
                enabled=True,
            )
        )
        db.commit()

        health_result = get_provider(provider_id).health_check(db, provider_id)
        if health_result.get("status") != "ok":
            raise RuntimeError(f"loopback health failed: {health_result}")

        if "image_edit" in requested:
            input_asset = asset_service.create_from_base64(
                db,
                ctx.user.id,
                EXTERNAL_ACCEPTANCE_REFERENCE_PNG_B64,
                f"proxy-kernel-contract-{suffix}.png",
                "image",
                "input",
                "image/png",
                source="self_test",
                provider_meta={"self_test": "proxy_kernel_loopback_contract"},
            )
            created_asset_ids.append(input_asset.id)
            db.commit()

        for operation in requested:
            logical_model = video_model_id if operation == "text_to_video" else image_model_id
            params: dict[str, Any] = {
                "prompt": f"proxy kernel loopback contract {operation}",
                "quality": "standard",
                "providers": [provider_id],
                "provider_preference": [provider_id],
                "_sync_process_lock": True,
            }
            input_asset_ids: list[str] = []
            if operation == "text_to_video":
                params["duration"] = 1
            elif operation == "image_edit":
                params["image"] = created_asset_ids[0]
                input_asset_ids = [created_asset_ids[0]]
            else:
                params["n"] = 1
            job = runtime.create_job(db, ctx.user.id, ctx.api_key.id, operation, logical_model, params, input_asset_ids=input_asset_ids, enqueue=False)
            job = runtime.process_job(db, job.id)
            output_assets = [db.get(models.MediaAsset, asset_id) for asset_id in loads(job.output_asset_ids_json, [])]
            created_asset_ids.extend([asset.id for asset in output_assets if asset])
            job_results.append(
                {
                    "operation": operation,
                    "ok": job.status == "completed" and bool(output_assets),
                    "job": serialize_job(db, job),
                    "outputs": [
                        {
                            "asset_id": asset.id,
                            "kind": asset.kind,
                            "mime_type": asset.mime_type,
                            "size_bytes": asset.size_bytes,
                        }
                        for asset in output_assets
                        if asset
                    ],
                }
            )

        expected_paths = {
            "text_to_image": "/v1/images/generations",
            "image_edit": "/v1/images/edits",
            "text_to_video": "/v1/videos/generations",
        }
        seen_paths = {item.get("path") for item in getattr(server, "request_log", [])}
        ok = all(item.get("ok") for item in job_results) and all(expected_paths[operation] in seen_paths for operation in requested)
    except Exception as exc:
        db.rollback()
        error_payload = {"type": type(exc).__name__, "message": str(exc)}
    finally:
        try:
            server.shutdown()
        finally:
            server.server_close()
            thread.join(timeout=2)
        try:
            provider = db.get(models.Provider, provider_id)
            if provider:
                provider.status = "disabled"
                provider.notes = (provider.notes or "") + " Disabled after loopback contract self-test."
            account = db.get(models.AccountResource, account_id)
            if account:
                account.status = "disabled"
                account.concurrency_limit = 0
            for mapping_id in [image_mapping_id, video_mapping_id]:
                mapping = db.get(models.ProviderModelMapping, mapping_id)
                if mapping:
                    mapping.enabled = False
            for pricing_id in [image_pricing_id, edit_pricing_id, video_pricing_id]:
                pricing = db.get(models.PricingRule, pricing_id)
                if pricing:
                    pricing.enabled = False
            for model_id in [image_model_id, video_model_id]:
                logical = db.get(models.LogicalModel, model_id)
                if logical:
                    logical.enabled = False
            db.commit()
        except Exception:
            db.rollback()

    return {
        "object": "media2api.proxy_kernel.loopback_contract_test",
        "ok": ok,
        "status": "passed" if ok else "failed",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "loopback_base_url": base_url,
        "operations": requested,
        "health": health_result,
        "jobs": job_results,
        "runner_requests": getattr(server, "request_log", []),
        "temporary_records": {
            "provider_id": provider_id,
            "account_id": account_id,
            "logical_models": [image_model_id, video_model_id],
            "mappings": [image_mapping_id, video_mapping_id],
            "pricing_rules": [image_pricing_id, edit_pricing_id, video_pricing_id],
            "disabled_after_run": True,
        },
        "error": error_payload,
        "policy": {
            "official_sdk_api": "forbidden",
            "third_party_public_service": "forbidden",
            "listener": "loopback_only",
            "upstream_calls": False,
            "purpose": "verify platform-to-loopback reverse-proxy contract before live provider acceptance",
        },
    }


